export const STOMP_PHYSICS = {
  KNEE_LIFT_AMPLITUDE: 60,
  HIP_CLEARANCE: 20,
  HOLD_THRESHOLD: 0.2,
  HOLD_KNEE_BONUS: 20,
  DESCENT_THRESHOLD: 0.6,
  KNEE_ATTACK_EXPONENT: 2,
  KNEE_ATTACK_MULTIPLIER: 2,
  IMPACT_SIGNAL_EXPONENT: 20,
  IMPACT_SHAKE_AMPLITUDE: 15,
  IMPACT_FLAT_FOOT_TARGET: -90,
} as const;

