  { name: "Anxious", settings: { breathing: { base: 0.7, range: 0.1 }, weightShift: { base: 0.5, range: 0.1 }, gazeSway: { base: 0.5, range: 0.08 }, tension: { base: 0.4, range: 0.08 }, fidgetFrequency: { base: 0.4, range: 0.08 }, transitionSpeed: { base: 0.4, range: 0.08 }, posture: { base: -0.2, range: 0.08 }, idlePinnedFeet: 'none' } },
  { name: "Attentive", settings: { breathing: { base: 0.1, range: 0.03 }, weightShift: { base: 0.05, range: 0.02 }, gazeSway: { base: 0.05, range: 0.01 }, tension: { base: 0.01, range: 0.005 }, fidgetFrequency: { base: 0.01, range: 0.005 }, transitionSpeed: { base: 0.15, range: 0.03 }, posture: { base: 0.7, range: 0.08 }, idlePinnedFeet: 'both' } },
  { name: "Crossed Arms", settings: { breathing: 0.3, weightShift: 0.1, tension: 0.1, transitionSpeed: 0.2, posture: 0.2, idlePinnedFeet: 'none' } },
  { name: "Heroic Flex", settings: { breathing: 0.6, weightShift: 0.4, tension: 0.4, transitionSpeed: 0.3, posture: 0.8, idlePinnedFeet: 'both' } },
  { name: "Lazy Grasp", settings: { breathing: 0.2, weightShift: 0.8, tension: 0.05, transitionSpeed: 0.1, posture: -0.4, idlePinnedFeet: 'right' } },
  { name: "Scratching", settings: { breathing: 0.5, weightShift: 0.3, tension: 0.2, fidgetFrequency: 0.9, transitionSpeed: 0.4, posture: 0.0, idlePinnedFeet: 'left' } },
];

const CollapsibleSection: React.FC<{ title: string; children: React.ReactNode; defaultOpen?: boolean; disabled?: boolean; }> = ({ title, children, defaultOpen = true, disabled = false }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  return (
    <div className={`flex flex-col gap-2 p-4 border rounded shadow-lg transition-all ${disabled ? 'border-ridge bg-mono-darker/50 opacity-50' : 'border-ridge bg-mono-dark'}`}>
      <button onClick={() => !disabled && setIsOpen(!isOpen)} className={`flex justify-between items-center w-full text-[10px] font-bold tracking-[0.2em] uppercase cursor-pointer transition-colors ${disabled ? 'text-mono-mid cursor-not-allowed' : `hover:text-ink text-selection`}`} disabled={disabled}>
        <span>{title}</span><span className="text-mono-mid transform transition-transform duration-200">{isOpen ? '▲' : '▼'}</span>
      </button>
      <div className={`overflow-hidden transition-all duration-300 ${isOpen ? 'max-h-[2000px] opacity-100' : 'max-h-0 opacity-0'}`}><div className="pt-2">{children}</div></div>
    </div>
  );
};

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(false);
  const [showLabels, setShowLabels] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [isSlowMoActive, setIsSlowMoActive] = useState(false);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);
  const H = 150;
  const [animationSpeed, setAnimationSpeed] = useState(1.0);
  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle'>('locomotion');
  const engineModeRef = useRef(engineMode);
  useEffect(() => { engineModeRef.current = engineMode; }, [engineMode]);
  const locomotionWeightRef = useRef(1.0);
  const transitionStartWeightRef = useRef(1.0);
  const transitionEndWeightRef = useRef(1.0);
  const modeTransitionStartTimeRef = useRef(0);
  const [activePins, setActivePins] = useState<string[]>([]);
  const [pinnedSlideOffset, setPinnedSlideOffset] = useState(150);
  const [bodyRotation, setBodyRotation] = useState(0);
  const [gravityCenter, setGravityCenter] = useState<'left' | 'center' | 'right'>('center');
  const [tensions, setTensions] = useState<Record<string, number>>({});
  const [shakeOffset, setShakeOffset] = useState({ x: 0, y: 0 });
  const [lotteJitter, setLotteJitter] = useState({ x: 0, y: 0 });
  const shakeOffsetRef = useRef({ x: 0, y: 0 });

  const [gait, setGait] = useState<WalkingEngineGait>(generateRandomGait(gaitPresets[0]));
  const [smoothedGait, setSmoothedGait] = useState<WalkingEngineGait>(gait);
  const gaitRef = useRef(gait);
  const smoothedGaitRef = useRef(smoothedGait);
  useEffect(() => { gaitRef.current = gait; }, [gait]);
  useEffect(() => { smoothedGaitRef.current = smoothedGait; }, [smoothedGait]);

  const [physicsControls, setPhysicsControls] = useState<PhysicsControls>(DEFAULT_PHYSICS_CONTROLS);
  const [smoothedPhysicsControls, setSmoothedPhysicsControls] = useState<PhysicsControls>(physicsControls);
  const physicsControlsRef = useRef(physicsControls);
  const smoothedPhysicsControlsRef = useRef(smoothedPhysicsControls);
  useEffect(() => { physicsControlsRef.current = physicsControls; }, [physicsControls]);
  useEffect(() => { smoothedPhysicsControlsRef.current = smoothedPhysicsControls; }, [smoothedPhysicsControls]);

  const [idleSettings, setIdleSettings] = useState<IdleSettings>(generateRandomIdle(idlePresets[0]));
  const [smoothedIdleSettings, setSmoothedIdleSettings] = useState<IdleSettings>(idleSettings);
  const [activeIdlePresetIndex, setActiveIdlePresetIndex] = useState(0);
  const idleSettingsRef = useRef(idleSettings);
  const smoothedIdleSettingsRef = useRef(smoothedIdleSettings);
  useEffect(() => { idleSettingsRef.current = idleSettings; }, [idleSettings]);
  useEffect(() => { smoothedIdleSettingsRef.current = smoothedIdleSettings; }, [smoothedIdleSettings]);

  const [lotteSettings, setLotteSettings] = useState<LotteSettings>(DEFAULT_LOTTE_SETTINGS);
  const lotteSettingsRef = useRef(lotteSettings);
  useEffect(() => { lotteSettingsRef.current = lotteSettings; }, [lotteSettings]);

  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [props, setProps] = useState<WalkingEngineProportions>(DEFAULT_PROPORTIONS);
  const [jointModes, setJointModes] = useState<JointModesState>({});
  const jointModesRef = useRef(jointModes);
  useEffect(() => { jointModesRef.current = jointModes; }, [jointModes]);

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const [isTransitioningToRest, setIsTransitioningToRest] = useState(false);
  const transitionStartTimeRef = useRef(0);
  const initialPoseOnPauseRef = useRef<WalkingEnginePose | null>(null);

  // Export State
  const [exportFormat, setExportFormat] = useState<'zip' | 'webm' | 'png'>('zip');
  const [syncToCycle, setSyncToCycle] = useState(true);
  const [isRecording, setIsRecording] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [zipProgress, setZipProgress] = useState(0);
  const [recordFrameCount, setRecordFrameCount] = useState(60);

  const framesRecordedRef = useRef(0);
  const capturedFramesRef = useRef<string[]>([]);
  const pivotsOnBeforeRecord = useRef(false);
  const labelsOnBeforeRecord = useRef(true);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const recordedChunksRef = useRef<Blob[]>([]);
  const lastPhaseRef = useRef(0);
  const hasStartedCycleCaptureRef = useRef(false);
  const isWebmRecorderStartedRef = useRef(false);

  const svgRef = useRef<SVGSVGElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastFrameTimeRef = useRef(0);

  useEffect(() => { 
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2} ${newWidth} ${newHeight}`);
  }, [zoomIndex]);

  const applyJointModes = useCallback((currentPose: WalkingEnginePose, modes: JointModesState): WalkingEnginePose => {
    const newPose = { ...currentPose };
    (Object.keys(modes) as Array<keyof typeof modes>).forEach(boneKey => {
      const mode = modes[boneKey];
      if (mode && typeof (newPose as any)[boneKey] === 'number') {
        if (mode.isStretch) (newPose as any)[boneKey] = lerp((newPose as any)[boneKey], 0, 0.5); 
        else if (mode.isBend) (newPose as any)[boneKey] = lerp((newPose as any)[boneKey], 80, 0.5);
      }
    });
    return newPose;
  }, []);

  const handleAnchorClick = (boneKey: keyof WalkingEnginePivotOffsets) => {
      if (boneKey !== PartName.LAnkle && boneKey !== PartName.RAnkle) return;
      setActivePins(prev => prev.includes(boneKey) ? prev.filter(k => k !== boneKey) : [...prev, boneKey]);
  };

  const transitionToMode = (targetMode: 'locomotion' | 'idle') => {
      if (engineModeRef.current !== targetMode) { 
        transitionStartWeightRef.current = locomotionWeightRef.current;
        transitionEndWeightRef.current = targetMode === 'locomotion' ? 1.0 : 0.0;
        modeTransitionStartTimeRef.current = performance.now();
        setEngineMode(targetMode);
      }
  };

  const handleIdleChange = useCallback((key: keyof IdleSettings, val: string) => {
    setIdleSettings(prev => ({ ...prev, [key]: parseFloat(val) }));
    transitionToMode('idle');
    setActiveIdlePresetIndex(-1);
  }, []); 

  const handleGaitChange = useCallback((key: keyof WalkingEngineGait, value: string) => { 
    setGait(currentGait => ({ ...currentGait, [key]: parseFloat(value) })); 
    transitionToMode('locomotion');
  }, []); 

  const handleLotteSettingChange = useCallback((key: keyof LotteSettings, value: boolean) => {
    setLotteSettings(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleTogglePause = useCallback(() => setIsPaused(p => {
    if (!p) {
      initialPoseOnPauseRef.current = pose;
      transitionStartTimeRef.current = performance.now();
      setIsTransitioningToRest(true);
      modeTransitionStartTimeRef.current = 0; 
      transitionStartWeightRef.current = 0.0;
      transitionEndWeightRef.current = 0.0;
    } else {
      setIsTransitioningToRest(false);
      transitionStartWeightRef.current = 0.0;
      transitionEndWeightRef.current = (engineModeRef.current === 'locomotion' ? 1.0 : 0.0);
      modeTransitionStartTimeRef.current = performance.now();
    }
    return !p;
  }), [pose]); 

  // Export Logic
  const drawSvgToCanvas = useCallback((onFinish?: (dataUrl: string) => void) => {
    const svg = svgRef.current; const canvas = canvasRef.current; const ctx = canvas?.getContext('2d'); if (!svg || !canvas || !ctx) return;
    const viewBoxString = svg.getAttribute('viewBox'); if (!viewBoxString) return;
    const [, , vbWidth, vbHeight] = viewBoxString.split(' ').map(parseFloat);
    canvas.width = 1500; canvas.height = 1500 * (vbHeight / vbWidth);
    const svgAspect = vbWidth / vbHeight; const canvasAspect = canvas.width / canvas.height;
    let dWidth, dHeight, dx, dy;
    if (canvasAspect > svgAspect) { dHeight = canvas.height; dWidth = dHeight * svgAspect; dx = (canvas.width - dWidth) / 2; dy = 0; } else { dWidth = canvas.width; dHeight = dWidth / svgAspect; dx = 0; dy = (canvas.height - dHeight) / 2; }
    const img = new Image(); const url = URL.createObjectURL(new Blob([new XMLSerializer().serializeToString(svg)], { type: 'image/svg+xml;charset=utf-8' }));
    img.onload = () => { 
      ctx.fillStyle = '#FFFFFF'; ctx.fillRect(0, 0, canvas.width, canvas.height); 
      ctx.drawImage(img, dx, dy, dWidth, dHeight); URL.revokeObjectURL(url); 
      onFinish?.(canvas.toDataURL('image/png'));
    };
    img.src = url;
  }, []);

  const finishRecording = useCallback(async () => {
    setIsRecording(false); setIsZipping(true); setZipProgress(0);
    const format = exportFormat; const frames = capturedFramesRef.current;
    if (format === 'zip') {
      const zip = new JSZip();
      for (let i = 0; i < frames.length; i++) {
        const base64Data = frames[i].replace(/^data:image\/png;base64,/, "");
        zip.file(`frame_${i.toString().padStart(4, '0')}.png`, base64Data, { base64: true });
        setZipProgress(Math.round(((i + 1) / frames.length) * 100));
      }
      const content = await zip.generateAsync({ type: 'blob' });
      saveAs(content, `bitruvius_sequence_${Date.now()}.zip`);
    } else if (format === 'webm') { mediaRecorderRef.current?.stop(); }
    else if (format === 'png') { if (frames.length > 0) saveAs(frames[0], `bitruvius_pose_${Date.now()}.png`); }
    setIsZipping(false); setShowPivots(pivotsOnBeforeRecord.current); setShowLabels(labelsOnBeforeRecord.current);
  }, [exportFormat]);

  const handleStartRecording = useCallback(() => {
    if (isRecording) return;
    pivotsOnBeforeRecord.current = showPivots; labelsOnBeforeRecord.current = showLabels;
    setShowPivots(false); setShowLabels(false);
    framesRecordedRef.current = 0; capturedFramesRef.current = []; recordedChunksRef.current = [];
    hasStartedCycleCaptureRef.current = false; isWebmRecorderStartedRef.current = false; setIsRecording(true);
    if (exportFormat === 'webm') {
      const canvas = canvasRef.current;
      if (canvas) {
        const stream = canvas.captureStream(targetFps);
        const recorder = new MediaRecorder(stream, { mimeType: 'video/webm;codecs=vp9' });
        recorder.ondataavailable = (e) => { if (e.data.size > 0) recordedChunksRef.current.push(e.data); };
        recorder.onstop = () => { saveAs(new Blob(recordedChunksRef.current, { type: 'video/webm' }), `bitruvius_animation_${Date.now()}.webm`); };
        mediaRecorderRef.current = recorder;
      }
    }
  }, [exportFormat, showPivots, showLabels, targetFps]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      const lotte = lotteSettingsRef.current;
      const fpsInterval = lotte.enabled && lotte.frameStepping ? 1000 / 12 : 1000 / targetFps;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < fpsInterval) return;

      const deltaTime = elapsed;
      lastFrameTimeRef.current = time - (elapsed % fpsInterval);

      if (lotte.enabled && lotte.paperJitter) {
          setLotteJitter({ x: (Math.random() - 0.5) * 1.5, y: (Math.random() - 0.5) * 1.5 });
      } else {
          setLotteJitter({ x: 0, y: 0 });
      }

      const targetGait = gaitRef.current;
      const targetIdle = idleSettingsRef.current;
      const targetPhysics = physicsControlsRef.current;

      const newSmoothedGait = { ...smoothedGaitRef.current };
      const newSmoothedIdle = { ...smoothedIdleSettingsRef.current };
      const newSmoothedPhysics = { ...smoothedPhysicsControlsRef.current };
      let needsGaitUpdate = false, needsIdleUpdate = false, needsPhysicsUpdate = false;
      const LERP_FACTOR = 0.2;

      for (const key in targetGait) {
          const k = key as keyof WalkingEngineGait;
          if (Math.abs(targetGait[k] - newSmoothedGait[k]) > 0.001) {
              needsGaitUpdate = true;
              newSmoothedGait[k] = lerp(newSmoothedGait[k], targetGait[k], LERP_FACTOR);
          } else { newSmoothedGait[k] = targetGait[k]; }
      }
      for (const key in targetIdle) {
          const k = key as keyof IdleSettings;
          if (k === 'idlePinnedFeet') { if (newSmoothedIdle[k] !== targetIdle[k]) { needsIdleUpdate = true; newSmoothedIdle[k] = targetIdle[k]; } continue; }
          if (Math.abs(targetIdle[k] - newSmoothedIdle[k]) > 0.001) {
              needsIdleUpdate = true;
              newSmoothedIdle[k] = lerp(newSmoothedIdle[k], targetIdle[k], LERP_FACTOR);
          } else { newSmoothedIdle[k] = targetIdle[k]; }
      }
      for (const key in targetPhysics) {
          const k = key as keyof PhysicsControls;
          if (Math.abs(targetPhysics[k] - newSmoothedPhysics[k]) > 0.001) {
              needsPhysicsUpdate = true;
              newSmoothedPhysics[k] = lerp(newSmoothedPhysics[k], targetPhysics[k], LERP_FACTOR);
          } else { newSmoothedPhysics[k] = targetPhysics[k]; }
      }

      if (needsGaitUpdate) setSmoothedGait(newSmoothedGait);
      if (needsIdleUpdate) setSmoothedIdleSettings(newSmoothedIdle);
      if (needsPhysicsUpdate) setSmoothedPhysicsControls(newSmoothedPhysics);

      let effectiveGait = newSmoothedGait;
      let activePhysics = newSmoothedPhysics;
      let currentIdle = newSmoothedIdle;

      const transitionElapsed = time - modeTransitionStartTimeRef.current;
      const progress = clamp(transitionElapsed / TIMING.MODE_TRANSITION_DURATION, 0, 1);
      locomotionWeightRef.current = lerp(transitionStartWeightRef.current, transitionEndWeightRef.current, easeInOutQuint(progress));
      const locWeight = locomotionWeightRef.current;

      let animationSpeedFactor = animationSpeed;
      if (isSlowMoActive) animationSpeedFactor *= 0.3;

      if (isPaused && !isRecording) {
        if (isTransitioningToRest) {
          const t = easeInOutQuint(Math.min(1, (performance.now() - transitionStartTimeRef.current) / TIMING.PAUSE_TRANSITION_DURATION));
          setPose(prevPose => {
            const newPose = { ...DEFAULT_RESTING_POSE };
            for (const key in newPose) {
              const k = key as keyof WalkingEnginePose;
              (newPose[k] as any) = lerp((initialPoseOnPauseRef.current?.[k] || 0) as number, (DEFAULT_RESTING_POSE[k] as number), t);
            }
            return newPose;
          });
          if (t >= 1) setIsTransitioningToRest(false);
        }
        return;
      }

      const gaitForLocomotionPhysics = engineModeRef.current === 'idle' ? { ...effectiveGait, frequency: 0 } : effectiveGait;
      const p = (time * animationSpeedFactor * 0.005 * effectiveGait.frequency) % (Math.PI * 2);

      let targetBodyRot = bodyRotation;
      if (lotte.enabled && lotte.profileLock) {
          targetBodyRot = lerp(bodyRotation, Math.round(bodyRotation / 90) * 90, 0.1);
      }
      setBodyRotation(targetBodyRot);

      const { pose: rawLocomotionPose, tensions: locomotionTensions, suggestedXOffset: locoX, suggestedYOffset: locoY } = updateLocomotionPhysics(p, locomotionStateRef.current, gaitForLocomotionPhysics, activePhysics, props, activePins, pinnedSlideOffset, gravityCenter, H, isIkEnabled, 1.0);
      const rawIdlePose = updateIdlePhysics(time, deltaTime, currentIdle, locWeight);

      // POSTURE OVERLAYS FOR IDLE
      const idlePresetName = idlePresets[activeIdlePresetIndex]?.name || "";
      if (engineMode === 'idle' && locomotionWeightRef.current < 0.1) {
          if (idlePresetName === "Crossed Arms") {
              rawIdlePose[PartName.LShoulder] = 30; rawIdlePose[PartName.RShoulder] = -30;
              rawIdlePose[PartName.LElbow] = 100; rawIdlePose[PartName.RElbow] = 100;
              rawIdlePose[PartName.LWrist] = -40; rawIdlePose[PartName.RWrist] = -40;
          } else if (idlePresetName === "Heroic Flex") {
              rawIdlePose[PartName.LShoulder] = 90; rawIdlePose[PartName.RShoulder] = -90;
              rawIdlePose[PartName.LElbow] = 90; rawIdlePose[PartName.RElbow] = 90;
          } else if (idlePresetName === "Lazy Grasp") {
              rawIdlePose[PartName.LShoulder] = -10; rawIdlePose[PartName.LElbow] = 30;
              rawIdlePose[PartName.LWrist] = 20;
          } else if (idlePresetName === "Scratching") {
              rawIdlePose[PartName.RShoulder] = 140; rawIdlePose[PartName.RElbow] = 140;
              rawIdlePose[PartName.RWrist] = -20 + (Math.sin(time * 0.01) * 20);
          }
      }

      const blendedRawPose: Partial<WalkingEnginePose> = {};
      const allKeys = new Set([...Object.keys(rawLocomotionPose), ...Object.keys(rawIdlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;

      allKeys.forEach(key => {
          const locoVal = (rawLocomotionPose as any)[key] ?? 0;
          const idleVal = (rawIdlePose as any)[key] ?? 0;
          if (key === 'x_offset') blendedRawPose.x_offset = lerp(idleVal, locoX, locWeight);
          else if (key === 'y_offset') blendedRawPose.y_offset = lerp(idleVal, locoY, locWeight);
          else (blendedRawPose as any)[key] = lerp(idleVal, locoVal, locWeight);
      });

      const { adjustedPose, tensions: groundingTensions } = applyFootGrounding(blendedRawPose, props, H, activePhysics, activePins, currentIdle, gravityCenter, locWeight, deltaTime);
      setTensions({ ...locomotionTensions, ...groundingTensions });

      const poseWithModes = applyJointModes(adjustedPose as WalkingEnginePose, jointModesRef.current);
      setPose(poseWithModes);

      if (isRecording) {
        let shouldCapture = false;
        if (exportFormat === 'png') { shouldCapture = true; finishRecording(); }
        else if (syncToCycle && engineMode === 'locomotion') {
          if (!hasStartedCycleCaptureRef.current) { if (p < lastPhaseRef.current) { hasStartedCycleCaptureRef.current = true; if (exportFormat === 'webm') mediaRecorderRef.current?.start(); shouldCapture = true; } }
          else { if (p < lastPhaseRef.current) { finishRecording(); } else { shouldCapture = true; } }
        } else { if (framesRecordedRef.current < recordFrameCount) { if (exportFormat === 'webm' && !isWebmRecorderStartedRef.current) { mediaRecorderRef.current?.start(); isWebmRecorderStartedRef.current = true; } shouldCapture = true; } else { finishRecording(); } }
        if (shouldCapture) drawSvgToCanvas((data) => { if (exportFormat === 'zip' || exportFormat === 'png') capturedFramesRef.current.push(data); framesRecordedRef.current++; });
      }
      lastPhaseRef.current = p;
    };
    lastFrameTimeRef.current = performance.now(); frame = requestAnimationFrame(animate); return () => cancelAnimationFrame(frame);
  }, [ isPaused, isRecording, targetFps, animationSpeed, engineMode, activePins, pinnedSlideOffset, gravityCenter, props, isSlowMoActive, isIkEnabled, applyJointModes, exportFormat, syncToCycle, recordFrameCount, finishRecording, drawSvgToCanvas, bodyRotation, activeIdlePresetIndex ]);

  return (
    <div ref={containerRef} className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <div className="flex flex-col gap-2">
              <button onClick={handleTogglePause} className={`text-[9px] px-3 py-1 border transition-all ${isPaused ? 'bg-red-500/20 text-accent-red border-accent-red/50' : 'bg-paper/10 text-mono-mid border-ridge hover:bg-ridge'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
              <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection-super-light text-ink border-selection-super-light' : 'bg-paper/10 text-mono-mid border-ridge hover:bg-ridge'}`}>{showPivots ? 'HIDE ANCHORS' : 'SHOW ANCHORS'}</button>
          </div>

          <div className="flex gap-2 mb-2">
            <button onClick={() => transitionToMode('locomotion')} className={`flex-1 text-[9px] px-3 py-1 border transition-all ${engineMode === 'locomotion' ? 'bg-selection text-paper border-selection' : 'bg-paper/10 text-mono-mid border-ridge hover:bg-ridge'}`}>WALK</button>
            <button onClick={() => transitionToMode('idle')} className={`flex-1 text-[9px] px-3 py-1 border transition-all ${engineMode === 'idle' ? 'bg-selection text-paper border-selection' : 'bg-paper/10 text-mono-mid border-ridge hover:bg-ridge'}`}>IDLE</button>
          </div>

          <CollapsibleSection title="Lotte Dynamics" defaultOpen={lotteSettings.enabled}>
            <div className="flex flex-col gap-3">
              <button onClick={() => handleLotteSettingChange('enabled', !lotteSettings.enabled)} className={`w-full text-[9px] py-1 border font-bold transition-all ${lotteSettings.enabled ? 'bg-selection text-paper' : 'bg-paper/10 border-ridge text-mono-mid'}`}>
                {lotteSettings.enabled ? 'LOTTE MODE: ACTIVE' : 'LOTTE MODE: INACTIVE'}
              </button>

              <div className="flex flex-col gap-2 pt-2 border-t border-ridge/30">
                {(['frameStepping', 'cutoutSnap', 'paperJitter', 'shadowBlur', 'profileLock'] as const).map(key => (
                  <div key={key} className="flex justify-between items-center">
                    <span className="text-[7px] uppercase font-bold text-mono-light">{key.replace(/([A-Z])/g, ' $1')}</span>
                    <button onClick={() => handleLotteSettingChange(key, !lotteSettings[key])} className={`text-[7px] px-2 py-0.5 border ${lotteSettings[key] ? 'bg-selection text-paper' : 'bg-paper/10 text-mono-mid border-ridge'}`}>
                      {lotteSettings[key] ? 'ON' : 'OFF'}
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Idle Dynamics" defaultOpen={engineMode === 'idle'}>
            <div className="flex flex-col gap-3">
                <div className="flex gap-1 mb-2 overflow-x-auto custom-scrollbar pb-1 -mx-1 px-1">
                    <div className="flex gap-1 min-w-max">
                        {idlePresets.map((preset, idx) => (<button key={idx} onClick={() => { setIdleSettings(generateRandomIdle(preset)); setActiveIdlePresetIndex(idx); transitionToMode('idle'); }} className={`text-[8px] px-3 py-1 border transition-all whitespace-nowrap ${activeIdlePresetIndex === idx ? 'bg-selection text-paper' : 'bg-paper/10 border-ridge text-mono-mid'}`}>{preset.name}</button>))}
                    </div>
                </div>
                <div className="flex flex-col gap-2">
                    {Object.keys(DEFAULT_IDLE_SETTINGS).filter(k => k !== 'idlePinnedFeet').map(k => {
                        const key = k as keyof Omit<IdleSettings, 'idlePinnedFeet'>;
                        return (<div key={key}>
                          <div className="flex justify-between text-[7px] uppercase font-bold text-mono-light"><span>{key.replace(/([A-Z])/g, ' $1')}</span><span className="text-selection">{idleSettings[key].toFixed(2)}</span></div>
                          <input type="range" min={key === 'posture' ? -1 : (key === 'transitionSpeed' ? 0.1 : 0)} max={key === 'posture' ? 1 : (key === 'transitionSpeed' ? 0.5 : 1)} step="0.01" value={idleSettings[key]} onChange={(e) => handleIdleChange(key, e.target.value)} className="w-full accent-selection bg-ridge h-1 appearance-none cursor-pointer" />
                        </div>)
                    })}
                </div>
                <CollapsibleSection title="Idle Anchoring" defaultOpen={true}>
                    <div className="flex gap-1 justify-between pt-2">
                        {(['none', 'left', 'right', 'both'] as const).map(opt => <button key={opt} onClick={() => { setIdleSettings(prev => ({ ...prev, idlePinnedFeet: opt })); transitionToMode('idle'); }} className={`flex-1 text-[8px] py-1 border transition-all ${idleSettings.idlePinnedFeet === opt ? 'bg-selection text-paper' : 'bg-paper/10 border-ridge text-mono-mid'}`}>{opt.toUpperCase()}</button>)}
                    </div>
                </CollapsibleSection>
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Advanced Locomotion" defaultOpen={engineMode === 'locomotion'}>
            <div className="flex flex-col gap-3">
                <div className="flex gap-1 overflow-x-auto custom-scrollbar pb-1 -mx-1 px-1">
                    <div className="flex gap-1 min-w-max">
                        {gaitPresets.map((preset, idx) => (<button key={idx} onClick={() => { setGait(generateRandomGait(preset)); transitionToMode('locomotion'); }} className={`text-[8px] px-3 py-1 border transition-all whitespace-nowrap bg-paper/10 border-ridge text-mono-mid`}>{preset.name}</button>))}
                    </div>
                </div>
                <CollapsibleSection title="Gait Controls" defaultOpen={true}>
                  <div className="space-y-2 mt-2 border-t border-ridge pt-3 h-64 overflow-y-auto custom-scrollbar"> 
                    {(Object.keys(gaitSliderConfig) as Array<keyof WalkingEngineGait>).map(key => {
                        const config = gaitSliderConfig[key]; if (!config) return null;
                        return (<div key={key}>
                            <div className="flex justify-between text-[7px] uppercase font-bold text-mono-light"><span>{config.label}</span><span className="text-selection">{gait[key].toFixed(2)}</span></div>
                            <input type="range" min={config.min} max={config.max} step={config.step} value={gait[key]} onChange={(e) => handleGaitChange(key, e.target.value)} className="w-full accent-selection bg-ridge h-1 appearance-none cursor-pointer" />
                        </div>)
                    })}
                  </div>
                </CollapsibleSection>
            </div>
          </CollapsibleSection>
        </div>
      )}

      <div className="flex-1 relative flex items-center justify-center bg-paper overflow-hidden">
        <canvas ref={canvasRef} className="hidden" />
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker/80 rounded-full transition-all text-ink">{isConsoleVisible ? '✕' : '☰'}</button>
        <svg ref={svgRef} viewBox={viewBox} className={`w-full h-full overflow-visible relative z-10 ${lotteSettings.enabled && lotteSettings.shadowBlur ? 'drop-shadow-2xl' : ''}`}>
          <g transform={`translate(${pose.x_offset + shakeOffset.x + lotteJitter.x}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset + shakeOffset.y + lotteJitter.y})`}>
             <Mannequin pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={props} showPivots={showPivots} showLabels={showLabels} baseUnitH={H} onAnchorMouseDown={handleAnchorClick} draggingBoneKey={null} isPaused={isPaused} activePins={activePins} tensions={tensions} jointModes={jointModes} lotteSettings={lotteSettings} />
          </g>
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useCallback } from 'react';
import { Bone } from './Bone';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING, CUTOUT_GAP_SIZE } from '../constants'; 
import { WalkingEnginePose, WalkingEngineProportions, WalkingEnginePivotOffsets, Vector2D, JointModesState, LotteSettings, PartName } from '../types';

interface MannequinProps {
  pose: WalkingEnginePose;
  bodyRotation: number;
  pivotOffsets: Record<string, number>;
  props: WalkingEngineProportions;
  showPivots: boolean;
  showLabels: boolean;
  baseUnitH: number;
  onAnchorMouseDown: (boneKey: keyof WalkingEnginePivotOffsets, clientX: number) => void;
  draggingBoneKey: keyof WalkingEnginePivotOffsets | null;
  isPaused: boolean;
  customTextures?: Partial<Record<keyof WalkingEngineProportions, string | null>>;
  onPlusClick?: (partKey: keyof WalkingEngineProportions) => void;
  activePins: string[];
  tensions: Record<string, number>;
  isSafeSwitchActive?: boolean;
  jointModes: JointModesState;
  lotteSettings: LotteSettings; 
}

const RENDER_ORDER: (keyof WalkingEngineProportions)[] = [
    'waist', 'torso', 'l_upper_leg', 'r_upper_leg', 'l_lower_leg', 'r_lower_leg', 'l_foot', 'r_foot', 'l_toe', 'r_toe', 
    'collar', 'l_upper_arm', 'r_upper_arm', 'head', 'l_lower_arm', 'r_lower_arm', 'l_hand', 'r_hand'
];

const partDefinitions: Record<keyof WalkingEngineProportions, any> = {
    head: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD_WIDTH, variant: 'head-tall-oval', drawsUpwards: true, label: 'Head', boneKey: 'neck' },
    collar: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR_WIDTH, variant: 'collar-horizontal-oval-shape', drawsUpwards: true, label: 'Collar', boneKey: 'collar' },
    torso: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO_WIDTH, variant: 'torso-teardrop-pointy-down', drawsUpwards: true, label: 'Torso', boneKey: 'torso' },
    waist: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST_WIDTH, variant: 'waist-teardrop-pointy-up', drawsUpwards: true, label: 'Waist', boneKey: 'waist' },
    r_upper_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_ARM, variant: 'deltoid-shape', label: 'R.Bicep', boneKey: PartName.RShoulder },
    r_lower_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM, variant: 'limb-tapered', label: 'R.Forearm', boneKey: PartName.RElbow },
    r_hand: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'R.Hand', boneKey: PartName.RWrist },
    l_upper_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_ARM, variant: 'deltoid-shape', label: 'L.Bicep', boneKey: PartName.LShoulder },
    l_lower_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM, variant: 'limb-tapered', label: 'L.Forearm', boneKey: PartName.LElbow },
    l_hand: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'L.Hand', boneKey: PartName.LWrist },
    r_upper_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_THIGH, variant: 'limb-tapered', label: 'R.Thigh', boneKey: PartName.RThigh },
    r_lower_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_CALF, variant: 'limb-tapered', label: 'R.Calf', boneKey: PartName.RKnee },
    r_foot: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'R.Foot', boneKey: PartName.RAnkle },
    r_toe: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE_WIDTH, variant: 'toe-triangle', label: 'R.Toe', boneKey: PartName.RToe },
    l_upper_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_THIGH, variant: 'limb-tapered', label: 'L.Thigh', boneKey: PartName.LThigh },
    l_lower_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_CALF, variant: 'limb-tapered', label: 'L.Calf', boneKey: PartName.LKnee },
    l_foot: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'L.Foot', boneKey: PartName.LAnkle },
    l_toe: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE_WIDTH, variant: 'toe-triangle', label: 'L.Toe', boneKey: PartName.LToe },
};

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

export const Mannequin: React.FC<MannequinProps> = ({
  pose, bodyRotation, pivotOffsets, props, showPivots, showLabels, baseUnitH,
  onAnchorMouseDown, draggingBoneKey, isPaused,
  customTextures, activePins, tensions, jointModes, lotteSettings, 
}) => {

    const getScaledDimension = useCallback((rawAnatomyValue: number, propKey: keyof WalkingEngineProportions, axis: 'w' | 'h') => {
        const propScale = props[propKey]?.[axis] || 1;
        return rawAnatomyValue * baseUnitH * propScale;
    }, [props, baseUnitH]);

    const calculateGlobalTransforms = useCallback(() => {
        const transforms: Partial<Record<keyof WalkingEngineProportions, { position: Vector2D; rotation: number }>> = {};
        const isCutoutMode = lotteSettings.enabled && lotteSettings.cutoutSnap;

        const getDrawLength = (rawAnatomyValue: number, propKey: keyof WalkingEngineProportions, axis: 'h'): number => {
            const fullLength = getScaledDimension(rawAnatomyValue, propKey, axis);
            return isCutoutMode ? Math.max(0, fullLength - CUTOUT_GAP_SIZE * 2) : fullLength;
        };

        const getChildPivotPosition = (parentGlobalPos: Vector2D, parentDrawLength: number, parentGlobalRot: number, drawsParentUpwards: boolean): Vector2D => {
            const yOffset = drawsParentUpwards 
                ? -(parentDrawLength + (isCutoutMode ? CUTOUT_GAP_SIZE * 2 : 0)) 
                : (parentDrawLength + (isCutoutMode ? CUTOUT_GAP_SIZE * 2 : 0));
            return addVec(parentGlobalPos, rotateVec({ x: 0, y: yOffset }, parentGlobalRot));
        };

        const getRotation = (partKey: string) => {
            const partRotation = (pose as any)[partKey] || 0;
            const offset = (pivotOffsets as any)[partKey] || 0; 
            return partRotation + offset;
        };

        const waistDrawLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist', 'h');
        const waistRot = getRotation(PartName.Waist) + bodyRotation;
        transforms.waist = { position: { x: 0, y: 0 }, rotation: waistRot };

        const torsoDrawLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso', 'h');
        const torsoPos = getChildPivotPosition(transforms.waist.position, waistDrawLen, waistRot, true);
        const torsoRot = waistRot + getRotation(PartName.Torso);
        transforms.torso = { position: torsoPos, rotation: torsoRot };

        const collarDrawLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar', 'h');
        const effectiveCollarYOffset = (RIGGING.COLLAR_OFFSET_Y + (pose.collarYOffset || 0)) * baseUnitH; 
        const collarStartPos = getChildPivotPosition(torsoPos, torsoDrawLen, torsoRot, true);
        collarStartPos.y += effectiveCollarYOffset; 
        const collarRot = torsoRot + getRotation(PartName.Collar);
        transforms.collar = { position: collarStartPos, rotation: collarRot };

        const headOffset = {x: 0, y: -ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD_NECK_GAP_OFFSET * baseUnitH};
        const headPos = getChildPivotPosition(collarStartPos, collarDrawLen, collarRot, true);
        headPos.y += headOffset.y; 
        const headRot = collarRot + getRotation('neck');
        transforms.head = { position: headPos, rotation: headRot };

        const rShoulderOffset = {x: RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER * baseUnitH, y: RIGGING.SHOULDER_Y_OFFSET_FROM_COLLAR_END * baseUnitH};
        const rShoulderStartPos = addVec(collarStartPos, rotateVec({x: rShoulderOffset.x, y: -collarDrawLen + rShoulderOffset.y + (isCutoutMode ? CUTOUT_GAP_SIZE * 2 : 0) }, collarRot)); 
        const rShoulderRot = collarRot + getRotation(PartName.RShoulder);
        transforms.r_upper_arm = { position: rShoulderStartPos, rotation: rShoulderRot };

        const rUpperArmLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, 'r_upper_arm', 'h'); 
        const rElbowPos = getChildPivotPosition(rShoulderStartPos, rUpperArmLen, rShoulderRot, false);
        const rElbowRot = rShoulderRot + getRotation(PartName.RElbow);
        transforms.r_lower_arm = {position: rElbowPos, rotation: rElbowRot};

        const rLowerArmLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, 'r_lower_arm', 'h'); 
        const rHandPos = getChildPivotPosition(rElbowPos, rLowerArmLen, rElbowRot, false);
        const rHandRot = rElbowRot + getRotation(PartName.RWrist);
        transforms.r_hand = {position: rHandPos, rotation: rHandRot};

        const lShoulderOffset = {x: RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER * baseUnitH, y: RIGGING.SHOULDER_Y_OFFSET_FROM_COLLAR_END * baseUnitH};
        const lShoulderStartPos = addVec(collarStartPos, rotateVec({x: lShoulderOffset.x, y: -collarDrawLen + lShoulderOffset.y + (isCutoutMode ? CUTOUT_GAP_SIZE * 2 : 0)}, collarRot)); 
        const lShoulderRot = collarRot + getRotation(PartName.LShoulder);
        transforms.l_upper_arm = { position: lShoulderStartPos, rotation: lShoulderRot };

        const lUpperArmLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, 'l_upper_arm', 'h'); 
        const lElbowPos = getChildPivotPosition(lShoulderStartPos, lUpperArmLen, lShoulderRot, false);
        const lElbowRot = lShoulderRot + getRotation(PartName.LElbow);
        transforms.l_lower_arm = {position: lElbowPos, rotation: lElbowRot};

        const lLowerArmLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, 'l_lower_arm', 'h'); 
        const lHandPos = getChildPivotPosition(lElbowPos, lLowerArmLen, lElbowRot, false);
        const lHandRot = lElbowRot + getRotation(PartName.LWrist);
        transforms.l_hand = {position: lHandPos, rotation: lHandRot};

        const rThighPos = { x: 0, y: 0 };
        const rThighRot = bodyRotation + getRotation(PartName.RThigh);
        transforms.r_upper_leg = {position: rThighPos, rotation: rThighRot};
        const rThighLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg', 'h'); 
        const rKneePos = getChildPivotPosition(rThighPos, rThighLen, rThighRot, false);
        const rKneeRot = rThighRot + getRotation(PartName.RKnee);
        transforms.r_lower_leg = {position: rKneePos, rotation: rKneeRot};
        const rLowerLegLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg', 'h'); 
        const rFootPos = getChildPivotPosition(rKneePos, rLowerLegLen, rKneeRot, false);
        const rFootRot = rKneeRot + getRotation(PartName.RAnkle);
        transforms.r_foot = {position: rFootPos, rotation: rFootRot};
        const rFootLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, 'r_foot', 'h'); 
        const rToePos = getChildPivotPosition(rFootPos, rFootLen, rFootRot, false);
        if (pose.r_toe_y_offset) {
            const offsetVector = rotateVec({ x: 0, y: pose.r_toe_y_offset }, rFootRot);
            rToePos.x += offsetVector.x; rToePos.y += offsetVector.y;
        }
        const rToeRot = rFootRot + getRotation(PartName.RToe);
        transforms.r_toe = {position: rToePos, rotation: rToeRot};

        const lThighPos = { x: 0, y: 0 };
        const lThighRot = bodyRotation + getRotation(PartName.LThigh);
        transforms.l_upper_leg = {position: lThighPos, rotation: lThighRot};
        const lThighLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'l_upper_leg', 'h'); 
        const lKneePos = getChildPivotPosition(lThighPos, lThighLen, lThighRot, false);
        const lKneeRot = lThighRot + getRotation(PartName.LKnee);
        transforms.l_lower_leg = {position: lKneePos, rotation: lKneeRot};
        const lLowerLegLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'l_lower_leg', 'h'); 
        const lFootPos = getChildPivotPosition(lKneePos, lLowerLegLen, lKneeRot, false);
        const lFootRot = lKneeRot + getRotation(PartName.LAnkle);
        transforms.l_foot = {position: lFootPos, rotation: lFootRot};
        const lFootLen = getDrawLength(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, 'l_foot', 'h'); 
        const lToePos = getChildPivotPosition(lFootPos, lFootLen, lFootRot, false);
        if (pose.l_toe_y_offset) {
            const offsetVector = rotateVec({ x: 0, y: pose.l_toe_y_offset }, lFootRot);
            lToePos.x += offsetVector.x; lToePos.y += offsetVector.y;
        }
        const lToeRot = lFootRot + getRotation(PartName.LToe);
        transforms.l_toe = {position: lToePos, rotation: lToeRot};

        return transforms;
    }, [pose, pivotOffsets, getScaledDimension, bodyRotation, baseUnitH, lotteSettings.enabled, lotteSettings.cutoutSnap]);

    const globalTransforms = useMemo(() => calculateGlobalTransforms(), [calculateGlobalTransforms]);
    const filterId = lotteSettings.enabled ? 'url(#grainy-paper-texture)' : '';

    return (
        <g filter={filterId}>
            <defs>
                {Object.entries(customTextures || {}).map(([partKey, textureUrl]) =>
                textureUrl ? (
                    <pattern key={`pattern-${partKey}`} id={`texture-${partKey}`} patternUnits="objectBoundingBox" width="1" height="1">
                        <image href={textureUrl} x="0" y="0" width="1" height="1" preserveAspectRatio="none" />
                    </pattern>
                ) : null
                )}
                <filter id="grainy-paper-texture" x="-50%" y="-50%" width="200%" height="200%">
                    <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" result="noise" />
                    <feColorMatrix type="saturate" values="0" />
                    <feComposite operator="in" in2="SourceGraphic" result="texture" />
                    <feBlend mode="multiply" in="SourceGraphic" in2="texture" result="blended" />
                </filter>
            </defs>

            {showPivots && <circle cx="0" cy="0" r={ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.ROOT_SIZE * baseUnitH * 0.7} fill="#DDDDDD" stroke="#000000" strokeWidth="1" data-no-export={true} />}
            {RENDER_ORDER.map(partKey => {
                const partProps = partDefinitions[partKey]; if (!partProps) return null;
                const target = globalTransforms[partKey]; if (!target) return null;
                const textureUrl = customTextures?.[partKey];
                const boneKey = partProps.boneKey as keyof WalkingEnginePivotOffsets;
                const isPinned = activePins.includes(boneKey);
                const currentTension = tensions[boneKey] || 0;
                const { isBend = false, isStretch = false } = jointModes[boneKey] || {};
                const boneLength = lotteSettings.enabled && lotteSettings.cutoutSnap
                    ? Math.max(0, getScaledDimension(partProps.rawH, partKey, 'h') - CUTOUT_GAP_SIZE * 2)
                    : getScaledDimension(partProps.rawH, partKey, 'h');

                return (
                    <g key={partKey} transform={`translate(${target.position.x}, ${target.position.y}) rotate(${target.rotation})`}>
                        <Bone 
                            rotation={0}
                            length={boneLength} 
                            width={getScaledDimension(partProps.rawW, partKey, 'w')}
                            variant={partProps.variant}
                            drawsUpwards={partProps.drawsUpwards}
                            label={partProps.label}
                            boneKey={boneKey}
                            proportionKey={partKey}
                            visible={true}
                            colorClass="fill-black"
                            showPivots={showPivots}
                            showLabel={showLabels}
                            offset={{x: 0, y: 0}}
                            onAnchorMouseDown={onAnchorMouseDown}
                            isBeingDragged={draggingBoneKey === partProps.boneKey}
                            isPausedAndPivotsVisible={showPivots}
                            patternFillId={textureUrl ? `url(#texture-${partKey})` : undefined}
                            isPinned={isPinned}
                            isBendActive={isBend}
                            isStretchActive={isStretch}
                            tension={currentTension}
                            isCutoutMode={lotteSettings.enabled && lotteSettings.cutoutSnap} 
                        />
                    </g>
                );
            })}
        </g>
    );
};

