const DEFAULT_PHYSICS_CONTROLS: PhysicsControls = { motionSmoothing: 0.85, jointElasticity: 0.8, stabilization: 0.75, impactDamping: 0.2, bodyMass: 0.5, pendulumDrag: 0.3, bounceIntensity: 0.5 };
const DEFAULT_PIVOT_OFFSETS: WalkingEnginePivotOffsets = { neck: 0, collar: 0, torso: 0, waist: 0, [PartName.LShoulder]: 0, [PartName.RShoulder]: 0, [PartName.LElbow]: 0, [PartName.RElbow]: 0, [PartName.LWrist]: 0, [PartName.RWrist]: 0, [PartName.LThigh]: 0, [PartName.RThigh]: 0, [PartName.LKnee]: 0, [PartName.RKnee]: 0, [PartName.LAnkle]: 0, [PartName.RAnkle]: 0, [PartName.LToe]: 0, [PartName.RToe]: 0 };
const DEFAULT_PROPORTIONS: WalkingEngineProportions = { head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 }, l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 0.5, h: 1 }, r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 0.5, h: 1 }, l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 }, r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 } };
const DEFAULT_GAIT_SETTINGS: WalkingEngineGait = {
