/**
 * BITRUVIAN IMAGE PROCESSOR
 * Handles background elimination and texture prep.
 */

export const processTextureImage = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return reject('No context');

        canvas.width = img.width;
        canvas.height = img.height;
        ctx.drawImage(img, 0, 0);

        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const data = imageData.data;

        // Sample background color from top-left pixel
        const bgR = data[0];
        const bgG = data[1];
        const bgB = data[2];

        // Sensitivity parameters
        const colorThreshold = 45; // Max distance from background color
        const darkLuminanceThreshold = 80; // Keep pixels darker than this (internal lines)

        for (let i = 0; i < data.length; i += 4) {
          const r = data[i];
          const g = data[i + 1];
          const b = data[i + 2];

          // Calculate Euclidean distance in RGB space
          const distance = Math.sqrt(
            Math.pow(r - bgR, 2) + 
            Math.pow(g - bgG, 2) + 
            Math.pow(b - bgB, 2)
          );

          // Calculate luminance (perceived brightness)
          const luminance = 0.299 * r + 0.587 * g + 0.114 * b;

          // If it matches the background color and isn't a dark line, make it transparent
          if (distance < colorThreshold && luminance > darkLuminanceThreshold) {
            data[i + 3] = 0; // Alpha
          }
        }

        ctx.putImageData(imageData, 0, 0);
        resolve(canvas.toDataURL('image/png'));
      };
      img.onerror = reject;
      img.src = e.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

