const calculateLegAngles = (s: number, g: WalkingEngineGait, phase: number, wf: number, baseUnitH: number) => {
  const hipMult = (GAIT_PHYSICS.HIP_BASE_MULTIPLIER + (g.stride * GAIT_PHYSICS.HIP_STRIDE_FACTOR)) * 
                  (GAIT_PHYSICS.HIP_INTENSITY_BASE + g.intensity * GAIT_PHYSICS.HIP_INTENSITY_FACTOR);
  let hip = s * hipMult;
  let knee = 0;
  let foot = -90;
  let toe = 0;
  let impactSignal = 0;
  let yOffset = 0;

  const stanceThreshold = -Math.max(0, (g.intensity - 1.0) * 0.4);

  if (s < stanceThreshold) {
    const stanceProgress = ((phase % (2 * Math.PI)) - Math.PI) / Math.PI;
    knee = g.gravity * GAIT_PHYSICS.STANCE_KNEE_GRAVITY_FACTOR * (1 - Math.sin(stanceProgress * Math.PI)) * wf;
    if (stanceProgress < 0.15) { 
      const t = stanceProgress / 0.15; 
      foot += lerp(GAIT_PHYSICS.STANCE_HEEL_STRIKE_ANGLE, 0, t); 
      toe = lerp(GAIT_PHYSICS.STANCE_TOE_STRIKE_ANGLE, 0, t); 
    } 
    else if (stanceProgress > 0.6) { 
      const t = (stanceProgress - 0.6) / 0.4; 
      foot += lerp(0, GAIT_PHYSICS.STANCE_TOE_OFF_ANGLE, t) * (g.foot_roll + g.kick_up_force * 0.1); 
      const toeBreakThreshold = GAIT_PHYSICS.TOE_BREAK_THRESHOLD_FACTOR * g.foot_roll;
      if (g.foot_roll > 0.01 && (foot + 90) < toeBreakThreshold) {
        const den = (GAIT_PHYSICS.STANCE_TOE_OFF_ANGLE * g.foot_roll) - toeBreakThreshold;
        if (Math.abs(den) > 0.01) {
          toe = Math.sin(Math.max(0, ((foot + 90) - toeBreakThreshold) / den) * Math.PI / 2) * 
                (GAIT_PHYSICS.TOE_BEND_MAX_ANGLE + g.kick_up_force * GAIT_PHYSICS.TOE_KICK_BONUS) * g.toe_bend;
        }
      }
    }
  } else {
    const swingArc = Math.sin(s * Math.PI); 
    const airFactor = GAIT_PHYSICS.HOVER_AIR_FACTOR_BASE - g.gravity;
    const hLift = g.hover_height * GAIT_PHYSICS.HOVER_HEIGHT_MULTIPLIER * swingArc * airFactor;
    hip -= hLift;
    knee = ((g.stride + g.intensity) * GAIT_PHYSICS.SWING_KNEE_BASE_FACTOR * airFactor) + hLift * GAIT_PHYSICS.SWING_KNEE_HOVER_RATIO;
    foot += GAIT_PHYSICS.SWING_FOOT_DORSIFLEXION * swingArc * (1 + g.gravity * GAIT_PHYSICS.SWING_FOOT_GRAVITY_FACTOR);

    const swingVelocity = Math.cos(phase);
    if (swingVelocity > 0) {
        const dragEffect = GAIT_PHYSICS.FOOT_DRAG_MAX_ANGLE * g.footDrag * swingVelocity;
        foot += dragEffect;
    }

    if (s / STOMP_PHYSICS.HOLD_THRESHOLD <= 1) { 
      const kick = Math.sin((s / STOMP_PHYSICS.HOLD_THRESHOLD) * Math.PI); 
      knee += kick * g.kick_up_force * GAIT_PHYSICS.KICK_UP_KNEE_AMPLITUDE * airFactor; 
      foot -= kick * g.kick_up_force * GAIT_PHYSICS.KICK_UP_FOOT_AMPLITUDE * airFactor; 
    }
    if (g.heavyStomp > 0) {
      knee += swingArc * STOMP_PHYSICS.KNEE_LIFT_AMPLITUDE * g.heavyStomp;
      hip -= swingArc * STOMP_PHYSICS.HIP_CLEARANCE * g.heavyStomp;
      const swingProgress = (phase % (2 * Math.PI)) / Math.PI;
      if (swingProgress > STOMP_PHYSICS.DESCENT_THRESHOLD) {
        const attack = (swingProgress - STOMP_PHYSICS.DESCENT_THRESHOLD) / (1 - STOMP_PHYSICS.DESCENT_THRESHOLD);
        const attackCurve = easeInQuint(clamp(attack, 0, 1));
        knee = lerp(knee, 0, attackCurve * g.heavyStomp * STOMP_PHYSICS.KNEE_ATTACK_MULTIPLIER);
        foot = lerp(foot, STOMP_PHYSICS.IMPACT_FLAT_FOOT_TARGET, attackCurve * g.heavyStomp);
        toe -= attackCurve * g.heavyStomp * GAIT_PHYSICS.TOE_BEND_MAX_ANGLE * 0.3;
        impactSignal = attackCurve * g.heavyStomp;
        yOffset = impactSignal * baseUnitH * 0.03;
      } else if (swingProgress > STOMP_PHYSICS.HOLD_THRESHOLD) {
        knee += STOMP_PHYSICS.HOLD_KNEE_BONUS * g.heavyStomp;
      }
    }
  }
  return { hip, knee, foot, toe, impactSignal, yOffset };
};

export const calculateFootTipGlobalPosition = (
  legAngles: { hip: number; knee: number; foot: number; toe: number },
  props: WalkingEngineProportions,
  baseUnitH: number,
  isRight: boolean
): Vector2D => {
  const rad = (deg: number) => deg * Math.PI / 180;
  const tKey = isRight ? 'r_upper_leg' : 'l_upper_leg';
  const cKey = isRight ? 'r_lower_leg' : 'l_lower_leg';
  const fKey = isRight ? 'r_foot' : 'l_foot';
  const toKey = isRight ? 'r_toe' : 'l_toe';
  const tL = (props[tKey]?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER * baseUnitH;
  const cL = (props[cKey]?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER * baseUnitH;
  const fL = (props[fKey]?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT * baseUnitH;
  const toL = (props[toKey]?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE * baseUnitH;
  const hG = rad(legAngles.hip);
  const kG = hG + rad(legAngles.knee);
  const fG = kG + rad(legAngles.foot);
  const toG = fG + rad(legAngles.toe);
  return { 
    x: tL * Math.sin(hG) + cL * Math.sin(kG) + fL * Math.sin(fG) + toL * Math.sin(toG),
    y: tL * Math.cos(hG) + cL * Math.cos(kG) + fL * Math.cos(fG) + toL * Math.cos(toG),
  };
};

export const updateLocomotionPhysics = (
  p: number, state: LocomotionState, gait: WalkingEngineGait, physics: PhysicsControls, props: WalkingEngineProportions, activePins: string[], pinnedSlideOffset: number, gravityCenter: 'left' | 'center' | 'right', baseUnitH: number, isIkEnabled: boolean, weightFactor: number = 1.0, hipSwayMaxLimit: number = 1.5, waistTwistMaxLimit: number = 2.0
): { pose: Partial<WalkingEnginePose>, tensions: Record<string, number>, shakeIntensity: number, suggestedXOffset: number, suggestedYOffset: number } => {
  const tensions: Record<string, number> = {};
  let shakeIntensity = 0;
  let suggestedXOffset = 0;
  let suggestedYOffset = 0;

  if (Math.abs(gait.frequency) < 0.001) {
    return { pose: { bodyRotation: 0, waist: 0, torso: 0, collar: 0, neck: 0, [PartName.LShoulder]: 0, [PartName.RShoulder]: 0, [PartName.LElbow]: 0, [PartName.RElbow]: 0, [PartName.LWrist]: 0, [PartName.RWrist]: 0, [PartName.LThigh]: 0, [PartName.LKnee]: 0, [PartName.LAnkle]: -90, [PartName.LToe]: 0, [PartName.RThigh]: 0, [PartName.RKnee]: 0, [PartName.RAnkle]: -90, [PartName.RToe]: 0 }, tensions: {}, shakeIntensity: 0, suggestedXOffset: 0, suggestedYOffset: 0 };
  }

  let stab = physics.stabilization;
  const cycle_p = p % (Math.PI * 2);
  const doubleSupportWindow = Math.PI * 0.15 * (1.5 - gait.intensity);
  const isWeightTransfer = (cycle_p > Math.PI - doubleSupportWindow && cycle_p < Math.PI + doubleSupportWindow) || cycle_p > (2 * Math.PI - doubleSupportWindow) || cycle_p < doubleSupportWindow;
  if (isWeightTransfer) stab = lerp(stab, 0.99, 0.25);
  const alpha = 1.0 - stab;

  const sVal = Math.sin(p);
  const cStride = Math.sin(p + Math.PI);

  state.smoothedTorsoLean = lerp(state.smoothedTorsoLean, (gait.lean * GAIT_PHYSICS.BODY_LEAN_MULTIPLIER) + (sVal * GAIT_PHYSICS.BODY_LEAN_OSCILLATION_AMPLITUDE * gait.intensity), alpha);
  const easedSway = Math.pow(gait.hip_sway / hipSwayMaxLimit, 2) * hipSwayMaxLimit;
  const swayMag = GAIT_PHYSICS.HIP_SWAY_BASE_MAG_MOD * easedSway * gait.intensity;
  state.smoothedBodySwayX = lerp(state.smoothedBodySwayX, sVal * swayMag, alpha);
  state.smoothedWaistSway = lerp(state.smoothedWaistSway, -sVal * swayMag * GAIT_PHYSICS.WAIST_SWAY_RATIO, alpha);
  const twistF = Math.pow(gait.waist_twist / waistTwistMaxLimit, 3) * waistTwistMaxLimit;
  state.smoothedWaistTwist = lerp(state.smoothedWaistTwist, cStride * (GAIT_PHYSICS.WAIST_TWIST_BASE + gait.arm_swing * GAIT_PHYSICS.WAIST_TWIST_ARM_SWING_BONUS) * twistF * gait.intensity, alpha);

  const swingMag = (GAIT_PHYSICS.ARM_SWING_BASE + (gait.stride * GAIT_PHYSICS.ARM_SWING_STRIDE_FACTOR)) * (GAIT_PHYSICS.ARM_SWING_INTENSITY_BASE + gait.intensity * GAIT_PHYSICS.ARM_SWING_INTENSITY_FACTOR) * gait.arm_swing;

  // REFINED ELBOW SOLVER
  const intensity = gait.intensity;
  const elbowFlex = gait.elbowFlexibility;

  // Runners hold arms higher (flexed), walkers let them hang.
  const baseFlexion = lerp(GAIT_PHYSICS.ELBOW_WALK_BASE, GAIT_PHYSICS.ELBOW_RUN_BASE, clamp((intensity - 0.4) * 1.5, 0, 1)) * gait.elbow_bend;

  const swingPhaseL = p + Math.PI;
  const swingPhaseR = p;

  // Inertial Lag using phase shift
  const lagPhaseL = swingPhaseL - GAIT_PHYSICS.ELBOW_LAG_RADIANS;
  const lagPhaseR = swingPhaseR - GAIT_PHYSICS.ELBOW_LAG_RADIANS;

  const calculateRefinedElbow = (lagSin: number) => {
    // Flexion bonus when arm is pulling forward (lagSin > 0)
    const flexBonus = Math.max(0, lagSin) * (40 + intensity * 30);
    // Extension 'snap' when arm is pushing back (lagSin < 0)
    const extSnap = Math.min(0, lagSin) * (15 + intensity * 15);

    return baseFlexion + (flexBonus + extSnap) * elbowFlex;
  };

  let lElbowT = calculateRefinedElbow(Math.sin(lagPhaseL));
  let rElbowT = calculateRefinedElbow(Math.sin(lagPhaseR));

  // Sneak Modifier: Tucked elbows when gravity (crouch) is high
  const sneakFactor = clamp((gait.gravity - 0.7) * 3, 0, 1);
  lElbowT = lerp(lElbowT, GAIT_PHYSICS.ELBOW_SNEAK_BASE * gait.elbow_bend, sneakFactor);
  rElbowT = lerp(rElbowT, GAIT_PHYSICS.ELBOW_SNEAK_BASE * gait.elbow_bend, sneakFactor);

  lElbowT = clamp(lElbowT, gait.elbowMinBend, gait.elbowMaxBend);
  rElbowT = clamp(rElbowT, gait.elbowMinBend, gait.elbowMaxBend);

  const armVelocityL = Math.cos(swingPhaseL);
  const armVelocityR = Math.cos(swingPhaseR);
  const wristDragL = armVelocityL * GAIT_PHYSICS.WRIST_DRAG_FACTOR * gait.arm_swing;
  const wristDragR = armVelocityR * GAIT_PHYSICS.WRIST_DRAG_FACTOR * gait.arm_swing;
  const runFlickFactor = clamp((gait.intensity - 0.8) * 5, 0, 1);
  const wristFlickL = Math.sin(swingPhaseL) * GAIT_PHYSICS.WRIST_FLICK_INTENSITY * runFlickFactor;
  const wristFlickR = Math.sin(swingPhaseR) * GAIT_PHYSICS.WRIST_FLICK_INTENSITY * runFlickFactor;
  const sneakWristL = -40 * sneakFactor;
  const sneakWristR = -40 * sneakFactor;

  const lLegResult = calculateLegAngles(sVal, gait, p, weightFactor, baseUnitH);
  const rLegResult = calculateLegAngles(cStride, gait, p + Math.PI, weightFactor, baseUnitH);
  let lLegFinal = lLegResult;
  let rLegFinal = rLegResult;
  shakeIntensity = Math.max(lLegResult.impactSignal, rLegResult.impactSignal);

  const isLPinned = activePins.includes(PartName.LAnkle);
  const isRPinned = activePins.includes(PartName.RAnkle);

  if (isLPinned || isRPinned) {
    let cX_base = isLPinned && isRPinned ? 0 : (isLPinned ? -pinnedSlideOffset / 4 : pinnedSlideOffset / 4);
    const tL = (props.l_upper_leg.h) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER * baseUnitH;
    const cL = (props.l_lower_leg.h) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER * baseUnitH;
    let ikHipPos = { x: state.smoothedBodySwayX + cX_base, y: suggestedYOffset };
    const getTAP = (): Vector2D => {
        return { x: 0, y: (MANNEQUIN_LOCAL_FLOOR_Y * baseUnitH) };
    };
    if (isLPinned) {
      const target = getTAP();
      const ik = solve2DJointIK(target, ikHipPos, tL, cL, 0);
      if (ik) { lLegFinal = { ...lLegFinal, hip: 90 - ik.angle1, knee: ik.angle2, foot: -90, toe: 0 }; tensions[PartName.LAnkle] = 0; }
      else { const angle = Math.atan2(target.y - ikHipPos.y, target.x - ikHipPos.x); lLegFinal = { ...lLegFinal, hip: 90 - (angle * 180 / Math.PI), knee: 0, foot: -90, toe: 0 }; tensions[PartName.LAnkle] = (Math.hypot(target.x - ikHipPos.x, target.y - ikHipPos.y) - (tL + cL)) / baseUnitH; }
    }
    if (isRPinned) {
      const target = getTAP();
      const ik = solve2DJointIK(target, ikHipPos, tL, cL, 0);
      if (ik) { rLegFinal = { ...rLegFinal, hip: 90 - ik.angle1, knee: ik.angle2, foot: -90, toe: 0 }; tensions[PartName.RAnkle] = 0; }
      else { const angle = Math.atan2(target.y - ikHipPos.y, target.x - ikHipPos.x); rLegFinal = { ...rLegFinal, hip: 90 - (angle * 180 / Math.PI), knee: 0, foot: -90, toe: 0 }; tensions[PartName.RAnkle] = (Math.hypot(target.x - ikHipPos.x, target.y - ikHipPos.y) - (tL + cL)) / baseUnitH; }
    }
    suggestedYOffset = ikHipPos.y; suggestedXOffset = ikHipPos.x;
  } else if (isIkEnabled) {
    const fY = MANNEQUIN_LOCAL_FLOOR_Y * baseUnitH;
    const lowestPointY = Math.min(calculateFootTipGlobalPosition(lLegResult, props, baseUnitH, false).y, calculateFootTipGlobalPosition(rLegResult, props, baseUnitH, true).y);
    suggestedYOffset = (lowestPointY + suggestedYOffset > fY - 5) ? fY - (lowestPointY + suggestedYOffset) : suggestedYOffset;
    const arcB = Math.min(-Math.sin(((p % (2 * Math.PI)) - Math.PI) / Math.PI * Math.PI) * GAIT_PHYSICS.VERTICALITY_BOB_AMPLITUDE * gait.verticality * gait.intensity * (1 - gait.gravity * GAIT_PHYSICS.VERTICALITY_GRAVITY_DAMPENING), -Math.sin(((p + Math.PI % (2 * Math.PI)) - Math.PI) / Math.PI * Math.PI) * GAIT_PHYSICS.VERTICALITY_BOB_AMPLITUDE * gait.verticality * gait.intensity * (1 - gait.gravity * GAIT_PHYSICS.VERTICALITY_GRAVITY_DAMPENING));
    suggestedYOffset += arcB;
    suggestedXOffset = state.smoothedBodySwayX;
    const ikAdjust = (leg: any, isR: boolean, ph: number, curY: number) => {
      const prog = ((ph % (2 * Math.PI)) - Math.PI) / Math.PI;
      const str = Math.max(0, prog < 0.15 ? easeInOutQuint(prog / 0.15) : (prog > 0.85 ? easeInOutQuint((1.0 - prog) / 0.15) : 1.0));
      const ftp = calculateFootTipGlobalPosition(leg, props, baseUnitH, isR);
      const errY = fY - (ftp.y + curY); 
      return Math.abs(errY) < 80 ? leg.knee + (errY > 0 ? errY * 0.2 * str : 0) + gait.gravity * GAIT_PHYSICS.IK_KNEE_GRAVITY_BONUS : leg.knee;
    };
    lLegFinal.knee = ikAdjust(lLegResult, false, p, suggestedYOffset);
    rLegFinal.knee = ikAdjust(rLegResult, true, p + Math.PI, suggestedYOffset);
  }

  state.smoothedLKnee = lerp(state.smoothedLKnee, lLegFinal.knee, alpha);
  state.smoothedRKnee = lerp(state.smoothedRKnee, rLegFinal.knee, alpha);
  state.smoothedLElbow = lerp(state.smoothedLElbow, lElbowT, alpha);
  state.smoothedRElbow = lerp(state.smoothedRElbow, rElbowT, alpha);
  state.smoothedLWrist = lerp(state.smoothedLWrist, wristDragL + wristFlickL + sneakWristL, alpha);
  state.smoothedRWrist = lerp(state.smoothedRWrist, wristDragR + wristFlickR + sneakWristR, alpha);

  const tTwist = -state.smoothedWaistTwist * (GAIT_PHYSICS.TORSO_COUNTER_TWIST_BASE + gait.torso_swivel * GAIT_PHYSICS.TORSO_COUNTER_TWIST_SWIVEL_RANGE);
  const finalTorso = state.smoothedTorsoLean + tTwist + state.smoothedWaistSway;
  const finalCollar = (state.smoothedTorsoLean * -GAIT_PHYSICS.COLLAR_LEAN_COMPENSATION) + (state.smoothedWaistSway * -GAIT_PHYSICS.COLLAR_SWAY_COMPENSATION) + (tTwist * -0.5);
  const finalNeck = state.smoothedTorsoLean * -GAIT_PHYSICS.NECK_LEAN_COMPENSATION + gait.head_spin - (suggestedYOffset - state.prevYOffset) * gait.headVelocitySensitivity * 8.0;
  state.prevYOffset = suggestedYOffset;

  return {
    pose: {
      x_offset: suggestedXOffset, y_offset: suggestedYOffset, bodyRotation: state.smoothedBodyRotation, waist: state.smoothedWaistTwist, torso: finalTorso, collar: finalCollar, neck: finalNeck,
      [PartName.LShoulder]: cStride * swingMag - gait.arm_spread * GAIT_PHYSICS.ARM_SPREAD_ANGLE,
      [PartName.RShoulder]: sVal * swingMag + gait.arm_spread * GAIT_PHYSICS.ARM_SPREAD_ANGLE,
      [PartName.LElbow]: state.smoothedLElbow, [PartName.RElbow]: state.smoothedRElbow,
      [PartName.LWrist]: state.smoothedLWrist, [PartName.RWrist]: state.smoothedRWrist,
      [PartName.LThigh]: lLegFinal.hip, [PartName.LKnee]: state.smoothedLKnee, [PartName.LAnkle]: lLegFinal.foot, [PartName.LToe]: lLegFinal.toe,
      [PartName.RThigh]: rLegFinal.hip, [PartName.RKnee]: state.smoothedRKnee, [PartName.RAnkle]: rLegFinal.foot, [PartName.RToe]: rLegFinal.toe,
    },
    tensions, shakeIntensity, suggestedXOffset, suggestedYOffset
  };
};

