  { name: "Normal Walk", settings: { intensity: { base: 0.8, range: 0.1 }, frequency: { base: 1.2, range: 0.2 }, stride: { base: 0.7, range: 0.15 }, lean: { base: 0.1, range: 0.05 }, hip_sway: { base: 0.4, range: 0.1 }, waist_twist: { base: 0.3, range: 0.08 }, arm_swing: { base: 0.6, range: 0.1 }, elbow_bend: { base: 0.7, range: 0.15 }, arm_spread: { base: 0.1, range: 0.05 }, gravity: { base: 0.3, range: 0.05 }, verticality: { base: 0.1, range: 0.05 }, kick_up_force: { base: 0.4, range: 0.1 }, foot_roll: { base: 0.6, range: 0.1 }, hover_height: { base: 0.1, range: 0.05 }, toe_bend: { base: 0.8, range: 0.1 }, torso_swivel: { base: 0.3, range: 0.05 }, headVelocitySensitivity: { base: 0.2, range: 0.05 }, elbowFlexibility: { base: 0.5, range: 0.1 } } },
  { name: "Run", settings: { intensity: { base: 1.0, range: 0.15 }, frequency: { base: 1.8, range: 0.25 }, stride: { base: 1.0, range: 0.2 }, lean: { base: 0.2, range: 0.08 }, arm_swing: { base: 0.9, range: 0.1 }, elbow_bend: { base: 0.9, range: 0.1 }, arm_spread: { base: 0.2, range: 0.08 }, gravity: { base: 0.5, range: 0.1 }, verticality: { base: 0.4, range: 0.1 }, kick_up_force: { base: 0.8, range: 0.1 }, foot_roll: { base: 0.8, range: 0.1 }, hover_height: { base: 0.4, range: 0.1 }, heavyStomp: { base: 0.1, range: 0.05 }, headVelocitySensitivity: { base: 0.5, range: 0.1 }, elbowFlexibility: { base: 0.7, range: 0.1 } } },
  { name: "Sneak", settings: { intensity: { base: 0.4, range: 0.08 }, frequency: { base: 0.8, range: 0.15 }, stride: { base: 0.4, range: 0.1 }, lean: { base: 0.3, range: 0.05 }, elbow_bend: { base: 1.2, range: 0.1 }, arm_spread: { base: 0.3, range: 0.05 }, gravity: { base: 0.9, range: 0.05 }, verticality: { base: 0.05, range: 0.02 }, foot_roll: { base: 0.9, range: 0.05 }, hover_height: { base: 0.5, range: 0.1 }, heavyStomp: { base: 0.5, range: 0.1 }, headVelocitySensitivity: { base: 0.1, range: 0.03 } } },
];

