                      <div className="flex items-center gap-1">
                        <span className="text-[8px] font-bold text-mono-light uppercase">{part.label}</span>
                        <button onClick={() => triggerTextureUpload(part.propKey as keyof WalkingEngineProportions)} className={`text-[6px] px-1 border uppercase font-bold ${hasTexture ? 'bg-accent-red text-white' : 'bg-paper/10 border-ridge'}`}>IMG</button>
                        {hasTexture && (
                            <div className="flex gap-0.5">
                                <button onClick={() => handleToggleMaskSetting(part.propKey as keyof WalkingEngineProportions, 'eliminateBackground')} className={`text-[5px] w-3 h-3 flex items-center justify-center border ${mask.eliminateBackground ? 'bg-selection text-paper' : 'bg-paper/10'}`}>E</button>
                                <button onClick={() => handleToggleMaskSetting(part.propKey as keyof WalkingEngineProportions, 'isPhysical')} className={`text-[5px] w-3 h-3 flex items-center justify-center border ${mask.isPhysical ? 'bg-selection text-paper' : 'bg-paper/10'}`}>P</button>
                            </div>
                        )}
                      </div>
                      <div className="flex gap-0.5">
                        <button onClick={() => handleToggleJointMode(part.key as keyof WalkingEnginePivotOffsets, 'isBend')} className={`text-[6px] w-4 h-3 flex items-center justify-center border ${isBend ? 'bg-ink text-paper' : 'bg-paper/10'}`}>B</button>
                        <button onClick={() => handleToggleJointMode(part.key as keyof WalkingEnginePivotOffsets, 'isStretch')} className={`text-[6px] w-4 h-3 flex items-center justify-center border ${isStretch ? 'bg-ink text-paper' : 'bg-paper/10'}`}>S</button>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 px-1">
                      <input type="range" min="-180" max="180" value={pivotOffsets[part.key as keyof WalkingEnginePivotOffsets] || 0} onChange={(e) => updatePivotOffset(part.key as keyof WalkingEnginePivotOffsets, e.target.value)} className="flex-1 accent-selection h-0.5" />
                    </div>
                  </div>
                );
              })}
            </div>
          </CollapsibleSection>
        </div>
      )}
      <div ref={viewportRef} className={`flex-1 relative flex items-center justify-center overflow-hidden ${isPanning ? 'cursor-grabbing' : 'cursor-crosshair'}`} onMouseDown={handleViewportMouseDown} onWheel={handleViewportWheel} onContextMenu={(e) => e.preventDefault()}>
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker rounded-full text-ink">{isConsoleVisible ? '✕' : '☰'}</button>
        <div className="absolute top-4 right-4 flex flex-col gap-2 z-50">
          <button onClick={() => setZoomIndex(prev => Math.min(UI.ZOOM_LEVELS.length - 1, prev + 1))} className="w-8 h-8 flex items-center justify-center bg-mono-darker/80 border border-ridge font-bold">+</button>
          <button onClick={handleResetViewport} className="w-8 h-8 flex items-center justify-center bg-mono-darker/80 border border-ridge text-[10px]">RST</button>
          <button onClick={() => setZoomIndex(prev => Math.max(0, prev - 1))} className="w-8 h-8 flex items-center justify-center bg-mono-darker/80 border border-ridge font-bold">-</button>
        </div>
        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full overflow-visible relative z-10" style={{ pointerEvents: isPanning ? 'none' : 'auto' }}>
          <g transform={`translate(${pose.x_offset + lotteJitter.x}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset + lotteJitter.y})`}>
             <Mannequin pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={props} showPivots={showPivots} baseUnitH={H} onAnchorMouseDown={handleAnchorMouseDown} draggingBoneKey={draggingBoneKey} isPaused={isPaused} customTextures={customTextures} maskSettings={maskSettings} activePins={activePins} tensions={tensions} jointModes={jointModes} lotteSettings={lotteSettings} />
          </g>
        </svg>
        <div className="absolute bottom-4 left-4 w-72 z-50 pointer-events-none opacity-80">
            <SystemLogger logs={systemLogs} isVisible={true} />
        </div>
      </div>
    </div>
  );
};

