/**
 * Fixed: Added randomization helper functions for presets to handle ParameterRange | number types.
 */
const generateRandomGait = (template: GaitPresetTemplate): WalkingEngineGait => {
  const newGait: any = { ...DEFAULT_GAIT_SETTINGS };
  for (const key in template.settings) {
    const param = (template.settings as any)[key];
    if (typeof param === 'number') {
      newGait[key] = param;
    } else if (param && typeof param.base === 'number') {
      newGait[key] = param.base + (Math.random() * 2 - 1) * (param.range || 0);
    }
  }
  return newGait as WalkingEngineGait;
};

const generateRandomIdle = (template: IdlePresetTemplate): IdleSettings => {
  const newIdle: any = { ...DEFAULT_IDLE_SETTINGS };
  for (const key in template.settings) {
    const param = (template.settings as any)[key];
    if (typeof param === 'number') {
      newIdle[key] = param;
    } else if (param && typeof param.base === 'number') {
      newIdle[key] = param.base + (Math.random() * 2 - 1) * (param.range || 0);
    } else if (key === 'idlePinnedFeet') {
      newIdle[key] = param;
    }
  }
  return newIdle as IdleSettings;
};

