  const [gait, setGait] = useState<WalkingEngineGait>(DEFAULT_GAIT_SETTINGS);
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [jointModes, setJointModes] = useState<JointModesState>({});
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [ghosting, setGhosting] = useState<GhostState>({ enabled: false, pinToManual: true, opacity: 0.15 });
  const [temporalPhase, setTemporalPhase] = useState<number | null>(null);
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-10), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    const p = (phase % (Math.PI * 2));
    const locPose = updateLocomotionPhysics(p, { ...locomotionStateRef.current }, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled);
    const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, activePins, idleSettings, isIkEnabled]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused && temporalPhase === null) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      const p = temporalPhase !== null ? (temporalPhase * Math.PI * 2) : (time * 0.005 * gait.frequency) % (Math.PI * 2);
      const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled);
      const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, elapsed);
      setPose(adjustedPose as WalkingEnginePose);
      setPoseDataString(JSON.stringify(adjustedPose, null, 2));
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, temporalPhase, targetFps]);

  const snapToPhase = (percent: number) => {
    setTemporalPhase(percent / 100);
    setIsPaused(true);
    logSystem(`SNAP: ${percent}%`);
  };

  const updatePivot = (key: keyof WalkingEnginePivotOffsets, val: number) => {
    setPivotOffsets(prev => ({ ...prev, [key]: val }));
  };

  const poseableParts = [
    { key: 'neck', label: 'Head' }, { key: 'collar', label: 'Collar' }, { key: 'torso', label: 'Torso' }, { key: 'waist', label: 'Waist' },
    { key: 'l_shoulder', label: 'L.Arm' }, { key: 'r_shoulder', label: 'R.Arm' }, { key: 'l_elbow', label: 'L.Elbow' }, { key: 'r_elbow', label: 'R.Elbow' },
    { key: 'l_hip', label: 'L.Thigh' }, { key: 'r_hip', label: 'R.Thigh' }, { key: 'l_knee', label: 'L.Knee' }, { key: 'r_knee', label: 'R.Knee' },
  ];

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <CollapsibleSection title="Gait System">
            <div className="grid grid-cols-2 gap-2 mb-2">
              <button onClick={() => setIsPaused(!isPaused)} className={`text-[9px] py-1 border ${isPaused ? 'bg-accent-red/20 border-accent-red' : 'border-ridge'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
              <button onClick={() => setTemporalPhase(null)} className="text-[9px] py-1 border border-ridge">LIVE</button>
            </div>
            {Object.entries({ Intensity: 'intensity', Frequency: 'frequency', Stride: 'stride' }).map(([label, key]) => (
              <div key={key} className="mb-2">
                <div className="flex justify-between text-[8px] uppercase"><span>{label}</span><span>{(gait as any)[key].toFixed(2)}</span></div>
                <input type="range" min="0" max="2" step="0.01" value={(gait as any)[key]} onChange={e => setGait(p => ({ ...p, [key]: parseFloat(e.target.value) }))} className="w-full h-1 accent-selection" />
              </div>
            ))}
          </CollapsibleSection>

          <CollapsibleSection title="Anatomical Manifest" defaultOpen={true}>
            <div className="flex flex-col gap-3">
              <div className="flex justify-between items-center text-[7px] font-bold uppercase text-mono-light">
                <span>Temporal Timeline</span>
                <button onClick={() => setGhosting(p => ({ ...p, enabled: !p.enabled }))} className={`px-2 py-0.5 border ${ghosting.enabled ? 'bg-selection text-paper' : 'border-ridge'}`}>Ghosting {ghosting.enabled ? 'ON' : 'OFF'}</button>
              </div>
              <div className="flex gap-1">
                {[0, 25, 50, 75, 100].map(p => (
                  <button key={p} onClick={() => snapToPhase(p)} className={`flex-1 text-[8px] py-1 border ${temporalPhase === p / 100 ? 'bg-selection text-paper border-selection' : 'border-ridge bg-mono-dark'}`}>{p}%</button>
                ))}
              </div>
              <div className="border-t border-ridge pt-2">
                <span className="text-[7px] font-bold text-mono-light uppercase">Kinetic Posing</span>
                <div className="flex flex-col gap-1 mt-1 max-h-64 overflow-y-auto custom-scrollbar pr-1">
                  {poseableParts.map(part => (
                    <div key={part.key} className="py-1 border-b border-ridge/30">
                      <div className="flex justify-between text-[7px] uppercase mb-1"><span>{part.label}</span><span>{pivotOffsets[part.key as keyof WalkingEnginePivotOffsets]}°</span></div>
                      <input type="range" min="-180" max="180" value={pivotOffsets[part.key as keyof WalkingEnginePivotOffsets]} onChange={e => updatePivot(part.key as keyof WalkingEnginePivotOffsets, parseInt(e.target.value))} className="w-full h-1 accent-selection" />
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </CollapsibleSection>

          <SystemLogger logs={systemLogs} isVisible={true} />
        </div>
      )}

      <div className="flex-1 relative overflow-hidden bg-white">
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker rounded-full text-ink">{isConsoleVisible ? '✕' : '☰'}</button>
        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full relative z-10">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={DEFAULT_PROPORTIONS} 
              showPivots={true} baseUnitH={H} onAnchorMouseDown={(k) => setActivePins(p => p.includes(k) ? p.filter(x => x !== k) : [...p, k])} 
              draggingBoneKey={null} isPaused={isPaused} activePins={activePins} tensions={{}} jointModes={{}} lotteSettings={DEFAULT_LOTTE_SETTINGS}
              ghosts={ghosting.enabled ? [
                { phase: ((temporalPhase || 0) - 0.25 + Math.PI*2) % (Math.PI*2), color: 'fill-green-200', opacity: 0.1 },
                { phase: ((temporalPhase || 0) + 0.25) % (Math.PI*2), color: 'fill-purple-200', opacity: 0.1 }
              ] : []}
              ghostDataGenerator={generatePoseAtPhase}
            />
          </g>
        </svg>
      </div>
    </div>
  );
};

