const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);
  const [poseDataString, setPoseDataString] = useState('');
  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [bodyRotation, setBodyRotation] = useState(0);
  const [gait, setGait] = useState<WalkingEngineGait>(DEFAULT_GAIT_SETTINGS);
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [jointModes, setJointModes] = useState<JointModesState>({});
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [ghosting, setGhosting] = useState<GhostState>({ enabled: false, pinToManual: true, opacity: 0.15 });
  const [temporalPhase, setTemporalPhase] = useState<number | null>(null);
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-10), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    // Phase is expected in 0..1 (stride_phase)
    const p = (phase * Math.PI * 2);
    const locPose = updateLocomotionPhysics(p, { ...INITIAL_LOCOMOTION_STATE }, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled);
    const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, activePins, idleSettings, isIkEnabled]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused && temporalPhase === null) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      const p = temporalPhase !== null ? (temporalPhase * Math.PI * 2) : (time * 0.005 * gait.frequency) % (Math.PI * 2);
      const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled);
      const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, elapsed);

      setPose(adjustedPose as WalkingEnginePose);
      setPoseDataString(JSON.stringify(adjustedPose, (k, v) => typeof v === 'number' ? Math.round(v * 10) / 10 : v, 2));
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, temporalPhase, targetFps]);

  const snapToPhase = (percent: number) => {
    setTemporalPhase(percent / 100);
    setIsPaused(true);
    logSystem(`SNAP: ${percent}%`);
  };

