  const [showPivots, setShowPivots] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);
  const [poseDataString, setPoseDataString] = useState('');
  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [bodyRotation, setBodyRotation] = useState(0);
  const [gait, setGait] = useState<WalkingEngineGait>(DEFAULT_GAIT_SETTINGS);
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [ghosting, setGhosting] = useState<GhostState>({ enabled: false, pinToManual: true, opacity: 0.15 });
  const [temporalPhase, setTemporalPhase] = useState<number | null>(null);
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-10), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    const p = (phase * Math.PI * 2);
    const locWeight = engineMode === 'locomotion' ? 1.0 : 0.0;
    const locPose = updateLocomotionPhysics(p, { ...INITIAL_LOCOMOTION_STATE }, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled);
    const idlePose = updateIdlePhysics(0, 16, idleSettings, locWeight);

    const blendedPose: Partial<WalkingEnginePose> = {};
    const allPoseKeys = new Set([...Object.keys(locPose), ...Object.keys(idlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;
    allPoseKeys.forEach(key => {
      const lVal = (locPose as any)[key] ?? 0;
      const iVal = (idlePose as any)[key] ?? 0;
      (blendedPose as any)[key] = lerp(iVal, lVal, locWeight);
    });

    const { adjustedPose } = applyFootGrounding(blendedPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', locWeight, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, activePins, idleSettings, isIkEnabled, engineMode]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused && temporalPhase === null) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      const p = temporalPhase !== null ? (temporalPhase * Math.PI * 2) : (time * 0.005 * gait.frequency) % (Math.PI * 2);
      const locWeight = engineMode === 'locomotion' ? 1.0 : 0.0;

      const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled);
      const idlePose = updateIdlePhysics(time, elapsed, idleSettings, locWeight);

      const blendedPose: Partial<WalkingEnginePose> = {};
      const allPoseKeys = new Set([...Object.keys(locPose), ...Object.keys(idlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;
      allPoseKeys.forEach(key => {
        const lVal = (locPose as any)[key] ?? 0;
        const iVal = (idlePose as any)[key] ?? 0;
        if (key === 'x_offset') blendedPose.x_offset = lerp(iVal, (locPose as any).x_offset, locWeight);
        else if (key === 'y_offset') blendedPose.y_offset = lerp(iVal, (locPose as any).y_offset, locWeight);
        else (blendedPose as any)[key] = lerp(iVal, lVal, locWeight);
      });

      const { adjustedPose } = applyFootGrounding(blendedPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', locWeight, elapsed);

      setPose(adjustedPose as WalkingEnginePose);
      setPoseDataString(JSON.stringify(adjustedPose, (k, v) => typeof v === 'number' ? Math.round(v * 10) / 10 : v, 2));
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, temporalPhase, targetFps, engineMode]);

  const snapToPhase = (percent: number) => {
    setTemporalPhase(percent / 100);
    setIsPaused(true);
    logSystem(`SNAP: ${percent}%`);
  };

  const updatePivot = (key: keyof WalkingEnginePivotOffsets, val: number) => {
    setPivotOffsets(prev => ({ ...prev, [key]: val }));
  };

  const poseableParts = [
    { key: 'neck', label: 'Head' }, { key: 'collar', label: 'Collar' }, { key: 'torso', label: 'Torso' }, { key: 'waist', label: 'Waist' },
    { key: 'l_shoulder', label: 'L.Arm' }, { key: 'r_shoulder', label: 'R.Arm' }, { key: 'l_elbow', label: 'L.Elbow' }, { key: 'r_elbow', label: 'R.Elbow' },
    { key: 'l_hip', label: 'L.Thigh' }, { key: 'r_hip', label: 'R.Thigh' }, { key: 'l_knee', label: 'L.Knee' }, { key: 'r_knee', label: 'R.Knee' },
    { key: 'l_foot', label: 'L.Foot' }, { key: 'r_foot', label: 'R.Foot' },
  ];

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <CollapsibleSection title="Gait Control">
            <div className="flex gap-2 mb-2">
              <button onClick={() => setEngineMode('locomotion')} className={`flex-1 text-[9px] py-1 border transition-all ${engineMode === 'locomotion' ? 'bg-selection text-paper' : 'border-ridge'}`}>WALK</button>
              <button onClick={() => setEngineMode('idle')} className={`flex-1 text-[9px] py-1 border transition-all ${engineMode === 'idle' ? 'bg-selection text-paper' : 'border-ridge'}`}>IDLE</button>
            </div>
            <div className="grid grid-cols-2 gap-2 mb-2">
              <button onClick={() => setIsPaused(!isPaused)} className={`text-[9px] py-1 border transition-all ${isPaused ? 'bg-accent-red/20 border-accent-red' : 'border-ridge'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
              <button onClick={() => setTemporalPhase(null)} className={`text-[9px] py-1 border transition-all ${temporalPhase === null ? 'bg-selection text-paper border-selection' : 'border-ridge'}`}>LIVE</button>
            </div>
            {Object.entries({ Intensity: 'intensity', Frequency: 'frequency', Stride: 'stride' }).map(([label, key]) => (
              <div key={key} className="mb-2">
                <div className="flex justify-between text-[8px] uppercase"><span>{label}</span><span>{(gait as any)[key].toFixed(2)}</span></div>
                <input type="range" min="0" max="2" step="0.01" value={(gait as any)[key]} onChange={e => setGait(p => ({ ...p, [key]: parseFloat(e.target.value) }))} className="w-full h-1 accent-selection" />
              </div>
            ))}
          </CollapsibleSection>

          <CollapsibleSection title="Anatomical Manifest" defaultOpen={true}>
            <div className="flex flex-col gap-3">
              <div className="flex justify-between items-center text-[7px] font-bold uppercase text-mono-light">
                <span>Temporal Timeline</span>
                <button onClick={() => setGhosting(p => ({ ...p, enabled: !p.enabled }))} className={`px-2 py-0.5 border ${ghosting.enabled ? 'bg-selection text-paper' : 'border-ridge'}`}>Ghosting {ghosting.enabled ? 'ON' : 'OFF'}</button>
              </div>
              <div className="flex gap-1">
                {[0, 25, 50, 75, 100].map(p => (
                  <button key={p} onClick={() => snapToPhase(p)} className={`flex-1 text-[8px] py-1 border transition-all ${temporalPhase === p / 100 ? 'bg-selection text-paper border-selection' : 'border-ridge bg-mono-dark'}`}>{p}%</button>
                ))}
              </div>
              <div className="border-t border-ridge pt-2">
                <span className="text-[7px] font-bold text-mono-light uppercase">Kinetic Posing</span>
                <div className="flex flex-col gap-1 mt-1 max-h-80 overflow-y-auto custom-scrollbar pr-1">
                  {poseableParts.map(part => (
                    <div key={part.key} className="py-1 border-b border-ridge/30">
                      <div className="flex justify-between text-[7px] uppercase mb-1"><span>{part.label}</span><span className="text-selection">{pivotOffsets[part.key as keyof WalkingEnginePivotOffsets]}°</span></div>
                      <input type="range" min="-180" max="180" value={pivotOffsets[part.key as keyof WalkingEnginePivotOffsets]} onChange={e => updatePivot(part.key as keyof WalkingEnginePivotOffsets, parseInt(e.target.value))} className="w-full h-1 accent-selection" />
                    </div>
                  ))}
                  <button onClick={() => setPivotOffsets(DEFAULT_PIVOT_OFFSETS)} className="w-full text-[8px] py-2 mt-2 border border-ridge uppercase font-bold text-mono-mid hover:text-ink transition-colors">Reset Poses</button>
                </div>
              </div>
              <div className="border-t border-ridge pt-2">
                 <span className="text-[7px] font-bold text-mono-light uppercase">Procedural JSON</span>
                 <textarea value={poseDataString} readOnly spellCheck={false} className="w-full h-32 bg-mono-darker border border-ridge p-2 text-[9px] font-mono resize-none focus:outline-none opacity-60" />
              </div>
            </div>
          </CollapsibleSection>

          <div className="mt-auto">
            <SystemLogger logs={systemLogs} isVisible={true} />
          </div>
        </div>
      )}

      <div className="flex-1 relative overflow-hidden bg-white">
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker rounded-full text-ink transition-all">{isConsoleVisible ? '✕' : '☰'}</button>
        <div className="absolute top-4 right-4 flex flex-col gap-2 z-50">
          <button onClick={() => setZoomIndex(prev => Math.min(UI.ZOOM_LEVELS.length - 1, prev + 1))} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge font-bold hover:bg-mono-darker shadow-sm">+</button>
          <button onClick={() => {setZoomIndex(UI.DEFAULT_ZOOM_INDEX); setPanOffset({x:0,y:0})}} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge text-[10px] hover:bg-mono-darker shadow-sm">RST</button>
          <button onClick={() => setZoomIndex(prev => Math.max(0, prev - 1))} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge font-bold hover:bg-mono-darker shadow-sm">-</button>
        </div>
        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full relative z-10" onContextMenu={e => e.preventDefault()}>
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={DEFAULT_PROPORTIONS} 
              showPivots={showPivots} baseUnitH={H} onAnchorMouseDown={(k) => setActivePins(p => p.includes(k) ? p.filter(x => x !== k) : [...p, k])} 
              draggingBoneKey={null} isPaused={isPaused} activePins={activePins} tensions={{}} jointModes={{}} lotteSettings={DEFAULT_LOTTE_SETTINGS}
              ghosts={ghosting.enabled ? [
                { phase: ((temporalPhase || 0) - 0.2 + 1) % 1, color: 'fill-green-200', opacity: 0.1 },
                { phase: ((temporalPhase || 0) - 0.1 + 1) % 1, color: 'fill-green-400', opacity: 0.2 },
                { phase: ((temporalPhase || 0) + 0.1) % 1, color: 'fill-purple-400', opacity: 0.2 },
                { phase: ((temporalPhase || 0) + 0.2) % 1, color: 'fill-purple-200', opacity: 0.1 }
              ] : []}
              ghostDataGenerator={generatePoseAtPhase}
            />
          </g>
        </svg>
      </div>
    </div>
  );
};

