overhauling for abroader system # Comprehensive Procedural Animation Engine Architecture

Here's how to extend your system into a full-featured animation engine:

## 1. **Core Animation System Architecture**

```typescript
// types/animation.ts
export type AnimationClip = {
  id: string;
  name: string;
  duration: number;
  frameRate: number;
  keyframes: Keyframe[];
  metadata: {
    created: number;
    modified: number;
    tags: string[];
    description: string;
  };
};

export type Keyframe = {
  time: number;
  pose: WalkingEnginePose;
  gait: Partial<WalkingEngineGait>;
  easing: EasingType;
  metadata?: Record<string, any>;
};

export type EasingType = 'linear' | 'easeInOutQuint' | 'easeInQuad' | 'easeOutQuad' | 'easeInOutCubic' | 'custom';

export type AnimationState = {
  currentClip: AnimationClip | null;
  currentTime: number;
  isPlaying: boolean;
  speed: number;
  loop: boolean;
};

export type AnimationLayer = {
  id: string;
  name: string;
  clip: AnimationClip;
  weight: number;
  enabled: boolean;
  blendMode: 'override' | 'additive' | 'lerp';
};

export type AnimationSequence = {
  id: string;
  name: string;
  clips: { clipId: string; startTime: number; weight: number }[];
  duration: number;
};

export type GaitProfile = {
  id: string;
  name: string;
  gait: WalkingEngineGait;
  transitions: Record<string, { duration: number; easing: EasingType }>;
  tags: string[];
};
```

## 2. **Animation Engine Service**

```typescript
// utils/animationEngine.ts
import { 
  AnimationClip, Keyframe, AnimationState, AnimationLayer, 
  EasingType, GaitProfile, AnimationSequence 
} from '../types/animation';
import { WalkingEnginePose, WalkingEngineGait } from '../types';
import { lerp, easeInOutQuint } from './kinematics';

export class AnimationEngine {
  private clips: Map<string, AnimationClip> = new Map();
  private gaitProfiles: Map<string, GaitProfile> = new Map();
  private sequences: Map<string, AnimationSequence> = new Map();
  private layers: AnimationLayer[] = [];
  private state: AnimationState = {
    currentClip: null,
    currentTime: 0,
    isPlaying: false,
    speed: 1.0,
    loop: true,
  };

  /**
   * Register a new animation clip
   */
  addClip(clip: AnimationClip): void {
    this.clips.set(clip.id, clip);
  }

  /**
   * Load animation from data (JSON, binary, etc.)
   */
  loadClipFromData(data: any, format: 'json' | 'binary' = 'json'): AnimationClip {
    if (format === 'json') {
      return data as AnimationClip;
    }
    // Implement binary deserialization if needed
    throw new Error('Binary format not yet implemented');
  }

  /**
   * Interpolate between keyframes
   */
  getFrameAtTime(clip: AnimationClip, time: number): WalkingEnginePose {
    const clampedTime = clip.duration > 0 ? time % clip.duration : 0;
    const keyframes = clip.keyframes.sort((a, b) => a.time - b.time);

    if (keyframes.length === 0) return {} as WalkingEnginePose;
    if (keyframes.length === 1) return keyframes[0].pose;

    let prevKf = keyframes[0];
    let nextKf = keyframes[keyframes.length - 1];

    for (let i = 0; i < keyframes.length - 1; i++) {
      if (keyframes[i].time <= clampedTime && keyframes[i + 1].time > clampedTime) {
        prevKf = keyframes[i];
        nextKf = keyframes[i + 1];
        break;
      }
    }

    const duration = nextKf.time - prevKf.time;
    if (duration === 0) return prevKf.pose;

    const t = (clampedTime - prevKf.time) / duration;
    const easedT = this.applyEasing(t, nextKf.easing);

    return this.blendPoses(prevKf.pose, nextKf.pose, easedT);
  }

  /**
   * Blend multiple poses from different layers
   */
  blendLayers(pose: WalkingEnginePose, time: number): WalkingEnginePose {
    let result = pose;

    for (const layer of this.layers.filter(l => l.enabled)) {
      const layerPose = this.getFrameAtTime(layer.clip, time);
      result = this.blendPosesByMode(result, layerPose, layer.weight, layer.blendMode);
    }

    return result;
  }

  /**
   * Animate between two gait profiles
   */
  transitionGait(
    fromProfile: GaitProfile,
    toProfile: GaitProfile,
    transitionTime: number,
    elapsedTime: number
  ): WalkingEngineGait {
    const t = Math.min(elapsedTime / transitionTime, 1);
    const easing = fromProfile.transitions[toProfile.id]?.easing || 'easeInOutQuint';
    const easedT = this.applyEasing(t, easing);

    const result: WalkingEngineGait = {} as WalkingEngineGait;
    const keys = Object.keys(fromProfile.gait) as (keyof WalkingEngineGait)[];

    keys.forEach(key => {
      const from = fromProfile.gait[key];
      const to = toProfile.gait[key];
      result[key] = lerp(from, to, easedT);
    });

    return result;
  }

  /**
   * Update animation state
   */
  update(deltaTime: number): void {
    if (!this.state.isPlaying || !this.state.currentClip) return;

    this.state.currentTime += deltaTime * this.state.speed;

    if (this.state.currentTime >= this.state.currentClip.duration) {
      if (this.state.loop) {
        this.state.currentTime = this.state.currentTime % this.state.currentClip.duration;
      } else {
        this.state.isPlaying = false;
        this.state.currentTime = this.state.currentClip.duration;
      }
    }
  }

  private blendPoses(
    pose1: WalkingEnginePose,
    pose2: WalkingEnginePose,
    t: number
  ): WalkingEnginePose {
    const result: any = {};
    const keys = new Set([
      ...Object.keys(pose1),
      ...Object.keys(pose2),
    ]) as Set<keyof WalkingEnginePose>;

    keys.forEach(key => {
      const v1 = (pose1 as any)[key] ?? 0;
      const v2 = (pose2 as any)[key] ?? 0;
      result[key] = lerp(v1, v2, t);
    });

    return result as WalkingEnginePose;
  }

  private blendPosesByMode(
    base: WalkingEnginePose,
    layer: WalkingEnginePose,
    weight: number,
    mode: 'override' | 'additive' | 'lerp'
  ): WalkingEnginePose {
    const result: any = { ...base };
    const keys = Object.keys(layer) as (keyof WalkingEnginePose)[];

    keys.forEach(key => {
      const baseVal = (result[key] ?? 0) as number;
      const layerVal = (layer[key] ?? 0) as number;

      switch (mode) {
        case 'override':
          result[key] = lerp(baseVal, layerVal, weight);
          break;
        case 'additive':
          result[key] = baseVal + layerVal * weight;
          break;
        case 'lerp':
          result[key] = lerp(baseVal, layerVal, weight);
          break;
      }
    });

    return result as WalkingEnginePose;
  }

  private applyEasing(t: number, easing: EasingType): number {
    switch (easing) {
      case 'linear':
        return t;
      case 'easeInOutQuint':
        return easeInOutQuint(t);
      case 'easeInQuad':
        return t * t;
      case 'easeOutQuad':
        return 1 - (1 - t) * (1 - t);
      case 'easeInOutCubic':
        return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
      default:
        return t;
    }
  }

  // Accessors
  getClip(id: string) { return this.clips.get(id); }
  getAllClips() { return Array.from(this.clips.values()); }
  getState() { return this.state; }
  setState(newState: Partial<AnimationState>) {
    this.state = { ...this.state, ...newState };
  }
  addLayer(layer: AnimationLayer) { this.layers.push(layer); }
  removeLayer(id: string) { this.layers = this.layers.filter(l => l.id !== id); }
  updateLayer(id: string, updates: Partial<AnimationLayer>) {
    const idx = this.layers.findIndex(l => l.id === id);
    if (idx >= 0) this.layers[idx] = { ...this.layers[idx], ...updates };
  }
}
```

## 3. **Animation Library Manager**

```typescript
// utils/animationLibrary.ts
import { AnimationClip, GaitProfile } from '../types/animation';
import JSZip from 'jszip';
import saveAs from 'file-saver';

export class AnimationLibrary {
  private indexDb: IDBDatabase | null = null;
  private storeName = 'animations';

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const req = indexedDB.open('BitruviusAnimationDB', 1);
      req.onupgradeneeded = () => {
        req.result.createObjectStore(this.storeName, { keyPath: 'id' });
      };
      req.onsuccess = () => {
        this.indexDb = req.result;
        resolve();
      };
      req.onerror = () => reject(req.error);
    });
  }

  async saveClip(clip: AnimationClip): Promise<void> {
    if (!this.indexDb) throw new Error('Library not initialized');
    return new Promise((resolve, reject) => {
      const tx = this.indexDb!.transaction([this.storeName], 'readwrite');
      const store = tx.objectStore(this.storeName);
      const req = store.put(clip);
      req.onsuccess = () => resolve();
      req.onerror = () => reject(req.error);
    });
  }

  async loadClip(id: string): Promise<AnimationClip | undefined> {
    if (!this.indexDb) throw new Error('Library not initialized');
    return new Promise((resolve, reject) => {
      const tx = this.indexDb!.transaction([this.storeName], 'readonly');
      const store = tx.objectStore(this.storeName);
      const req = store.get(id);
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });
  }

  async getAllClips(): Promise<AnimationClip[]> {
    if (!this.indexDb) throw new Error('Library not initialized');
    return new Promise((resolve, reject) => {
      const tx = this.indexDb!.transaction([this.storeName], 'readonly');
      const store = tx.objectStore(this.storeName);
      const req = store.getAll();
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });
  }

  async deleteClip(id: string): Promise<void> {
    if (!this.indexDb) throw new Error('Library not initialized');
    return new Promise((resolve, reject) => {
      const tx = this.indexDb!.transaction([this.storeName], 'readwrite');
      const store = tx.objectStore(this.storeName);
      const req = store.delete(id);
      req.onsuccess = () => resolve();
      req.onerror = () => reject(req.error);
    });
  }

  /**
   * Export animations as ZIP archive
   */
  async exportLibrary(clipIds: string[], filename: string = 'animations.zip'): Promise<void> {
    const zip = new JSZip();
    const manifest: any = { version: '1.0', clips: [] };

    for (const id of clipIds) {
      const clip = await this.loadClip(id);
      if (clip) {
        zip.file(`clips/${clip.id}.json`, JSON.stringify(clip, null, 2));
        manifest.clips.push({ id: clip.id, name: clip.name });
      }
    }

    zip.file('manifest.json', JSON.stringify(manifest, null, 2));
    const blob = await zip.generateAsync({ type: 'blob' });
    saveAs(blob, filename);
  }

  /**
   * Import animations from ZIP archive
   */
  async importLibrary(file: File): Promise<AnimationClip[]> {
    const zip = new JSZip();
    await zip.loadAsync(file);

    const manifestStr = await zip.file('manifest.json')?.async('string') || '{}';
    const manifest = JSON.parse(manifestStr);
    const imported: AnimationClip[] = [];

    for (const clipRef of manifest.clips || []) {
      const clipStr = await zip.file(`clips/${clipRef.id}.json`)?.async('string');
      if (clipStr) {
        const clip = JSON.parse(clipStr) as AnimationClip;
        await this.saveClip(clip);
        imported.push(clip);
      }
    }

    return imported;
  }
}
```

## 4. **Enhanced React Component with Timeline Editor**

```typescript
// components/AnimationTimeline.tsx
import React, { useState, useRef, useEffect } from 'react';
import { AnimationClip, Keyframe } from '../types/animation';
import { WalkingEnginePose, WalkingEngineGait } from '../types';

interface AnimationTimelineProps {
  clip: AnimationClip | null;
  currentTime: number;
  isPlaying: boolean;
  onTimeChange: (time: number) => void;
  onAddKeyframe: (time: number, pose: WalkingEnginePose, gait: Partial<WalkingEngineGait>) => void;
  onDeleteKeyframe: (index: number) => void;
}

export const AnimationTimeline: React.FC<AnimationTimelineProps> = ({
  clip,
  currentTime,
  isPlaying,
  onTimeChange,
  onAddKeyframe,
  onDeleteKeyframe,
}) => {
  const timelineRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [zoomLevel, setZoomLevel] = useState(1);

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!clip || !timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const percent = (e.clientX - rect.left) / rect.width;
    onTimeChange(percent * clip.duration);
  };

  const handleKeyframeClick = (e: React.MouseEvent<HTMLDivElement>, time: number) => {
    e.stopPropagation();
    onTimeChange(time);
  };

  if (!clip) return <div className="text-mono-light text-sm p-4">No animation loaded</div>;

  const pixelsPerSecond = 100 * zoomLevel;
  const totalWidth = (clip.duration * pixelsPerSecond);

  return (
    <div className="flex flex-col gap-2 p-4 bg-mono-darker/50 rounded">
      <div className="flex justify-between items-center mb-2">
        <h3 className="text-sm font-bold text-ink">{clip.name}</h3>
        <div className="flex gap-2">
          <input
            type="range"
            min="0.5"
            max="3"
            step="0.5"
            value={zoomLevel}
            onChange={(e) => setZoomLevel(parseFloat(e.target.value))}
            className="w-24 h-1 accent-selection"
          />
          <span className="text-xs text-mono-light">{currentTime.toFixed(2)}s / {clip.duration.toFixed(2)}s</span>
        </div>
      </div>

      <div className="overflow-x-auto border border-ridge bg-mono-darker/20 rounded">
        <div
          ref={timelineRef}
          style={{ width: `${totalWidth}px`, minWidth: '100%' }}
          className="relative h-32 bg-gradient-to-b from-mono-darker/10 to-mono-darker/20 cursor-pointer"
          onClick={handleTimelineClick}
        >
          {/* Grid lines */}
          {Array.from({ length: Math.ceil(clip.duration) }).map((_, i) => (
            <div
              key={i}
              style={{ left: `${i * pixelsPerSecond}px` }}
              className="absolute top-0 bottom-0 w-px bg-mono-light/20"
            >
              <span className="absolute top-1 left-1 text-xs text-mono-light">{i}s</span>
            </div>
          ))}

          {/* Keyframes */}
          {clip.keyframes.map((kf, idx) => (
            <div
              key={idx}
              style={{ left: `${(kf.time / clip.duration) * totalWidth}px` }}
              className="absolute top-1/2 w-4 h-8 -translate-x-1/2 -translate-y-1/2 cursor-pointer group"
              onClick={(e) => handleKeyframeClick(e, kf.time)}
            >
              <div className="w-4 h-4 bg-selection border border-paper rounded-full shadow-lg" />
              <div className="absolute top-full left-1/2 -translate-x-1/2 mt-1 hidden group-hover:block bg-mono-dark text-paper text-xs px-2 py-1 rounded whitespace-nowrap z-10">
                {kf.time.toFixed(2)}s
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onDeleteKeyframe(idx);
                  }}
                  className="ml-2 text-accent-red hover:text-accent-red/80"
                >
                  ✕
                </button>
              </div>
            </div>
          ))}

          {/* Playhead */}
          <div
            style={{ left: `${(currentTime / clip.duration) * totalWidth}px` }}
            className="absolute top-0 bottom-0 w-1 bg-accent-red/80 pointer-events-none"
          />
        </div>
      </div>
    </div>
  );
};
```

## 5. **Updated App with Animation Support**

```typescript
// App.tsx - Enhanced version
const App: React.FC = () => {
  // ... existing state ...
  const [animationEngine] = useState(() => new AnimationEngine());
  const [animationLibrary] = useState(() => new AnimationLibrary());
  const [currentClip, setCurrentClip] = useState<AnimationClip | null>(null);
  const [clips, setClips] = useState<AnimationClip[]>([]);

  useEffect(() => {
    animationLibrary.init().then(() => {
      animationLibrary.getAllClips().then(setClips);
    });
  }, []);

  const createClipFromCurrentState = () => {
    const now = Date.now();
    const clip: AnimationClip = {
      id: `clip_${now}`,
      name: `Animation_${new Date().toLocaleTimeString()}`,
      duration: 2, // 2 seconds default
      frameRate: 60,
      keyframes: [{
        time: 0,
        pose,
        gait: {},
        easing: 'easeInOutQuint',
      }],
      metadata: {
        created: now,
        modified: now,
        tags: [engineMode],
        description: 'Created from current state',
      },
    };

    animationLibrary.saveClip(clip);
    animationEngine.addClip(clip);
    setClips(p => [...p, clip]);
    setCurrentClip(clip);
    logSystem(`✓ Clip created: ${clip.name}`);
  };

  const addKeyframeToClip = () => {
    if (!currentClip) return;
    const updatedClip: AnimationClip = {
      ...currentClip,
      keyframes: [
        ...currentClip.keyframes,
        {
          time: animationEngine.getState().currentTime,
          pose,
          gait: {},
          easing: 'easeInOutQuint',
        },
      ].sort((a, b) => a.time - b.time),
      metadata: { ...currentClip.metadata, modified: Date.now() },
    };
    animationLibrary.saveClip(updatedClip);
    animationEngine.addClip(updatedClip);
    setCurrentClip(updatedClip);
  };

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      <div className="w-96 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
        {/* ... existing controls ... */}

        <CollapsibleSection title="Animation Library">
          <div className="flex flex-col gap-2 max-h-40 overflow-y-auto pr-1">
            {clips.map(clip => (
              <button
                key={clip.id}
                onClick={() => {
                  setCurrentClip(clip);
                  animationEngine.addClip(clip);
                  animationEngine.setState({ currentClip: clip, currentTime: 0, isPlaying: true });
                }}
                className={`text-left px-2 py-1 text-[8px] border transition-all truncate ${
                  currentClip?.id === clip.id
                    ? 'bg-selection text-paper border-selection'
                    : 'border-ridge hover:bg-mono-dark'
                }`}
                title={clip.name}
              >
                {clip.name}
              </button>
            ))}
          </div>
          <button
            onClick={createClipFromCurrentState}
            className="w-full text-[8px] py-1 mt-2 border border-ridge uppercase font-bold hover:bg-selection hover:text-paper transition-all"
          >
            + New Clip
          </button>
        </CollapsibleSection>

        <CollapsibleSection title="Timeline Editor" defaultOpen={false}>
          <AnimationTimeline
            clip={currentClip}
            currentTime={animationEngine.getState().currentTime}
            isPlaying={animationEngine.getState().isPlaying}
            onTimeChange={(time) => animationEngine.setState({ currentTime: time })}
            onAddKeyframe={() => addKeyframeToClip()}
            onDeleteKeyframe={(idx) => {
              if (!currentClip) return;
              const updated = {
                ...currentClip,
                keyframes: currentClip.keyframes.filter((_, i) => i !== idx),
              };
              animationLibrary.saveClip(updated);
              setCurrentClip(updated);
            }}
          />
        </CollapsibleSection>
      </div>
      {/* ... rest of UI ... */}
    </div>
  );
};
```

