const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);

  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle' | 'animation'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [bodyRotation, setBodyRotation] = useState(0);

  const [gait, setGait] = useState<WalkingEngineGait>(DEFAULT_GAIT_SETTINGS);
  const [gaitEnabled, setGaitEnabled] = useState<Record<keyof WalkingEngineGait, boolean>>(() => {
    const initial: any = {};
    Object.keys(DEFAULT_GAIT_SETTINGS).forEach(k => initial[k] = true);
    return initial;
  });

  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [ghosting, setGhosting] = useState<GhostState>({ enabled: false, pinToManual: true, opacity: 0.15 });
  const [temporalPhase, setTemporalPhase] = useState<number | null>(null);

  // Animation Engine State
  const [currentClip, setCurrentClip] = useState<AnimationClip | null>(null);
  const [animState, setAnimState] = useState<AnimationState>({ currentClip: null, currentTime: 0, isPlaying: false, speed: 1 });
  const [clips, setClips] = useState<AnimationClip[]>([]);

  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-10), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    const p = (phase * Math.PI * 2);
    const locPose = updateLocomotionPhysics(p, { ...INITIAL_LOCOMOTION_STATE }, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, 1.0, gaitEnabled);
    const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, gaitEnabled, activePins, idleSettings, isIkEnabled]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused && temporalPhase === null && !animState.isPlaying) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      let finalPose: WalkingEnginePose;

      if (engineMode === 'animation' && currentClip) {
        if (animState.isPlaying) {
          setAnimState(prev => {
            let nextTime = prev.currentTime + (elapsed / 1000) * prev.speed;
            if (nextTime > currentClip.duration) {
              if (currentClip.loop) nextTime = nextTime % currentClip.duration;
              else {
                nextTime = currentClip.duration;
                return { ...prev, isPlaying: false, currentTime: nextTime };
              }
            }
            return { ...prev, currentTime: nextTime };
          });
        }
        const animPose = AnimationEngine.getPoseAtTime(currentClip, animState.currentTime);
        finalPose = animPose || DEFAULT_RESTING_POSE;
      } else {
        const p = temporalPhase !== null ? (temporalPhase * Math.PI * 2) : (time * 0.005 * gait.frequency) % (Math.PI * 2);
        const locWeight = engineMode === 'locomotion' ? 1.0 : 0.0;
        const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, locWeight, gaitEnabled);
        const idlePose = updateIdlePhysics(time, elapsed, idleSettings, locWeight);

        const blendedPose: Partial<WalkingEnginePose> = {};
        const allPoseKeys = new Set([...Object.keys(locPose), ...Object.keys(idlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;
        allPoseKeys.forEach(key => {
          const lVal = (locPose as any)[key] ?? 0;
          const iVal = (idlePose as any)[key] ?? 0;
          (blendedPose as any)[key] = lerp(iVal, lVal, locWeight);
        });

        const { adjustedPose } = applyFootGrounding(blendedPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', locWeight, elapsed);
        finalPose = adjustedPose as WalkingEnginePose;
      }

      setPose(finalPose);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, gaitEnabled, activePins, idleSettings, isIkEnabled, temporalPhase, targetFps, engineMode, currentClip, animState]);

  const addKeyframe = () => {
    if (!currentClip) return;
    const newKf: Keyframe = { time: animState.currentTime, pose: { ...pose }, gait: { ...gait }, easing: 'easeInOutQuint' };
    const updated = { ...currentClip, keyframes: [...currentClip.keyframes, newKf].sort((a, b) => a.time - b.time) };
    setCurrentClip(updated);
    setClips(p => p.map(c => c.id === updated.id ? updated : c));
    logSystem(`Keyframe Added at ${animState.currentTime.toFixed(2)}s`);
  };

  const createNewClip = () => {
    const newClip: AnimationClip = { id: `clip-${Date.now()}`, name: `Anim ${clips.length + 1}`, duration: 5, keyframes: [], loop: true };
    setClips(p => [...p, newClip]);
    setCurrentClip(newClip);
    setEngineMode('animation');
    logSystem("Created New Animation Clip");
  };

  const toggleGaitFactor = (key: keyof WalkingEngineGait) => {
    setGaitEnabled(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const updatePivot = (key: keyof WalkingEnginePivotOffsets, val: number) => {
    setPivotOffsets(prev => ({ ...prev, [key]: val }));
  };

  const poseableParts = [
    { key: 'neck', label: 'Head' }, { key: 'collar', label: 'Collar' }, { key: 'torso', label: 'Torso' }, { key: 'waist', label: 'Waist' },
    { key: PartName.LShoulder, label: 'L.Arm' }, { key: PartName.RShoulder, label: 'R.Arm' }, { key: PartName.LElbow, label: 'L.Elbow' }, { key: PartName.RElbow, label: 'R.Elbow' },
    { key: PartName.LThigh, label: 'L.Thigh' }, { key: PartName.RThigh, label: 'R.Thigh' }, { key: PartName.LKnee, label: 'L.Knee' }, { key: PartName.RKnee, label: 'R.Knee' },
  ];

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <CollapsibleSection title="Engine Mode">
            <div className="flex flex-col gap-2">
              <div className="flex gap-1">
                <button onClick={() => setEngineMode('locomotion')} className={`flex-1 text-[9px] py-1 border transition-all ${engineMode === 'locomotion' ? 'bg-selection text-paper' : 'border-ridge'}`}>WALK</button>
                <button onClick={() => setEngineMode('idle')} className={`flex-1 text-[9px] py-1 border transition-all ${engineMode === 'idle' ? 'bg-selection text-paper' : 'border-ridge'}`}>IDLE</button>
                <button onClick={() => setEngineMode('animation')} className={`flex-1 text-[9px] py-1 border transition-all ${engineMode === 'animation' ? 'bg-selection text-paper' : 'border-ridge'}`}>ANIM</button>
              </div>
              {engineMode === 'animation' && (
                <div className="flex flex-col gap-1 border-t border-ridge pt-2">
                  <select 
                    className="w-full text-[9px] bg-mono-dark border border-ridge p-1"
                    onChange={(e) => setCurrentClip(clips.find(c => c.id === e.target.value) || null)}
                    value={currentClip?.id || ''}
                  >
                    <option value="">Select Animation...</option>
                    {clips.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                  <button onClick={createNewClip} className="text-[8px] py-1 border border-ridge bg-mono-dark hover:bg-selection hover:text-paper transition-all uppercase font-bold">+ New Clip</button>
                </div>
              )}
            </div>
          </CollapsibleSection>

          {engineMode === 'animation' && currentClip && (
            <CollapsibleSection title="Animation Editor">
              <div className="flex flex-col gap-2">
                <div className="flex gap-1">
                  <button onClick={() => setAnimState(p => ({...p, isPlaying: !p.isPlaying}))} className={`flex-1 text-[9px] py-1 border ${animState.isPlaying ? 'bg-accent-red/20 border-accent-red text-accent-red' : 'border-ridge'}`}>{animState.isPlaying ? 'PAUSE' : 'PLAY'}</button>
                  <button onClick={addKeyframe} className="flex-1 text-[9px] py-1 border border-ridge bg-mono-dark hover:bg-ridge">+ KEY</button>
                </div>
                <div className="flex items-center gap-2 text-[8px] uppercase">
                  <span>Duration</span>
                  <input type="number" step="0.1" value={currentClip.duration} onChange={(e) => {
