const App: React.FC = () => {
  const [library] = useState(() => new CharacterLibraryManager());
  const [characters, setCharacters] = useState<CharacterMorphology[]>([]);
  const [currentCharacter, setCurrentCharacter] = useState<CharacterMorphology | null>(null);
  const [charDescription, setCharDescription] = useState('');

  const [showPivots, setShowPivots] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);

  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle' | 'animation'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [bodyRotation, setBodyRotation] = useState(0);

  const [gait, setGait] = useState<WalkingEngineGait>(DEFAULT_GAIT_SETTINGS);
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [temporalPhase, setTemporalPhase] = useState<number | null>(null);

  const [currentClip, setCurrentClip] = useState<AnimationClip | null>(null);
  const [animState, setAnimState] = useState<AnimationState>({ currentClip: null, currentTime: 0, isPlaying: false, speed: 1 });
  const [clips, setClips] = useState<AnimationClip[]>([]);

  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    library.init().then(() => {
      library.getAllCharacters().then(setCharacters);
    });
  }, []);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-10), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  const generateCharacter = async () => {
    if (!charDescription.trim()) return;
    const char = CharacterGenerator.generateCharacter(charDescription);
    await library.saveCharacter(char);
    setCharacters(p => [...p, char]);
    setCurrentCharacter(char);
    setGait(GaitSynthesizer.synthesizeGait(char));
    setCharDescription('');
    logSystem(`Character Synthesized: ${char.name}`);
  };

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    const p = (phase * Math.PI * 2);
    const locPose = updateLocomotionPhysics(p, { ...INITIAL_LOCOMOTION_STATE }, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, 1.0);
    const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, activePins, idleSettings, isIkEnabled]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused && temporalPhase === null && !animState.isPlaying) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      let finalPose: WalkingEnginePose;

      if (engineMode === 'animation' && currentClip) {
        if (animState.isPlaying) {
          setAnimState(prev => {
            let nextTime = prev.currentTime + (elapsed / 1000) * prev.speed;
            if (nextTime > currentClip.duration) {
              if (currentClip.loop) nextTime = nextTime % currentClip.duration;
              else {
                nextTime = currentClip.duration;
                return { ...prev, isPlaying: false, currentTime: nextTime };
              }
            }
            return { ...prev, currentTime: nextTime };
          });
        }
        const animPose = AnimationEngine.getPoseAtTime(currentClip, animState.currentTime);
        finalPose = animPose || DEFAULT_RESTING_POSE;
      } else {
        const p = temporalPhase !== null ? (temporalPhase * Math.PI * 2) : (time * 0.005 * gait.frequency) % (Math.PI * 2);
        const locWeight = engineMode === 'locomotion' ? 1.0 : 0.0;
        const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, locWeight);
        const idlePose = updateIdlePhysics(time, elapsed, idleSettings, locWeight);

        const blendedPose: Partial<WalkingEnginePose> = {};
        const allKeys = new Set([...Object.keys(locPose), ...Object.keys(idlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;
        allKeys.forEach(key => {
          const lVal = (locPose as any)[key] ?? 0;
          const iVal = (idlePose as any)[key] ?? 0;
          (blendedPose as any)[key] = lerp(iVal, lVal, locWeight);
        });

        const { adjustedPose } = applyFootGrounding(blendedPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', locWeight, elapsed);
        finalPose = adjustedPose as WalkingEnginePose;
      }
      setPose(finalPose);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, temporalPhase, targetFps, engineMode, currentClip, animState]);

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <CollapsibleSection title="Character Factory">
            <div className="flex flex-col gap-2">
              <label className="text-[8px] font-bold uppercase text-mono-light">Description Prompt</label>
              <textarea 
                value={charDescription}
                onChange={(e) => setCharDescription(e.target.value)}
                placeholder="e.g. 'A nervous, tiny flyer'"
                className="w-full h-16 p-2 bg-mono-dark border border-ridge text-[9px] resize-none focus:outline-none focus:border-selection"
              />
              <button 
                onClick={generateCharacter}
                className="w-full py-1.5 bg-selection text-paper text-[9px] font-bold uppercase hover:opacity-90 transition-all"
              >
                Synthesize Character
              </button>
            </div>
          </CollapsibleSection>

          {currentCharacter && (
            <div className="p-3 bg-mono-dark/50 border border-ridge rounded text-[9px]">
              <div className="text-selection font-bold mb-1">{currentCharacter.name}</div>
              <div className="text-mono-light grid grid-cols-2 gap-x-2">
                <span>Stability: {(currentCharacter.gaitDNA.stability * 100).toFixed(0)}%</span>
                <span>Agility: {(currentCharacter.gaitDNA.agility * 100).toFixed(0)}%</span>
              </div>
            </div>
          )}

          <CollapsibleSection title="Character Library">
            <div className="flex flex-col gap-1 max-h-40 overflow-y-auto pr-1">
              {characters.map(char => (
                <button 
                  key={char.id}
                  onClick={() => { setCurrentCharacter(char); setGait(GaitSynthesizer.synthesizeGait(char)); }}
                  className={`text-left p-1 px-2 border rounded text-[8px] transition-all truncate ${currentCharacter?.id === char.id ? 'bg-selection text-paper border-selection' : 'border-ridge bg-paper/20 hover:bg-mono-dark'}`}
                >
                  {char.name}
                </button>
              ))}
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Engine Controls">
            <div className="flex gap-1 mb-2">
              <button onClick={() => setEngineMode('locomotion')} className={`flex-1 text-[9px] py-1 border ${engineMode === 'locomotion' ? 'bg-selection text-paper' : 'border-ridge'}`}>WALK</button>
              <button onClick={() => setEngineMode('idle')} className={`flex-1 text-[9px] py-1 border ${engineMode === 'idle' ? 'bg-selection text-paper' : 'border-ridge'}`}>IDLE</button>
              <button onClick={() => setEngineMode('animation')} className={`flex-1 text-[9px] py-1 border ${engineMode === 'animation' ? 'bg-selection text-paper' : 'border-ridge'}`}>ANIM</button>
            </div>
            <button onClick={() => setIsPaused(!isPaused)} className={`w-full text-[9px] py-1 border ${isPaused ? 'bg-accent-red/20 border-accent-red text-accent-red' : 'border-ridge'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
          </CollapsibleSection>

          <CollapsibleSection title="Kinetic Manifest" defaultOpen={false}>
            <div className="flex flex-col gap-3">
              <div className="flex gap-1">
                {[0, 25, 50, 75, 100].map(p => (
                  <button key={p} onClick={() => { setTemporalPhase(p / 100); setIsPaused(true); }} className={`flex-1 text-[8px] py-1 border ${temporalPhase === p / 100 ? 'bg-selection text-paper' : 'border-ridge bg-mono-dark'}`}>{p}%</button>
                ))}
              </div>
            </div>
          </CollapsibleSection>

          <div className="mt-auto">
            <SystemLogger logs={systemLogs} isVisible={true} />
          </div>
        </div>
      )}

      <div className="flex-1 relative overflow-hidden bg-white">
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker rounded-full text-ink transition-all">{isConsoleVisible ? '✕' : '☰'}</button>
        <div className="absolute top-4 right-4 flex flex-col gap-2 z-50">
          <button onClick={() => setZoomIndex(prev => Math.min(UI.ZOOM_LEVELS.length - 1, prev + 1))} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge font-bold shadow-sm">+</button>
          <button onClick={() => {setZoomIndex(UI.DEFAULT_ZOOM_INDEX); setPanOffset({x:0,y:0})}} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge text-[10px] shadow-sm">RST</button>
          <button onClick={() => setZoomIndex(prev => Math.max(0, prev - 1))} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge font-bold shadow-sm">-</button>
        </div>
        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full relative z-10">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={DEFAULT_PROPORTIONS} 
              showPivots={showPivots} baseUnitH={H * (currentCharacter?.anatomy.bodyLength || 1)} 
              onAnchorMouseDown={(k) => setActivePins(p => p.includes(k) ? p.filter(x => x !== k) : [...p, k])} 
              draggingBoneKey={null} isPaused={isPaused} activePins={activePins} tensions={{}} jointModes={{}} lotteSettings={DEFAULT_LOTTE_SETTINGS}
              ghosts={[]}
              ghostDataGenerator={generatePoseAtPhase}
            />
          </g>
        </svg>
      </div>
    </div>
  );
};

