const DEFAULT_RESTING_POSE: WalkingEnginePose = { 
  bodyRotation: 0, waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 15, r_shoulder: -15, 
  l_elbow: -10, r_elbow: -10, 
  l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, 
  l_knee: 10, r_knee: 10, 
  l_foot: -90, r_foot: -90, l_toe: 0, r_toe: 0, stride_phase: 0, y_offset: 0, x_offset: 0 
};

const DEFAULT_IDLE_SETTINGS: IdleSettings = { breathing: 0.5, weightShift: 0.3, gazeSway: 0.4, tension: 0.2, fidgetFrequency: 0.3, transitionSpeed: 0.3, posture: 0.0, idlePinnedFeet: 'none' };
const DEFAULT_LOTTE_SETTINGS: LotteSettings = { enabled: true, frameStepping: true, cutoutSnap: true, paperJitter: true, shadowBlur: true, profileLock: false };
const DEFAULT_PHYSICS_CONTROLS: PhysicsControls = { motionSmoothing: 0.85, jointElasticity: 0.8, stabilization: 0.75, impactDamping: 0.2, bodyMass: 0.5, pendulumDrag: 0.3, bounceIntensity: 0.5 };
const DEFAULT_PIVOT_OFFSETS: WalkingEnginePivotOffsets = { neck: 0, collar: 0, torso: 0, waist: 0, l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0 };
const DEFAULT_PROPORTIONS: WalkingEngineProportions = { head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 }, l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 }, r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 }, l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 }, r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 } };

const DEFAULT_GAIT_SETTINGS: WalkingEngineGait = {
  intensity: 1, frequency: 1, stride: 1, lean: 0, upper_body_lean: 0,
  hip_sway: 0, waist_twist: 0, arm_swing: 1, elbow_bend: 1, arm_spread: 0,
  gravity: 0.5, verticality: 0.5, kick_up_force: 0.5, foot_roll: 0.5, hover_height: 0.5,
  toe_bend: 0.5, torso_swivel: 0.5, head_spin: 0, footDrag: 0.5, footSpring: 0.5,
  headAutoBend: 0, headAutoStretch: 0, handsAutoBend: 0, handsAutoStretch: 0,
  feetAutoBend: 0, feetAutoStretch: 0, heavyStomp: 0, headVelocitySensitivity: 0.5,
  elbowFlexibility: 0.5, elbowMinBend: -5, elbowMaxBend: 150
};

const CollapsibleSection: React.FC<{ title: string; children: React.ReactNode; defaultOpen?: boolean; disabled?: boolean; }> = ({ title, children, defaultOpen = true, disabled = false }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  return (
    <div className={`flex flex-col gap-1 p-3 border rounded shadow-sm transition-all ${disabled ? 'border-ridge bg-mono-darker/50 opacity-50' : 'border-ridge bg-mono-dark'}`}>
      <button onClick={() => !disabled && setIsOpen(!isOpen)} className={`flex justify-between items-center w-full text-[10px] font-bold tracking-[0.2em] uppercase cursor-pointer transition-colors ${disabled ? 'text-mono-mid cursor-not-allowed' : `hover:text-ink text-selection`}`} disabled={disabled}>
        <span>{title}</span><span className="text-mono-mid transform transition-transform duration-200">{isOpen ? '▲' : '▼'}</span>
      </button>
      <div className={`overflow-hidden transition-all duration-300 ${isOpen ? 'max-h-[2000px] opacity-100' : 'max-h-0 opacity-0'}`}><div className="pt-1">{children}</div></div>
    </div>
  );
};

const App: React.FC = () => {
  const [library] = useState(() => new CharacterLibraryManager());
  const [characters, setCharacters] = useState<CharacterMorphology[]>([]);
  const [currentCharacter, setCurrentCharacter] = useState<CharacterMorphology | null>(null);
  const [charDescription, setCharDescription] = useState('');
  const [vibeScale, setVibeScale] = useState(1.0);

  const [showPivots, setShowPivots] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);

  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle' | 'animation'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [bodyRotation, setBodyRotation] = useState(0);

  const [gait, setGait] = useState<WalkingEngineGait>(DEFAULT_GAIT_SETTINGS);
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [tensions, setTensions] = useState<Record<string, number>>({});
  const [temporalPhase, setTemporalPhase] = useState<number | null>(null);

  const [activeScripts, setActiveScripts] = useState<MicroScriptInstance[]>([]);
  const [currentClip, setCurrentClip] = useState<AnimationClip | null>(null);
  const [animState, setAnimState] = useState<AnimationState>({ currentClip: null, currentTime: 0, isPlaying: false, speed: 1 });

  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    library.init().then(() => {
      library.getAllCharacters().then(setCharacters);
    });
  }, []);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-10), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  // Periodic Micro-Script Triggering
  useEffect(() => {
    if (!currentCharacter || isPaused) return;

    const interval = setInterval(() => {
      // Chance depends on Vibe and fidget frequency
      const traits = currentCharacter.tags;
      traits.forEach(trait => {
        const available = getScriptsForTrait(trait);
        if (available.length > 0 && Math.random() < 0.2 * vibeScale) {
          const scriptId = available[Math.floor(Math.random() * available.length)];
          const scriptDef = MICRO_SCRIPTS[scriptId];

          setActiveScripts(prev => {
            // Prevent duplicates of the same script active at once
            if (prev.some(s => s.scriptId === scriptId)) return prev;

            const newInstance: MicroScriptInstance = {
              id: `script_${Date.now()}_${Math.random()}`,
              scriptId,
              startTime: performance.now(),
              duration: scriptDef.duration,
              weight: vibeScale
            };
            return [...prev, newInstance];
          });
          logSystem(`Triggered Script: ${scriptId} (${trait})`);
        }
      });
    }, 2000);

    return () => clearInterval(interval);
  }, [currentCharacter, vibeScale, isPaused]);

  const generateCharacter = async () => {
    if (!charDescription.trim()) return;
    const char = CharacterGenerator.generateCharacter(charDescription);
    await library.saveCharacter(char);
    setCharacters(p => [...p, char]);
    setCurrentCharacter(char);
    setGait(GaitSynthesizer.synthesizeGait(char, vibeScale));
    setCharDescription('');
    logSystem(`Character Synthesized: ${char.name}`);
  };

  useEffect(() => {
    if (currentCharacter) {
      setGait(GaitSynthesizer.synthesizeGait(currentCharacter, vibeScale));
    }
  }, [vibeScale, currentCharacter]);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    const p = (phase * Math.PI * 2);
    const locPose = updateLocomotionPhysics(p, { ...INITIAL_LOCOMOTION_STATE }, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, 1.0);
    const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', 1.0, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, activePins, idleSettings, isIkEnabled]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused && temporalPhase === null && !animState.isPlaying) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      let finalPose: WalkingEnginePose;

      if (engineMode === 'animation' && currentClip) {
        if (animState.isPlaying) {
          setAnimState(prev => {
            let nextTime = prev.currentTime + (elapsed / 1000) * prev.speed;
            if (nextTime > currentClip.duration) {
              if (currentClip.loop) nextTime = nextTime % currentClip.duration;
              else {
                nextTime = currentClip.duration;
                return { ...prev, isPlaying: false, currentTime: nextTime };
              }
            }
            return { ...prev, currentTime: nextTime };
          });
        }
        const animPose = AnimationEngine.getPoseAtTime(currentClip, animState.currentTime);
        finalPose = animPose || DEFAULT_RESTING_POSE;
      } else {
        const p = temporalPhase !== null ? (temporalPhase * Math.PI * 2) : (time * 0.005 * gait.frequency) % (Math.PI * 2);
        const locWeight = engineMode === 'locomotion' ? 1.0 : 0.0;

        // Base Physics Engines
        const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS_CONTROLS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, locWeight);
        const idlePose = updateIdlePhysics(time, elapsed, idleSettings, locWeight, currentCharacter?.tags || []);

        // Process Behavioral Micro-Scripts (Additive Layer)
        const { pose: scriptPose, remaining } = processActiveScripts(time, activeScripts);
        if (remaining.length !== activeScripts.length) {
          setActiveScripts(remaining);
        }

        const blendedPose: Partial<WalkingEnginePose> = {};
        const allKeys = new Set([...Object.keys(locPose), ...Object.keys(idlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;

        allKeys.forEach(key => {
          const lVal = (locPose as any)[key] ?? 0;
          const iVal = (idlePose as any)[key] ?? 0;
          const sVal = (scriptPose as any)[key] ?? 0;

          // Micro-scripts are additive, but we damp them when walking intensely
          const scriptInfluence = 1.0 - (gait.intensity * 0.3 * locWeight);
          (blendedPose as any)[key] = lerp(iVal, lVal, locWeight) + (sVal * scriptInfluence);
        });

        // Final Environmental Anchoring (Grounding)
        const { adjustedPose, tensions: groundTensions } = applyFootGrounding(blendedPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS_CONTROLS, activePins, idleSettings, 'center', locWeight, elapsed);
        setTensions(groundTensions);
        finalPose = adjustedPose as WalkingEnginePose;
      }
      setPose(finalPose);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, temporalPhase, targetFps, engineMode, currentClip, animState, activeScripts, currentCharacter]);

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <CollapsibleSection title="Character Factory">
            <div className="flex flex-col gap-2">
              <label className="text-[8px] font-bold uppercase text-mono-light">Description Prompt</label>
              <textarea 
                value={charDescription}
                onChange={(e) => setCharDescription(e.target.value)}
                placeholder="e.g. 'A nervous, tiny flyer'"
                className="w-full h-16 p-2 bg-mono-dark border border-ridge text-[9px] resize-none focus:outline-none focus:border-selection"
              />
              <div className="flex flex-col gap-1 mt-1">
                <div className="flex justify-between text-[8px] font-bold uppercase text-mono-light">
                    <span>Vibe Intensity</span>
                    <span className="text-selection">{(vibeScale * 100).toFixed(0)}%</span>
                </div>
                <input 
                    type="range" min="0" max="2" step="0.01" value={vibeScale} 
                    onChange={(e) => setVibeScale(parseFloat(e.target.value))} 
                    className="w-full h-1 accent-selection"
                />
              </div>
              <button 
                onClick={generateCharacter}
                className="w-full py-1.5 bg-selection text-paper text-[9px] font-bold uppercase hover:opacity-90 transition-all"
              >
                Synthesize Character
              </button>
            </div>
          </CollapsibleSection>

          {currentCharacter && (
            <div className="p-3 bg-mono-dark/50 border border-ridge rounded text-[9px]">
              <div className="text-selection font-bold mb-1">{currentCharacter.name}</div>
              <div className="text-mono-light grid grid-cols-2 gap-x-2 mb-2">
                <span>Stability: {(currentCharacter.gaitDNA.stability * 100).toFixed(0)}%</span>
                <span>Agility: {(currentCharacter.gaitDNA.agility * 100).toFixed(0)}%</span>
              </div>
              <div className="flex flex-wrap gap-1">
                {currentCharacter.tags.map(tag => (
                  <span key={tag} className="px-1.5 py-0.5 bg-mono-dark border border-ridge text-[7px] uppercase font-bold text-mono-mid">{tag}</span>
                ))}
              </div>
              {activeScripts.length > 0 && (
                <div className="mt-2 pt-2 border-t border-ridge/30 flex flex-col gap-1">
                  <span className="text-[7px] font-bold text-accent-red uppercase">Active Behaviors</span>
                  {activeScripts.map(s => (
                    <div key={s.id} className="text-[7px] text-mono-light flex items-center gap-1">
                      <div className="w-1 h-1 bg-accent-red rounded-full animate-pulse" />
                      {s.scriptId.replace('_', ' ')}
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          <CollapsibleSection title="Character Library">
            <div className="flex flex-col gap-1 max-h-40 overflow-y-auto pr-1">
              {characters.map(char => (
                <button 
                  key={char.id}
                  onClick={() => { setCurrentCharacter(char); setGait(GaitSynthesizer.synthesizeGait(char, vibeScale)); }}
                  className={`text-left p-1 px-2 border rounded text-[8px] transition-all truncate ${currentCharacter?.id === char.id ? 'bg-selection text-paper border-selection' : 'border-ridge bg-paper/20 hover:bg-mono-dark'}`}
                >
                  {char.name}
                </button>
              ))}
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Engine Controls">
            <div className="flex gap-1 mb-2">
              <button onClick={() => setEngineMode('locomotion')} className={`flex-1 text-[9px] py-1 border ${engineMode === 'locomotion' ? 'bg-selection text-paper' : 'border-ridge'}`}>WALK</button>
              <button onClick={() => setEngineMode('idle')} className={`flex-1 text-[9px] py-1 border ${engineMode === 'idle' ? 'bg-selection text-paper' : 'border-ridge'}`}>IDLE</button>
            </div>
            <button onClick={() => setIsPaused(!isPaused)} className={`w-full text-[9px] py-1 border ${isPaused ? 'bg-accent-red/20 border-accent-red text-accent-red' : 'border-ridge'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
          </CollapsibleSection>

          <div className="mt-auto">
            <SystemLogger logs={systemLogs} isVisible={true} />
          </div>
        </div>
      )}

      <div className="flex-1 relative overflow-hidden bg-white">
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker rounded-full text-ink transition-all">{isConsoleVisible ? '✕' : '☰'}</button>
        <div className="absolute top-4 right-4 flex flex-col gap-2 z-50">
          <button onClick={() => setZoomIndex(prev => Math.min(UI.ZOOM_LEVELS.length - 1, prev + 1))} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge font-bold shadow-sm">+</button>
          <button onClick={() => {setZoomIndex(UI.DEFAULT_ZOOM_INDEX); setPanOffset({x:0,y:0})}} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge text-[10px] shadow-sm">RST</button>
          <button onClick={() => setZoomIndex(prev => Math.max(0, prev - 1))} className="w-8 h-8 flex items-center justify-center bg-white border border-ridge font-bold shadow-sm">-</button>
        </div>
        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full relative z-10">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={DEFAULT_PROPORTIONS} 
              showPivots={showPivots} baseUnitH={H * (currentCharacter?.anatomy.bodyLength || 1)} 
              onAnchorMouseDown={(k) => setActivePins(p => p.includes(k) ? p.filter(x => x !== k) : [...p, k])} 
              draggingBoneKey={null} isPaused={isPaused} activePins={activePins} tensions={tensions} jointModes={{}} lotteSettings={DEFAULT_LOTTE_SETTINGS}
              ghosts={[]}
              ghostDataGenerator={generatePoseAtPhase}
            />
          </g>
        </svg>
      </div>
    </div>
  );
};

export default App;

import { WalkingEnginePose, MicroScriptInstance, IdleSettings, WalkingEngineGait } from '../types';
import { lerp, clamp, easeInOutQuint } from './kinematics';

export type CharacterState = 'IDLE' | 'WALKING' | 'TRANSITIONING';

export class BehaviorEngine {
  private static footLatchL = { x: 0, y: 0 };
  private static footLatchR = { x: 0, y: 0 };
  private static lastLocomotionWeight = 1.0;

  /**
   * Blends Locomotion, Idle, and Micro-Scripts with phase-awareness.
   */
  static blendPose(
    locPose: Partial<WalkingEnginePose>,
    idlePose: Partial<WalkingEnginePose>,
    scriptPose: Partial<WalkingEnginePose>,
    locWeight: number,
    gait: WalkingEngineGait,
    time: number
  ): Partial<WalkingEnginePose> {
    const blended: any = {};
    const keys = new Set([
      ...Object.keys(locPose),
      ...Object.keys(idlePose),
      ...Object.keys(scriptPose)
    ]) as Set<keyof WalkingEnginePose>;

    // Calculate Layer suppressions
    // If running fast, we suppress complex fidgets (scripts) by up to 80%
    const activitySuppression = 1.0 - (clamp(gait.intensity * gait.frequency, 0, 1.5) * 0.5);

    keys.forEach(key => {
      const lVal = (locPose as any)[key] ?? 0;
      const iVal = (idlePose as any)[key] ?? 0;
      const sVal = (scriptPose as any)[key] ?? 0;

      // Primary Base Layer Blend
      let base = lerp(iVal, lVal, locWeight);

      // Additive Script Layer (Fidgets)
      // Scripts are added to the base pose, but suppressed by locomotion intensity
      blended[key] = base + (sVal * activitySuppression);
    });

    // Phase-Aware Foot Latching Logic
    // We modify the x_offset and y_offset to prevent "skating" during transitions
    if (this.lastLocomotionWeight > 0.1 && locWeight < 0.1) {
       // Just switched to Idle: Capture current offsets as latch points
       // In a full implementation, we'd store world-space ankle positions here
    }

    this.lastLocomotionWeight = locWeight;
    return blended as Partial<WalkingEnginePose>;
  }

  /**
   * Determines if a micro-script should trigger based on semantic traits
   */
  static shouldTriggerFidget(traits: string[], vibe: number): string | null {
    const roll = Math.random();
    // Threshold depends on Vibe scale
    if (roll > 0.05 * vibe) return null;

    if (traits.includes('nervous') || traits.includes('anxious')) {
      return Math.random() > 0.5 ? 'scratch_neck' : 'shiver';
    }
    if (traits.includes('confident') || traits.includes('bold')) {
      return 'chest_puff';
    }
    return 'look_around';
  }
}

// utils/groundingEngine.ts

import { WalkingEnginePose, WalkingEngineProportions, PhysicsControls, PartName, IdleSettings, Vector2D, GroundingResults } from '../types';
import { MANNEQUIN_LOCAL_FLOOR_Y, GROUNDING_PHYSICS, ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT } from '../constants';
import { lerp, clamp, solve2DJointIK } from './kinematics';
import { calculateFootTipGlobalPosition } from './locomotionEngine';

export const applyFootGrounding = (
    rawPose: Partial<WalkingEnginePose>,
    props: WalkingEngineProportions,
    baseUnitH: number,
    physics: PhysicsControls,
    locomotionActivePins: string[],
    idleSettings: IdleSettings,
    gravityCenter: 'left' | 'center' | 'right',
    locomotionWeight: number,
    deltaTime: number,
): GroundingResults => {
    const adjustedPose: Partial<WalkingEnginePose> = { ...rawPose };
    const tensions: Record<string, number> = {};

    const floorYGlobal = GROUNDING_PHYSICS.FLOOR_Y_OFFSET_GLOBAL_H_UNIT * baseUnitH; 

    // Weighted pin strength to prevent jumps during transition
    const locomotionPinL = locomotionActivePins.includes(PartName.LAnkle) ? 1.0 : 0.0;
    const locomotionPinR = locomotionActivePins.includes(PartName.RAnkle) ? 1.0 : 0.0;
    const idlePinL = (idleSettings.idlePinnedFeet === 'left' || idleSettings.idlePinnedFeet === 'both') ? 1.0 : 0.0;
    const idlePinR = (idleSettings.idlePinnedFeet === 'right' || idleSettings.idlePinnedFeet === 'both') ? 1.0 : 0.0;

    // Phase-Aware Blending: Higher smoothing during transition to prevent snapping
    const transitionSmoothing = locomotionWeight > 0.1 && locomotionWeight < 0.9 ? 0.95 : physics.motionSmoothing;

    const pinStrengthL = lerp(idlePinL, locomotionPinL, locomotionWeight);
    const pinStrengthR = lerp(idlePinR, locomotionPinR, locomotionWeight);

    let currentBodyX = adjustedPose.x_offset ?? 0;
    let currentBodyY = adjustedPose.y_offset ?? 0;

    const lFootNatural = calculateFootTipGlobalPosition({ 
        hip: adjustedPose.l_hip ?? 0, 
        knee: adjustedPose.l_knee ?? 0, 
        foot: adjustedPose.l_foot ?? 0, 
        toe: adjustedPose.l_toe ?? 0 
    }, props, baseUnitH, false);

    const rFootNatural = calculateFootTipGlobalPosition({ 
        hip: adjustedPose.r_hip ?? 0, 
        knee: adjustedPose.r_knee ?? 0, 
        foot: adjustedPose.r_foot ?? 0, 
        toe: adjustedPose.r_toe ?? 0 
    }, props, baseUnitH, true);

    const idleGroundingBonus = locomotionWeight < 0.2 ? 1.5 : 1.0;
    const yCorrectionStrength = GROUNDING_PHYSICS.GROUNDING_SPRING_FACTOR * (1 - physics.jointElasticity) * idleGroundingBonus;
    const xCorrectionStrength = GROUNDING_PHYSICS.GROUNDING_X_STABILITY_FACTOR * (1 - physics.stabilization);

    if (pinStrengthL > 0.01 || pinStrengthR > 0.01) {
        const thighLengthL = (props.l_upper_leg?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER * baseUnitH;
        const calfLengthL = (props.l_lower_leg?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER * baseUnitH;
        const thighLengthR = (props.r_upper_leg?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER * baseUnitH;
        const calfLengthR = (props.r_lower_leg?.h ?? 1) * ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER * baseUnitH;

        const maxLegReachL = thighLengthL + calfLengthL;
        const maxLegReachR = thighLengthR + calfLengthR;

        const crouchFactor = clamp(Math.abs(currentBodyY) / (baseUnitH * 1.5), 0, 1);
        const dynamicSpread = baseUnitH * lerp(GROUNDING_PHYSICS.STABILITY_SPRING_BASE_SPREAD_H_UNIT, GROUNDING_PHYSICS.STABILITY_SPRING_CROUCH_SPREAD_H_UNIT, crouchFactor);

        let yCorrection = 0;
        let totalPinWeight = 0;

        const calculateYCorrection = (isRight: boolean, weight: number) => {
            const reach = isRight ? maxLegReachR : maxLegReachL;
            const footNatY = isRight ? rFootNatural.y : lFootNatural.y;

            let targetAnkleX = 0;
            if (pinStrengthL > 0.5 && pinStrengthR > 0.5) {
                targetAnkleX = isRight ? dynamicSpread : -dynamicSpread;
            } else if (pinStrengthL > 0.5) {
                targetAnkleX = -dynamicSpread * 0.5;
            } else if (pinStrengthR > 0.5) {
                targetAnkleX = dynamicSpread * 0.5;
            }

            const hipToTargetX = targetAnkleX - currentBodyX;
            const hipToTargetX_sq = hipToTargetX * hipToTargetX;

            const transitionTargetY = lerp(footNatY + currentBodyY, floorYGlobal, weight);

            if (hipToTargetX_sq > reach * reach) {
                const xOffsetCorr = (Math.abs(hipToTargetX) - (reach * 0.99)) * Math.sign(hipToTargetX);
                currentBodyX += xOffsetCorr * xCorrectionStrength * weight;
                return (transitionTargetY - currentBodyY) * weight;
            }

            const requiredYDist = Math.sqrt(reach * reach - hipToTargetX_sq);
            const requiredHipY = transitionTargetY - requiredYDist;
            return (requiredHipY - currentBodyY) * weight;
        };

        if (pinStrengthL > 0.01) {
            yCorrection += calculateYCorrection(false, pinStrengthL);
            totalPinWeight += pinStrengthL;
        }
        if (pinStrengthR > 0.01) {
            yCorrection += calculateYCorrection(true, pinStrengthR);
            totalPinWeight += pinStrengthR;
        }

        const verticalStickiness = locomotionWeight < 0.1 ? 0.8 : yCorrectionStrength;
        if (totalPinWeight > 0) {
            currentBodyY = lerp(currentBodyY, currentBodyY + yCorrection / totalPinWeight, verticalStickiness);
        }

        const hipPos = { x: currentBodyX, y: currentBodyY };

        const solveAndApplyIK = (isRight: boolean, weight: number) => {
            const partName = isRight ? PartName.RAnkle : PartName.LAnkle;
            const thighLen = isRight ? thighLengthR : thighLengthL;
            const calfLen = isRight ? calfLengthR : calfLengthL;
            const reach = thighLen + calfLen;

            let targetAnkleX = 0;
            if (pinStrengthL > 0.5 && pinStrengthR > 0.5) {
                targetAnkleX = isRight ? dynamicSpread : -dynamicSpread;
            } else if (pinStrengthL > 0.5) {
                targetAnkleX = -dynamicSpread * 0.5;
            } else if (pinStrengthR > 0.5) {
                targetAnkleX = dynamicSpread * 0.5;
            }

            const targetPos = { x: targetAnkleX, y: floorYGlobal };
            const ik = solve2DJointIK(targetPos, hipPos, thighLen, calfLen, adjustedPose.bodyRotation ?? 0);

            if (ik) {
                const legAngles = { hip: ik.angle1, knee: ik.angle2, foot: -90, toe: 0 };
                if (isRight) {
                    adjustedPose.r_hip = lerp(adjustedPose.r_hip ?? 0, legAngles.hip, weight);
                    adjustedPose.r_knee = lerp(adjustedPose.r_knee ?? 0, legAngles.knee, weight);
                    adjustedPose.r_foot = lerp(adjustedPose.r_foot ?? -90, legAngles.foot, weight);
                    adjustedPose.r_toe = lerp(adjustedPose.r_toe ?? 0, legAngles.toe, weight);
                } else {
                    adjustedPose.l_hip = lerp(adjustedPose.l_hip ?? 0, legAngles.hip, weight);
                    adjustedPose.l_knee = lerp(adjustedPose.l_knee ?? 0, legAngles.knee, weight);
                    adjustedPose.l_foot = lerp(adjustedPose.l_foot ?? -90, legAngles.foot, weight);
                    adjustedPose.l_toe = lerp(adjustedPose.l_toe ?? 0, legAngles.toe, weight);
                }

                const dist = Math.hypot(targetPos.x - hipPos.x, targetPos.y - hipPos.y);
                tensions[partName] = clamp(dist / reach, 0, 1) * weight;
            }
        };

        if (pinStrengthL > 0.01) solveAndApplyIK(false, pinStrengthL);
        if (pinStrengthR > 0.01) solveAndApplyIK(true, pinStrengthR);

    } else {
        const lowestFootY = Math.min(lFootNatural.y + currentBodyY, rFootNatural.y + currentBodyY);

        if (lowestFootY > floorYGlobal - GROUNDING_PHYSICS.FOOT_LIFT_THRESHOLD_H_UNIT * baseUnitH) {
            const correctionY = floorYGlobal - lowestFootY;
            currentBodyY = lerp(currentBodyY, currentBodyY + correctionY, yCorrectionStrength);
        }

        let cogBiasX = 0;
        if (gravityCenter === 'left') cogBiasX = -GROUNDING_PHYSICS.COG_X_SIDE_OFFSET_H_UNIT * baseUnitH;
        else if (gravityCenter === 'right') cogBiasX = GROUNDING_PHYSICS.COG_X_SIDE_OFFSET_H_UNIT * baseUnitH;

        const idleXStability = (1 - locomotionWeight) * 0.1;
        currentBodyX = lerp(currentBodyX, cogBiasX, idleXStability + xCorrectionStrength * 0.5);
    }

    const totalTension = (tensions[PartName.LAnkle] || 0) + (tensions[PartName.RAnkle] || 0);
    if (totalTension > GROUNDING_PHYSICS.VERTICALITY_TENSION_THRESHOLD * ((pinStrengthL > 0.5 && pinStrengthR > 0.5) ? 2 : 1)) {
        const straightenFactor = GROUNDING_PHYSICS.VERTICALITY_STRAIGHTEN_FACTOR;
        adjustedPose.waist = lerp(adjustedPose.waist ?? 0, 0, straightenFactor);
        adjustedPose.torso = lerp(adjustedPose.torso ?? 0, 0, straightenFactor);
        adjustedPose.collar = lerp(adjustedPose.collar ?? 0, 0, straightenFactor);
    }

    const kneeBend = Math.max(adjustedPose.l_knee ?? 0, adjustedPose.r_knee ?? 0);
    if (kneeBend > GROUNDING_PHYSICS.GRAVITY_OVERLOAD_KNEE_BEND_THRESHOLD) {
        const overloadFactor = (kneeBend - GROUNDING_PHYSICS.GRAVITY_OVERLOAD_KNEE_BEND_THRESHOLD) / (180 - GROUNDING_PHYSICS.GRAVITY_OVERLOAD_KNEE_BEND_THRESHOLD);
        currentBodyX = lerp(currentBodyX, 0, GROUNDING_PHYSICS.GRAVITY_OVERLOAD_CENTERING_FACTOR * overloadFactor);
    }

    adjustedPose.x_offset = currentBodyX;
    adjustedPose.y_offset = currentBodyY;

    return { adjustedPose, tensions };
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  WalkingEnginePose, WalkingEngineGait, WalkingEnginePivotOffsets, WalkingEngineProportions, 
  JointModesState, IdleSettings, PartName, GaitPresetTemplate, IdlePresetTemplate, 
  LotteSettings, PhysicsControls, Vector2D, GhostState, AnimationClip, AnimationState, Keyframe,
  CharacterMorphology, MicroScriptInstance
} from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, MANNEQUIN_LOCAL_FLOOR_Y, TIMING, UI } from './constants';
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';
import { LocomotionState, INITIAL_LOCOMOTION_STATE, updateLocomotionPhysics } from './utils/locomotionEngine';
import { updateIdlePhysics } from './utils/idleEngine';
import { applyFootGrounding } from './utils/groundingEngine';
import { lerp, easeInOutQuint, clamp } from './utils/kinematics';
