      <div className="flex-1 relative overflow-hidden bg-white">
        {/* Floating Scene Controls */}
        <div className="absolute top-4 left-4 z-50 flex gap-2">
            <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="p-2 bg-white border border-ridge hover:bg-mono-darker rounded-full text-ink transition-all shadow-sm">{isConsoleVisible ? '✕' : '☰'}</button>
