// New randomization function for Gait presets
const generateRandomGait = (template: GaitPresetTemplate): WalkingEngineGait => {
  const newGait: Partial<WalkingEngineGait> = {};
  for (const key in DEFAULT_GAIT_SETTINGS) { // Iterate over all possible gait keys
    const param = template.settings[key as keyof WalkingEngineGait];
    const config = gaitSliderConfig[key as keyof WalkingEngineGait];

    if (typeof param === 'number') {
      // Fixed value in template
      (newGait as any)[key] = param;
    } else if (param && typeof param === 'object' && 'base' in param && 'range' in param) {
      // Randomize within base +/- range
      let value = (param as ParameterRange).base + (Math.random() * 2 - 1) * (param as ParameterRange).range;
      // Clamp within overall slider config min/max
      if (config) {
        value = clamp(value, config.min, config.max);
      }
      (newGait as any)[key] = value;
    } else {
      // Fallback to default if not defined in template
      (newGait as any)[key] = (DEFAULT_GAIT_SETTINGS as any)[key];
    }
  }
  return newGait as WalkingEngineGait;
};

// New randomization function for Idle presets
const generateRandomIdle = (template: IdlePresetTemplate): IdleSettings => {
  const newIdle: Partial<IdleSettings> = {};
  for (const key in DEFAULT_IDLE_SETTINGS) {
    const param = template.settings[key as keyof IdleSettings];
    // Define broad min/max bounds for idle settings if not implicitly available
    const min = key === 'posture' ? -1 : 0;
    const max = key === 'posture' ? 1 : 1;
    // Special handling for transitionSpeed (Idle Speed) min/max
    const currentMin = key === 'transitionSpeed' ? 0.1 : min;
    const currentMax = key === 'transitionSpeed' ? 0.5 : max; // Max idle speed 0.5

    if (key === 'idlePinnedFeet') {
      // Directly assign if it's a valid string literal, otherwise fallback to default
      (newIdle as any)[key] = (template.settings.idlePinnedFeet === 'left' || template.settings.idlePinnedFeet === 'right' || template.settings.idlePinnedFeet === 'both' || template.settings.idlePinnedFeet === 'none')
        ? template.settings.idlePinnedFeet
        : DEFAULT_IDLE_SETTINGS.idlePinnedFeet; // Fallback to default
    } else if (typeof param === 'number') {
      (newIdle as any)[key] = param;
    } else if (param && typeof param === 'object' && 'base' in param && 'range' in param) {
      let value = (param as ParameterRange).base + (Math.random() * 2 - 1) * (param as ParameterRange).range;
      value = clamp(value, currentMin, currentMax);
      (newIdle as any)[key] = value;
    } else {
      (newIdle as any)[key] = (DEFAULT_IDLE_SETTINGS as any)[key];
    }
  }
  return newIdle as IdleSettings;
};


