        </div>

        <svg viewBox={viewBox} className="w-full h-full relative z-10 bg-triangle-grid">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
