const App: React.FC = () => {
  const [library] = useState(() => new CharacterLibraryManager());
  const [characters, setCharacters] = useState<CharacterMorphology[]>([]);
  const [currentCharacter, setCurrentCharacter] = useState<CharacterMorphology | null>(null);
  const [charDescription, setCharDescription] = useState('');
  const [vibeScale, setVibeScale] = useState(1.0);

  const [showPivots, setShowPivots] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);

  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle' | 'animation'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [gravityCenter, setGravityCenter] = useState<'left' | 'center' | 'right'>('center');

  const [gait, setGait] = useState<WalkingEngineGait>(GaitSynthesizer.synthesizeGait(CharacterGenerator.generateCharacter('Default'), 1.0));
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [tensions, setTensions] = useState<Record<string, number>>({});

  const [activeScripts, setActiveScripts] = useState<MicroScriptInstance[]>([]);
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const locomotionWeightRef = useRef(1.0);

  useEffect(() => {
    library.init().then(() => library.getAllCharacters().then(setCharacters));
  }, []);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-12), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  // Behavioral Fidget Trigger
  useEffect(() => {
    if (!currentCharacter || isPaused) return;
    const interval = setInterval(() => {
      const scriptId = BehaviorEngine.shouldTriggerFidget(currentCharacter.tags, vibeScale);
      if (scriptId) {
        const scriptDef = MICRO_SCRIPTS[scriptId];
        setActiveScripts(prev => {
          if (prev.some(s => s.scriptId === scriptId)) return prev;
          return [...prev, {
            id: `script_${Date.now()}`,
            scriptId,
            startTime: performance.now(),
            duration: scriptDef.duration,
            weight: vibeScale
          }];
        });
        logSystem(`Micro-script: ${scriptId.toUpperCase()}`);
      }
    }, 1500);
    return () => clearInterval(interval);
  }, [currentCharacter, vibeScale, isPaused]);

  const generateCharacter = async () => {
    if (!charDescription.trim()) return;
    const char = CharacterGenerator.generateCharacter(charDescription);
    await library.saveCharacter(char);
    setCharacters(p => [...p, char]);
    setCurrentCharacter(char);
    setGait(GaitSynthesizer.synthesizeGait(char, vibeScale));
    setCharDescription('');
    logSystem(`Synthesized behavioral genome: ${char.name}`);
  };

  useEffect(() => {
    if (currentCharacter) setGait(GaitSynthesizer.synthesizeGait(currentCharacter, vibeScale));
  }, [vibeScale, currentCharacter]);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  const generatePoseAtPhase = useCallback((phase: number) => {
    const p = (phase * Math.PI * 2);
    const locPose = updateLocomotionPhysics(p, { ...INITIAL_LOCOMOTION_STATE }, gait, DEFAULT_PHYSICS, DEFAULT_PROPORTIONS, activePins, 150, gravityCenter, H, isIkEnabled, 1.0);
    const { adjustedPose } = applyFootGrounding(locPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS, activePins, idleSettings, gravityCenter, 1.0, 16);
    return adjustedPose as WalkingEnginePose;
  }, [gait, activePins, idleSettings, isIkEnabled, gravityCenter]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      const targetWeight = engineMode === 'locomotion' ? 1.0 : 0.0;
      locomotionWeightRef.current = lerp(locomotionWeightRef.current, targetWeight, 0.1);
      const locWeight = locomotionWeightRef.current;

      const p = (time * 0.005 * gait.frequency) % (Math.PI * 2);

      const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS, DEFAULT_PROPORTIONS, activePins, 150, gravityCenter, H, isIkEnabled, locWeight);
      const idlePose = updateIdlePhysics(time, elapsed, idleSettings, locWeight, currentCharacter?.tags || []);
      const { pose: scriptPose, remaining } = processActiveScripts(time, activeScripts);
      if (remaining.length !== activeScripts.length) setActiveScripts(remaining);

      const blendedPose = BehaviorEngine.blendPose(locPose, idlePose, scriptPose, locWeight, gait, time);
      const { adjustedPose, tensions: groundTensions } = applyFootGrounding(blendedPose, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS, activePins, idleSettings, gravityCenter, locWeight, elapsed);

      setTensions(groundTensions);
      setPose(adjustedPose as WalkingEnginePose);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, targetFps, engineMode, activeScripts, currentCharacter, gravityCenter]);

  const categories = ['Primary', 'Body', 'Arms', 'Legs', 'Effects'];

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-dark p-4 flex flex-col gap-1 custom-scrollbar overflow-y-auto shrink-0 z-20 shadow-2xl">
          <h1 className="text-xl font-archaic tracking-widest border-b-2 border-selection pb-1 text-ink uppercase italic flex items-center justify-between">
            <span>BITRUVIUS.ENGINE</span>
            <span className="text-[9px] bg-selection text-paper px-1">PHASE 0.2</span>
          </h1>

          <CollapsibleSection title="Genetics" defaultOpen={true}>
            <textarea 
              value={charDescription}
              onChange={(e) => setCharDescription(e.target.value)}
              placeholder="Prompt semantic behavior..."
              className="w-full h-14 p-2 bg-paper border border-ridge text-[9px] resize-none focus:outline-none focus:border-selection"
            />
            <div className="flex flex-col gap-1">
              <div className="flex justify-between text-[8px] font-bold uppercase text-mono-light">
                  <span>Vibe/Intensity</span>
                  <span className="text-selection">{(vibeScale * 100).toFixed(0)}%</span>
              </div>
              <input type="range" min="0" max="2" step="0.01" value={vibeScale} onChange={(e) => setVibeScale(parseFloat(e.target.value))} className="w-full h-1 accent-selection" />
              <button onClick={generateCharacter} className="w-full py-2 bg-selection text-paper text-[8px] font-bold uppercase hover:bg-selection-light transition-all">Synthesize DNA</button>
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Gait Matrix" count={Object.keys(gaitSliderConfig).length}>
             <div className="flex flex-col gap-3 h-64 overflow-y-auto pr-2 custom-scrollbar">
               {categories.map(cat => (
                 <div key={cat} className="flex flex-col gap-2">
                    <div className="text-[7px] font-black text-mono-light uppercase border-b border-ridge/30 pb-0.5">{cat} Layers</div>
                    {Object.entries(gaitSliderConfig)
                      .filter(([_, conf]) => conf.category === cat)
                      .map(([key, conf]) => (
                        <div key={key} className="flex flex-col">
                           <div className="flex justify-between text-[7px] font-bold text-selection/70 uppercase">
                              <span>{conf.label}</span>
                              <span>{gait[key as keyof WalkingEngineGait].toFixed(2)}</span>
                           </div>
                           <input 
                              type="range" min={conf.min} max={conf.max} step={conf.step} 
                              value={gait[key as keyof WalkingEngineGait]} 
                              onChange={(e) => setGait(p => ({...p, [key]: parseFloat(e.target.value)}))}
                              className="w-full h-1 accent-selection"
                           />
                        </div>
                      ))}
                 </div>
               ))}
             </div>
          </CollapsibleSection>

          <CollapsibleSection title="Joint Bias Matrix" count={Object.keys(pivotOffsets).length}>
            <div className="grid grid-cols-1 gap-2 h-48 overflow-y-auto pr-2 custom-scrollbar">
              {Object.keys(pivotOffsets).map(k => (
                <div key={k} className="flex flex-col">
                   <div className="flex justify-between text-[7px] font-bold uppercase text-mono-light">
                      <span>{k.replace('_', '.')}</span>
                      <span className="text-selection">{(pivotOffsets[k as keyof WalkingEnginePivotOffsets])}°</span>
                   </div>
                   <input 
                      type="range" min="-180" max="180" 
                      value={pivotOffsets[k as keyof WalkingEnginePivotOffsets]} 
                      onChange={(e) => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))}
                      className="w-full h-1 accent-selection"
                   />
                </div>
              ))}
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Idle Matrix" count={7}>
             <div className="flex flex-col gap-2">
                {Object.keys(DEFAULT_IDLE_SETTINGS).filter(k => k !== 'idlePinnedFeet').map(k => (
                  <div key={k} className="flex flex-col">
                    <div className="flex justify-between text-[7px] font-bold uppercase text-mono-light">
                       <span>{k}</span>
                       <span className="text-selection">{(idleSettings[k as keyof IdleSettings] as number).toFixed(2)}</span>
                    </div>
                    <input 
                      type="range" min="0" max="1" step="0.01" 
                      value={(idleSettings as any)[k]} 
                      onChange={(e) => setIdleSettings(p => ({...p, [k]: parseFloat(e.target.value)}))}
                      className="w-full h-1 accent-selection"
                    />
                  </div>
                ))}
             </div>
          </CollapsibleSection>

          <div className="mt-auto">
             <div className="flex gap-1 mb-2">
                <button onClick={() => setEngineMode('locomotion')} className={`flex-1 text-[8px] py-1 border ${engineMode === 'locomotion' ? 'bg-selection text-paper' : 'bg-paper'}`}>WALK</button>
                <button onClick={() => setEngineMode('idle')} className={`flex-1 text-[8px] py-1 border ${engineMode === 'idle' ? 'bg-selection text-paper' : 'bg-paper'}`}>IDLE</button>
             </div>
             <SystemLogger logs={systemLogs} isVisible={true} />
          </div>
        </div>
      )}

      <div className="flex-1 relative overflow-hidden bg-shell">
        <div className="absolute top-4 left-4 z-50 flex gap-2">
            <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="p-2 bg-paper border border-ridge hover:bg-mono-darker rounded shadow-sm transition-all">{isConsoleVisible ? '✕' : '☰'}</button>
            <div className="px-3 py-1 bg-paper/90 backdrop-blur-sm border border-ridge rounded text-[9px] font-bold text-mono-mid flex items-center gap-2 shadow-sm">
                <div className={`w-1.5 h-1.5 rounded-full ${engineMode === 'locomotion' ? 'bg-accent-green' : 'bg-accent-purple'} animate-pulse`} />
                {engineMode.toUpperCase()} | {Math.round(locomotionWeightRef.current * 100)}% LATCH
            </div>
            <button onClick={() => setIsPaused(!isPaused)} className={`px-4 py-1 text-[9px] font-bold border rounded shadow-sm ${isPaused ? 'bg-accent-red text-paper' : 'bg-paper'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
        </div>

        <div className="absolute top-4 right-4 flex flex-col gap-1 z-50">
          <button onClick={() => setZoomIndex(prev => Math.min(UI.ZOOM_LEVELS.length - 1, prev + 1))} className="w-8 h-8 flex items-center justify-center bg-paper border border-ridge font-bold shadow-sm hover:bg-mono-darker rounded">+</button>
          <button onClick={() => setZoomIndex(UI.DEFAULT_ZOOM_INDEX)} className="w-8 h-8 flex items-center justify-center bg-paper border border-ridge text-[7px] font-bold shadow-sm hover:bg-mono-darker rounded">RST</button>
