  { motionSmoothing: 0.75, jointElasticity: 0.6, stabilization: 0.6, impactDamping: 0.4, bodyMass: 0.4, pendulumDrag: 0.2, bounceIntensity: 1.2 },
  { motionSmoothing: 0.95, jointElasticity: 0.9, stabilization: 0.9, impactDamping: 0.1, bodyMass: 0.8, pendulumDrag: 0.8, bounceIntensity: 0.2 },
];

const CollapsibleSection: React.FC<{ title: string; children: React.ReactNode; defaultOpen?: boolean; disabled?: boolean; }> = ({ title, children, defaultOpen = true, disabled = false }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  return (
    <div className={`flex flex-col gap-2 p-4 border rounded shadow-lg transition-all ${disabled ? 'border-ridge bg-mono-darker/50 opacity-50' : 'border-ridge bg-mono-dark'}`}>
      <button onClick={() => !disabled && setIsOpen(!isOpen)} className={`flex justify-between items-center w-full text-[10px] font-bold tracking-[0.2em] uppercase cursor-pointer transition-colors ${disabled ? 'text-mono-mid cursor-not-allowed' : `hover:text-ink text-selection`}`} disabled={disabled}>
        <span>{title}</span><span className="text-mono-mid transform transition-transform duration-200">{isOpen ? '▲' : '▼'}</span>
      </button>
      <div className={`overflow-hidden transition-all duration-300 ${isOpen ? 'max-h-[2000px] opacity-100' : 'max-h-0 opacity-0'}`}><div className="pt-2">{children}</div></div>
    </div>
  );
};

type ExportFormat = 'zip' | 'webm' | 'png';

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(false);
  const [showLabels, setShowLabels] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [isSlowMoActive, setIsSlowMoActive] = useState(false);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [isLoggerVisible, setIsLoggerVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);
  const [poseDataString, setPoseDataString] = useState('');
  const [isPoseDataValid, setIsPoseDataValid] = useState(true);
  const [copyButtonText, setCopyButtonText] = useState('Copy');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;
  const [animationSpeed, setAnimationSpeed] = useState(1.0);
  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle'>('locomotion');
  const engineModeRef = useRef(engineMode);
  useEffect(() => { engineModeRef.current = engineMode; }, [engineMode]);
  const locomotionWeightRef = useRef(1.0);
  const transitionStartWeightRef = useRef(1.0);
  const transitionEndWeightRef = useRef(1.0);
  const modeTransitionStartTimeRef = useRef(0);
  const [activePins, setActivePins] = useState<string[]>([]);
  const [pinnedSlideOffset, setPinnedSlideOffset] = useState(150);
  const [bodyRotation, setBodyRotation] = useState(0);
  const [gravityCenter, setGravityCenter] = useState<'left' | 'center' | 'right'>('center');
  const [tensions, setTensions] = useState<Record<string, number>>({});
  const [shakeOffset, setShakeOffset] = useState({ x: 0, y: 0 });
  const shakeOffsetRef = useRef({ x: 0, y: 0 });

  const [gait, setGait] = useState<WalkingEngineGait>(generateRandomGait(gaitPresets[0]));
  const [smoothedGait, setSmoothedGait] = useState<WalkingEngineGait>(gait);
  const [activePresetIndex, setActivePresetIndex] = useState(0);
  const gaitRef = useRef(gait);
  const smoothedGaitRef = useRef(smoothedGait);
  useEffect(() => { gaitRef.current = gait; }, [gait]);
  useEffect(() => { smoothedGaitRef.current = smoothedGait; }, [smoothedGait]);

  const [physicsControls, setPhysicsControls] = useState<PhysicsControls>(DEFAULT_PHYSICS_CONTROLS);
  const [smoothedPhysicsControls, setSmoothedPhysicsControls] = useState<PhysicsControls>(physicsControls);
  const physicsControlsRef = useRef(physicsControls);
  const smoothedPhysicsControlsRef = useRef(smoothedPhysicsControls);
  useEffect(() => { physicsControlsRef.current = physicsControls; }, [physicsControls]);
  useEffect(() => { smoothedPhysicsControlsRef.current = smoothedPhysicsControls; }, [smoothedPhysicsControls]);

  const [idleSettings, setIdleSettings] = useState<IdleSettings>(generateRandomIdle(idlePresets[0]));
  const [smoothedIdleSettings, setSmoothedIdleSettings] = useState<IdleSettings>(idleSettings);
  const [activeIdlePresetIndex, setActiveIdlePresetIndex] = useState(0);
  const idleSettingsRef = useRef(idleSettings);
  const smoothedIdleSettingsRef = useRef(smoothedIdleSettings);
  useEffect(() => { idleSettingsRef.current = idleSettings; }, [idleSettings]);
  useEffect(() => { smoothedIdleSettingsRef.current = smoothedIdleSettings; }, [smoothedIdleSettings]);

  const [lotteSettings, setLotteSettings] = useState<LotteSettings>(DEFAULT_LOTTE_SETTINGS);
  const lotteSettingsRef = useRef(lotteSettings);
  useEffect(() => { lotteSettingsRef.current = lotteSettings; }, [lotteSettings]);

  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_PIVOT_OFFSETS);
  const [props, setProps] = useState<WalkingEngineProportions>(DEFAULT_PROPORTIONS);
  const [jointModes, setJointModes] = useState<JointModesState>({});
  const jointModesRef = useRef(jointModes);
  useEffect(() => { jointModesRef.current = jointModes; }, [jointModes]);

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const [isTransitioningToRest, setIsTransitioningToRest] = useState(false);
  const transitionStartTimeRef = useRef(0);
  const initialPoseOnPauseRef = useRef<WalkingEnginePose | null>(null);

  const [exportFormat, setExportFormat] = useState<ExportFormat>('zip');
  const [syncToCycle, setSyncToCycle] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [zipProgress, setZipProgress] = useState(0);
  const [recordFrameCount, setRecordFrameCount] = useState(60);

  const framesRecordedRef = useRef(0);
  const capturedFramesRef = useRef<string[]>([]);
  const pivotsOnBeforeRecord = useRef(false);
  const labelsOnBeforeRecord = useRef(true);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const recordedChunksRef = useRef<Blob[]>([]);
  const lastPhaseRef = useRef(0);
  const hasStartedCycleCaptureRef = useRef(false);
  const isWebmRecorderStartedRef = useRef(false);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);

  const svgRef = useRef<SVGSVGElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const lastFrameTimeRef = useRef(0);

  useEffect(() => { 
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2} ${newWidth} ${newHeight}`);
  }, [zoomIndex]);

  useEffect(() => {
    if (!isPaused || isPoseDataValid) {
      setPoseDataString(JSON.stringify(pose, (key, value) => typeof value === 'number' ? parseFloat(value.toFixed(1)) : value, 2));
    }
  }, [pose, isPaused, isPoseDataValid]);

  const handleAnchorClick = (boneKey: keyof WalkingEnginePivotOffsets) => {
      if (boneKey !== PartName.LAnkle && boneKey !== PartName.RAnkle) return;
      setActivePins(prev => prev.includes(boneKey) ? prev.filter(k => k !== boneKey) : [...prev, boneKey]);
  };

  const transitionToMode = (targetMode: 'locomotion' | 'idle') => {
      if (engineModeRef.current !== targetMode) { 
        transitionStartWeightRef.current = locomotionWeightRef.current;
        transitionEndWeightRef.current = targetMode === 'locomotion' ? 1.0 : 0.0;
        modeTransitionStartTimeRef.current = performance.now();
        setEngineMode(targetMode);
      }
  };

  const handleIdleChange = useCallback((key: keyof IdleSettings, val: string) => {
    setIdleSettings(prev => ({ ...prev, [key]: parseFloat(val) }));
    transitionToMode('idle');
    setActiveIdlePresetIndex(-1);
  }, []); 

  const updatePivotOffset = useCallback((key: keyof WalkingEnginePivotOffsets, val: string) => setPivotOffsets(prev => ({ ...prev, [key]: parseInt(val) })), []);

  const handleCopyPoseData = useCallback(() => {
    navigator.clipboard.writeText(poseDataString).then(() => {
      setCopyButtonText('Copied!');
      setTimeout(() => setCopyButtonText('Copy'), 1500);
    });
  }, [poseDataString]);

  const handleTogglePause = useCallback(() => setIsPaused(p => {
    if (!p) {
      initialPoseOnPauseRef.current = pose;
      transitionStartTimeRef.current = performance.now();
      setIsTransitioningToRest(true);
      modeTransitionStartTimeRef.current = 0; 
      transitionStartWeightRef.current = 0.0;
      transitionEndWeightRef.current = 0.0;
    } else {
      setIsTransitioningToRest(false);
      transitionStartWeightRef.current = 0.0;
      transitionEndWeightRef.current = (engineModeRef.current === 'locomotion' ? 1.0 : 0.0);
      modeTransitionStartTimeRef.now();
    }
    return !p;
  }), [pose]); 

  const handleGaitChange = useCallback((key: keyof WalkingEngineGait, value: string) => { 
    setGait(currentGait => ({ ...currentGait, [key]: parseFloat(value) })); 
    transitionToMode('locomotion');
    setActivePresetIndex(-1); 
  }, []); 

  const handlePoseDataChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newString = e.target.value;
    setPoseDataString(newString);
    if (isPaused) {
        try {
            const newPoseObject = JSON.parse(newString);
            setPose(prevPose => ({ ...prevPose, ...newPoseObject }));
            setIsPoseDataValid(true);
        } catch (error) { setIsPoseDataValid(false); }
    }
  };

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isZipping) return;

      const lotte = lotteSettingsRef.current;
      const fpsInterval = lotte.enabled && lotte.frameStepping ? 1000 / 12 : 1000 / targetFps;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < fpsInterval) return;

      const deltaTime = elapsed;
      lastFrameTimeRef.current = time - (elapsed % fpsInterval);

      const targetGait = gaitRef.current;
      const targetIdle = idleSettingsRef.current;
      const targetPhysics = physicsControlsRef.current;

      const newSmoothedGait = { ...smoothedGaitRef.current };
      const newSmoothedIdle = { ...smoothedIdleSettingsRef.current };
      const newSmoothedPhysics = { ...smoothedPhysicsControlsRef.current };
      let needsGaitUpdate = false, needsIdleUpdate = false, needsPhysicsUpdate = false;
      const LERP_FACTOR = 0.2;

      for (const key in targetGait) {
          const k = key as keyof WalkingEngineGait;
          if (Math.abs(targetGait[k] - newSmoothedGait[k]) > 0.001) {
              needsGaitUpdate = true;
              newSmoothedGait[k] = lerp(newSmoothedGait[k], targetGait[k], LERP_FACTOR);
          } else { newSmoothedGait[k] = targetGait[k]; }
      }
      for (const key in targetIdle) {
          const k = key as keyof IdleSettings;
          if (k === 'idlePinnedFeet') {
              if (newSmoothedIdle[k] !== targetIdle[k]) {
                  needsIdleUpdate = true;
                  newSmoothedIdle[k] = targetIdle[k];
              }
              continue;
          }
          if (Math.abs(targetIdle[k] - newSmoothedIdle[k]) > 0.001) {
              needsIdleUpdate = true;
              newSmoothedIdle[k] = lerp(newSmoothedIdle[k], targetIdle[k], LERP_FACTOR);
          } else { newSmoothedIdle[k] = targetIdle[k]; }
      }
      for (const key in targetPhysics) {
          const k = key as keyof PhysicsControls;
          if (Math.abs(targetPhysics[k] - newSmoothedPhysics[k]) > 0.001) {
              needsPhysicsUpdate = true;
              newSmoothedPhysics[k] = lerp(newSmoothedPhysics[k], targetPhysics[k], LERP_FACTOR);
          } else { newSmoothedPhysics[k] = targetPhysics[k]; }
      }

      if (needsGaitUpdate) setSmoothedGait(newSmoothedGait);
      if (needsIdleUpdate) setSmoothedIdleSettings(newSmoothedIdle);
      if (needsPhysicsUpdate) setSmoothedPhysicsControls(newSmoothedPhysics);

      const transitionElapsed = time - modeTransitionStartTimeRef.current;
      const progress = clamp(transitionElapsed / TIMING.MODE_TRANSITION_DURATION, 0, 1);
      locomotionWeightRef.current = lerp(transitionStartWeightRef.current, transitionEndWeightRef.current, easeInOutQuint(progress));
      const locWeight = locomotionWeightRef.current;

      let animationSpeedFactor = animationSpeed;
      if (isSlowMoActive) animationSpeedFactor *= 0.3;

      if (isPaused && !isRecording) {
        if (isTransitioningToRest) {
          const t = easeInOutQuint(Math.min(1, (performance.now() - transitionStartTimeRef.current) / TIMING.PAUSE_TRANSITION_DURATION));
          setPose(prevPose => {
            const newPose = { ...DEFAULT_RESTING_POSE };
            for (const key in newPose) {
              const k = key as keyof WalkingEnginePose;
              (newPose[k] as any) = lerp((initialPoseOnPauseRef.current?.[k] || 0) as number, (DEFAULT_RESTING_POSE[k] as number), t);
            }
            return newPose;
          });
          if (t >= 1) setIsTransitioningToRest(false);
        }
        return;
      }

      const gaitForLocomotionPhysics = engineModeRef.current === 'idle' ? { ...newSmoothedGait, frequency: 0 } : newSmoothedGait;
      const p = (time * animationSpeedFactor * 0.005 * newSmoothedGait.frequency) % (Math.PI * 2);

      const swayLimit = gaitSliderConfig.hip_sway?.max ?? 1.5;
      const twistLimit = gaitSliderConfig.waist_twist?.max ?? 2.0;

      // Fixed destructuring to match return type of updateLocomotionPhysics
      const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gaitForLocomotionPhysics, newSmoothedPhysics, props, activePins, pinnedSlideOffset, gravityCenter, H, isIkEnabled, locWeight);
      const idlePose = updateIdlePhysics(time, deltaTime, newSmoothedIdle, locWeight);

      const blendedPose: Partial<WalkingEnginePose> = {};
      const allPoseKeys = new Set([...Object.keys(locPose), ...Object.keys(idlePose), ...Object.keys(DEFAULT_RESTING_POSE)]) as Set<keyof WalkingEnginePose>;
      allPoseKeys.forEach(key => {
        const lVal = (locPose as any)[key] ?? 0;
        const iVal = (idlePose as any)[key] ?? 0;
        if (key === 'x_offset') blendedPose.x_offset = lerp(iVal, locPose.x_offset ?? 0, locWeight);
        else if (key === 'y_offset') blendedPose.y_offset = lerp(iVal, locPose.y_offset ?? 0, locWeight);
        else (blendedPose as any)[key] = lerp(iVal, lVal, locWeight);
      });

      const { adjustedPose, tensions: groundTensions } = applyFootGrounding(blendedPose, props, H, newSmoothedPhysics, activePins, newSmoothedIdle, gravityCenter, locWeight, deltaTime);
      setTensions(groundTensions);
      setPose(adjustedPose as WalkingEnginePose);
    };
    frame = requestAnimationFrame(animate); return () => cancelAnimationFrame(frame);
  }, [isPaused, engineMode, animationSpeed, isIkEnabled, isSlowMoActive, targetFps, pinnedSlideOffset, gravityCenter, activePins, isRecording, props, bodyRotation]);

  const poseableParts = [
    { key: 'neck', label: 'Head' }, { key: 'collar', label: 'Collar' }, { key: 'torso', label: 'Torso' }, { key: 'waist', label: 'Waist' },
    { key: PartName.LShoulder, label: 'L.Shoulder' }, { key: PartName.RShoulder, label: 'R.Shoulder' }, { key: PartName.LElbow, label: 'L.Elbow' }, { key: PartName.RElbow, label: 'R.Elbow' },
    { key: PartName.LWrist, label: 'L.Hand' }, { key: PartName.RWrist, label: 'R.Hand' }, { key: PartName.LThigh, label: 'L.Thigh' }, { key: PartName.RThigh, label: 'R.Thigh' },
    { key: PartName.LKnee, label: 'L.Knee' }, { key: PartName.RKnee, label: 'R.Knee' }, { key: PartName.LAnkle, label: 'L.Ankle' }, { key: PartName.RAnkle, label: 'R.Ankle' },
  ];

  return (
    <div className="w-full h-full flex bg-paper select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-3 custom-scrollbar overflow-y-auto shrink-0 z-20">
          <h1 className="text-xl font-archaic tracking-widest border-b border-ridge pb-2 text-ink uppercase italic">Bitruvius.Kinetic</h1>

          <div className="flex flex-col gap-2">
            <button onClick={handleTogglePause} className={`text-[9px] px-3 py-1 border transition-all ${isPaused ? 'bg-accent-red/20 text-accent-red border-accent-red/50' : 'bg-paper/10 border-ridge hover:bg-ridge'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
            <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper' : 'bg-paper/10 border-ridge'}`}>{showPivots ? 'HIDE ANCHORS' : 'SHOW ANCHORS'}</button>
          </div>

          <div className="flex gap-2">
            <button onClick={() => transitionToMode('locomotion')} className={`flex-1 text-[9px] px-3 py-1 border transition-all ${engineMode === 'locomotion' ? 'bg-selection text-paper' : 'bg-paper/10 border-ridge'}`}>WALK</button>
            <button onClick={() => transitionToMode('idle')} className={`flex-1 text-[9px] px-3 py-1 border transition-all ${engineMode === 'idle' ? 'bg-selection text-paper' : 'bg-paper/10 border-ridge'}`}>IDLE</button>
          </div>

          <CollapsibleSection title="Kinetic Posing" defaultOpen={false}>
            <div className="flex flex-col border-t border-ridge divide-y divide-ridge/20">
              {poseableParts.map(part => (
                <div key={part.key} className="flex flex-col py-1">
                  <div className="flex justify-between text-[8px] font-bold uppercase text-mono-light mb-1">
                    <span>{part.label}</span>
                    <span className="text-selection">{(pivotOffsets[part.key as keyof WalkingEnginePivotOffsets] || 0)}°</span>
                  </div>
                  <input type="range" min="-180" max="180" value={pivotOffsets[part.key as keyof WalkingEnginePivotOffsets] || 0} onChange={(e) => updatePivotOffset(part.key as keyof WalkingEnginePivotOffsets, e.target.value)} className="w-full accent-selection h-1" />
                </div>
              ))}
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Idle Dynamics" defaultOpen={engineMode === 'idle'}>
            <div className="flex flex-col gap-2">
              <div className="flex gap-1 overflow-x-auto pb-1 mb-1">
                {idlePresets.map((p, i) => (
                  <button key={i} onClick={() => { setIdleSettings(generateRandomIdle(p)); transitionToMode('idle'); setActiveIdlePresetIndex(i); }} className={`text-[7px] px-2 py-1 border whitespace-nowrap uppercase ${activeIdlePresetIndex === i ? 'bg-selection text-paper border-selection' : 'border-ridge bg-paper/20'}`}>{p.name}</button>
                ))}
              </div>
              {Object.keys(DEFAULT_IDLE_SETTINGS).filter(k => k !== 'idlePinnedFeet').map(k => (
                <div key={k}>
                  <div className="flex justify-between text-[7px] font-bold uppercase text-mono-light"><span>{k}</span>
                    <span className="text-selection">{(idleSettings[k as keyof IdleSettings] as number).toFixed(2)}</span>
                  </div>
                  <input type="range" min="0" max="1" step="0.01" value={(idleSettings as any)[k]} onChange={(e) => handleIdleChange(k as keyof IdleSettings, e.target.value)} className="w-full h-1 accent-selection" />
                </div>
              ))}
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Advanced Locomotion" defaultOpen={engineMode === 'locomotion'}>
            <div className="flex flex-col gap-2">
              <div className="flex gap-1 overflow-x-auto pb-1 mb-1">
                {gaitPresets.map((p, i) => (
                  <button key={i} onClick={() => { setGait(generateRandomGait(p)); transitionToMode('locomotion'); setActivePresetIndex(i); }} className={`text-[7px] px-2 py-1 border whitespace-nowrap uppercase ${activePresetIndex === i ? 'bg-selection text-paper border-selection' : 'border-ridge bg-paper/20'}`}>{p.name}</button>
                ))}
              </div>
              <div className="h-64 overflow-y-auto custom-scrollbar pr-2 space-y-2">
                {(Object.keys(gaitSliderConfig) as Array<keyof WalkingEngineGait>).map(k => {
                  const conf = gaitSliderConfig[k]!;
                  return (
                    <div key={k}>
                      <div className="flex justify-between text-[7px] font-bold uppercase text-mono-light"><span>{conf.label}</span><span className="text-selection">{gait[k].toFixed(2)}</span></div>
                      <input type="range" min={conf.min} max={conf.max} step={conf.step} value={gait[k]} onChange={(e) => handleGaitChange(k, e.target.value)} className="w-full h-1 accent-selection" />
                    </div>
                  );
                })}
              </div>
            </div>
          </CollapsibleSection>

          <CollapsibleSection title="Anatomical Manifest" defaultOpen={false}>
            <div className="flex flex-col gap-2">
              <span className="text-[7px] font-bold text-mono-light uppercase">Procedural JSON Interface</span>
              <textarea value={poseDataString} onChange={handlePoseDataChange} disabled={!isPaused} spellCheck={false} className={`w-full h-48 bg-mono-darker border border-ridge p-2 text-[9px] font-mono resize-none focus:outline-none transition-all ${isPaused ? 'text-ink border-selection' : 'text-mono-mid opacity-60'}`} />
              <div className="flex gap-1">
                <button onClick={handleCopyPoseData} className="flex-1 text-[8px] py-1 border border-ridge uppercase font-bold">{copyButtonText}</button>
                <button onClick={() => { setPose(DEFAULT_RESTING_POSE); setIsPaused(true); }} className="flex-1 text-[8px] py-1 border border-ridge uppercase font-bold">Reset</button>
              </div>
            </div>
          </CollapsibleSection>
        </div>
      )}

      <div className={`flex-1 relative overflow-hidden cursor-crosshair`}>
        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 bg-mono-darker/50 hover:bg-mono-darker rounded-full transition-all text-ink">{isConsoleVisible ? '✕' : '☰'}</button>

        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full relative z-10">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={bodyRotation} pivotOffsets={pivotOffsets} props={props} 
              showPivots={showPivots} baseUnitH={H} onAnchorMouseDown={(k) => handleAnchorClick(k)} 
              draggingBoneKey={draggingBoneKey} isPaused={isPaused} activePins={activePins} tensions={tensions} jointModes={jointModes} lotteSettings={DEFAULT_LOTTE_SETTINGS} 
            />
          </g>
        </svg>

        <div className="absolute bottom-4 left-4 w-72 pointer-events-none opacity-80">
          <SystemLogger logs={systemLogs} isVisible={isLoggerVisible} />
        </div>
        <canvas ref={canvasRef} className="hidden" />
      </div>
    </div>
  );
};

export default App;

import { CharacterMorphology, GaitGenome, GaitParameter } from '../types';
import { WalkingEngineGait } from '../types';
import { lerp } from './kinematics';

export class GaitSynthesizer {
  static synthesizeGait(morphology: CharacterMorphology, vibeScale: number = 1.0): WalkingEngineGait {
    const g = morphology.gaitDNA;
    const anat = morphology.anatomy;
    const tags = morphology.tags || [];

    // Archetype Detection
    const isQueen = tags.some(t => ['queen', 'regal', 'formal', 'stiff', 'elegant'].includes(t.toLowerCase()));
    const isAthlete = tags.some(t => ['athlete', 'runner', 'bold', 'heroic', 'energetic'].includes(t.toLowerCase()));
    const isVillain = tags.some(t => ['villain', 'sneaky', 'aggressive', 'creeping', 'dark'].includes(t.toLowerCase()));

    // A helper to lerp between a neutral/default value and a personality-driven value based on vibeScale
    const scale = (val: number, neutral: number = 1.0) => lerp(neutral, val, vibeScale);

    // Initial Synthesized Gait
    const gait: WalkingEngineGait = {
      intensity: scale(this.calculateIntensity(g)),
      frequency: scale(this.calculateFrequency(g, anat)),
      stride: scale(this.calculateStride(g, anat)),
      lean: scale(this.calculateLean(g, anat), 0),
      upper_body_lean: scale(this.calculateUpperBodyLean(g, anat), 0),
      hip_sway: scale(this.calculateHipSway(g), 0.4),
      waist_twist: scale(this.calculateWaistTwist(g), 0.3),
      arm_swing: scale(this.calculateArmSwing(g), 0.6),
      elbow_bend: scale(this.calculateElbowBend(g), 0.7),
      arm_spread: scale(this.calculateArmSpread(g), 0.1),
      gravity: scale(this.calculateGravity(g), 0.3),
      verticality: scale(this.calculateVerticality(g), 0.5),
      kick_up_force: scale(this.calculateKickUpForce(g), 0.4),
      hover_height: scale(this.calculateHoverHeight(g), 0.1),
      foot_roll: scale(this.calculateFootRoll(g, morphology.constraints), 0.6),
      toe_bend: scale(this.calculateToeBend(g), 0.8),
      footDrag: scale(this.calculateFootDrag(g), 0.5),
      footSpring: scale(this.calculateFootSpring(g), 0.5),
      torso_swivel: scale(this.calculateTorsoSwivel(g), 0.3),
      head_spin: scale(this.calculateHeadSpin(g), 0),
      handsAutoBend: scale(this.calculateLimbAutoBend(g, 'hands'), 0.3),
      handsAutoStretch: scale(this.calculateLimbAutoStretch(g, 'hands'), 0.3),
      feetAutoBend: scale(this.calculateLimbAutoBend(g, 'feet'), 0.4),
      feetAutoStretch: scale(this.calculateLimbAutoStretch(g, 'feet'), 0.4),
      headAutoBend: 0.1,
      headAutoStretch: 0.05,
      heavyStomp: scale(this.calculateStomp(g), 0),
      headVelocitySensitivity: scale(this.calculateHeadSensitivity(g), 0.2),
      elbowFlexibility: scale(this.calculateFlexibility(g), 0.5),
      elbowMinBend: scale(this.calculateMinBend(g), -5),
      elbowMaxBend: scale(this.calculateMaxBend(g), 150),
    };

    // Archetype Overrides (vibeScale weighted)
    if (isQueen) {
        gait.verticality = lerp(gait.verticality, 0.9, vibeScale);
        gait.waist_twist *= lerp(1, 0.2, vibeScale);
        gait.hip_sway *= lerp(1, 0.3, vibeScale);
        gait.arm_swing *= lerp(1, 0.1, vibeScale);
        gait.lean = lerp(gait.lean, -0.1, vibeScale); // Proud back lean
    }
    if (isAthlete) {
        gait.frequency *= lerp(1, 1.4, vibeScale);
        gait.stride *= lerp(1, 1.3, vibeScale);
        gait.kick_up_force = lerp(gait.kick_up_force, 0.8, vibeScale);
        gait.arm_swing = lerp(gait.arm_swing, 1.5, vibeScale);
        gait.heavyStomp = lerp(gait.heavyStomp, 0.4, vibeScale);
    }
    if (isVillain) {
        gait.gravity = lerp(gait.gravity, 0.8, vibeScale); // Crouched
        gait.lean = lerp(gait.lean, 0.5, vibeScale); // Forward lean
        gait.footDrag = lerp(gait.footDrag, 0.7, vibeScale);
        gait.elbow_bend = lerp(gait.elbow_bend, 1.4, vibeScale); // Tense arms
        gait.headVelocitySensitivity = lerp(gait.headVelocitySensitivity, 0.8, vibeScale); // Wary head
    }

    return gait;
  }

  private static calculateIntensity(g: GaitGenome): number {
    return Math.min(2, g.stride.base * (1 + g.frequency.base * 0.5) * (1 - g.energyCost * 0.3));
  }
  private static calculateFrequency(g: GaitGenome, anat: CharacterMorphology['anatomy']): number {
    return g.frequency.base * (1 + (anat.limbCount - 4) * 0.1) * (2 - g.weight);
  }
  private static calculateStride(g: GaitGenome, anat: CharacterMorphology['anatomy']): number {
    return g.stride.base * (1 + anat.limbLength * 0.2) * (1 - g.energyCost * 0.2);
  }
  private static calculateLean(g: GaitGenome, anat: CharacterMorphology['anatomy']): number {
    return g.bodyPitch.base * (anat.centerOfMass - 0.5) * 2;
  }
  private static calculateUpperBodyLean(g: GaitGenome, anat: CharacterMorphology['anatomy']): number {
    return g.bodyPitch.base * 0.5 * (anat.centerOfMass > 0.6 ? 1 : -0.5);
  }
  private static calculateHipSway(g: GaitGenome): number {
    return g.bodyRoll.base * (1 + g.stride.base);
  }
  private static calculateWaistTwist(g: GaitGenome): number {
    return g.bodyRoll.base * 0.8 * (1 - g.stability * 0.5);
  }
  private static calculateArmSwing(g: GaitGenome): number {
    return Math.min(2, g.shoulderSwing.base * (1 + g.stride.base * 0.3) * (1 - g.weight * 0.3));
  }
  private static calculateElbowBend(g: GaitGenome): number {
    return g.shoulderSwing.base * (1 + g.confidence * 0.2);
  }
  private static calculateArmSpread(g: GaitGenome): number {
    return g.shoulderSwing.base * g.agility * 0.5 * (1 - g.weight);
  }
  private static calculateGravity(g: GaitGenome): number {
    return Math.min(1, 0.3 + g.weight * 0.4 + g.bodyBounce.base * 0.3);
  }
  private static calculateVerticality(g: GaitGenome): number {
    return 0.5 + g.bodyBounce.base * 0.3 - g.weight * 0.2;
  }
  private static calculateKickUpForce(g: GaitGenome): number {
    return g.bodyBounce.base * (1 - g.weight * 0.5) * g.agility;
  }
  private static calculateHoverHeight(g: GaitGenome): number {
    return g.bodyBounce.base * (1 - g.weight) * 0.6;
  }
  private static calculateFootRoll(g: GaitGenome, constraints: any): number {
    const strikeWeight = constraints.strikeType === 'heel' ? 0.8 : 
                        constraints.strikeType === 'toe' ? 0.3 :
                        constraints.strikeType === 'flat' ? 0.5 : 0.4;
    return g.ankleFlexion.base * strikeWeight;
  }
  private static calculateToeBend(g: GaitGenome): number {
    return g.ankleFlexion.base * (1 + g.stride.base * 0.2);
  }
  private static calculateFootDrag(g: GaitGenome): number {
    return 1 - g.agility * 0.3;
  }
  private static calculateFootSpring(g: GaitGenome): number {
    return g.bodyBounce.base * (1 - g.weight * 0.5);
  }
  private static calculateTorsoSwivel(g: GaitGenome): number {
    return g.bodyRoll.base * g.agility * 0.5;
  }
  private static calculateHeadSpin(g: GaitGenome): number {
    return g.confidence * 0.3 * (1 - g.anxiousness * 0.5);
  }
  private static calculateStomp(g: GaitGenome): number {
    return Math.min(1, g.weight * 0.5 * (1 - g.agility));
  }
  private static calculateHeadSensitivity(g: GaitGenome): number {
    return 0.5 * (1 + g.anxiousness * 0.3);
  }
  private static calculateFlexibility(g: GaitGenome): number {
    return g.agility * (1 - g.weight * 0.3);
  }
  private static calculateMinBend(g: GaitGenome): number {
    return -5 - g.agility * 20;
  }
  private static calculateMaxBend(g: GaitGenome): number {
    return 150 - g.weight * 30;
  }
  private static calculateLimbAutoBend(g: GaitGenome, limbType: string): number {
    if (limbType === 'hands') return g.shoulderSwing.base * 0.3;
    if (limbType === 'feet') return g.ankleFlexion.base * 0.4;
    return 0;
  }
  private static calculateLimbAutoStretch(g: GaitGenome, limbType: string): number {
    if (limbType === 'hands') return g.shoulderSwing.base * 0.15;
    if (limbType === 'feet') return g.ankleFlexion.base * 0.2;
    return 0;
  }
}

