export class CombatStateController {
  private static bpm = 120;
  private static beatInterval = 60000 / this.bpm;
  private static lastBeatTime = 0;
  private static structureInternal = 0;

  /**
   * Updates combat metrics and returns current AI state behavior logic.
   */
  static updateCombat(
    time: number, 
    stats: CombatStats, 
    archetype: FighterArchetype = 'DISCIPLE'
  ): { 
    state: CombatState; 
    structure: number; 
    beatProgress: number; 
    guardPose: Partial<WalkingEnginePose> 
  } {
    // 1. Structure Management
    // Structure recovers naturally over time if not STUNNED
    const recovery = stats.recoveryRate * 0.01;
    this.structureInternal = clamp(this.structureInternal - recovery, 0, 100);

    // 2. Beat Management
    const elapsed = time - this.lastBeatTime;
    if (elapsed >= this.beatInterval) {
      this.lastBeatTime = time;
    }
    const beatProgress = elapsed / this.beatInterval;

    // 3. State Determination (Simplified Sifu Logic)
    let currentState: CombatState = 'NEUTRAL';
    if (this.structureInternal >= 100) currentState = 'STUNNED';
    else if (this.structureInternal > 70) currentState = 'BLOCKING';
    else if (beatProgress > 0.8 && archetype === 'DISCIPLE') currentState = 'ADVANCING';

    // 4. Kinetic Guard Poses
    const guardPose: Partial<WalkingEnginePose> = {};
    if (currentState === 'BLOCKING' || currentState === 'STUNNED') {
      const tension = this.structureInternal / 100;
      guardPose.collar = 15 * tension; // Hunch
      guardPose.l_elbow = -140; // Tight guard
      guardPose.r_elbow = -140;
      guardPose.l_shoulder = -20;
      guardPose.r_shoulder = 20;
    }

    if (currentState === 'STUNNED') {
        guardPose.neck = 45; // Head dropped
        guardPose.torso = 25; // Slumped
    }

    return { 
      state: currentState, 
      structure: this.structureInternal, 
      beatProgress,
      guardPose
    };
  }

  /**
   * Triggers an impact event (e.g., character hit)
   */
  static triggerImpact(damage: number, structureDamage: number) {
    this.structureInternal = clamp(this.structureInternal + structureDamage, 0, 100);
  }

  /**
   * Resets structure gauge
   */
  static resetStructure() {
    this.structureInternal = 0;
  }
}

