      <button onClick={() => setIsOpen(!isOpen)} className="flex justify-between items-center w-full py-2.5 px-1 text-[9px] font-black tracking-widest uppercase hover:bg-mono-darker/50 transition-colors">
        <span className="flex items-center gap-2"><span className={isOpen ? 'text-selection' : 'text-mono-light'}>{isOpen ? '▼' : '▶'}</span>{title}</span>
        {count !== undefined && <span className="text-[7px] bg-mono-dark px-1.5 py-0.5 rounded border border-ridge text-mono-light">{count}</span>}
      </button>
      {isOpen && <div className="p-2 pt-0 flex flex-col gap-3">{children}</div>}
    </div>
  );
};

const App: React.FC = () => {
  const [library] = useState(() => new CharacterLibraryManager());
  const [characters, setCharacters] = useState<CharacterMorphology[]>([]);
  const [currentCharacter, setCurrentCharacter] = useState<CharacterMorphology | null>(null);
  const [charDescription, setCharDescription] = useState('');
  const [vibeScale, setVibeScale] = useState(1.0);

  // Combat State
  const [isCombatMode, setIsCombatMode] = useState(false);
  const [combatState, setCombatState] = useState<CombatState>('NEUTRAL');
  const [structure, setStructure] = useState(0);
  const [beatProgress, setBeatProgress] = useState(0);

  const [showPivots, setShowPivots] = useState(true);
  const [isPaused, setIsPaused] = useState(false);
  const [isIkEnabled, setIsIkEnabled] = useState(true);
  const [targetFps, setTargetFps] = useState(TIMING.DEFAULT_TARGET_FPS);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [panOffset, setPanOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);

  const [engineMode, setEngineMode] = useState<'locomotion' | 'idle'>('locomotion');
  const [activePins, setActivePins] = useState<string[]>([]);
  const [gait, setGait] = useState<WalkingEngineGait>(GaitSynthesizer.synthesizeGait(CharacterGenerator.generateCharacter('Default'), 1.0));
  const [idleSettings, setIdleSettings] = useState<IdleSettings>(DEFAULT_IDLE_SETTINGS);
  const [pivotOffsets, setPivotOffsets] = useState<Record<string, number>>({});
  const [pose, setPose] = useState<WalkingEnginePose>(DEFAULT_RESTING_POSE);
  const [tensions, setTensions] = useState<Record<string, number>>({});
  const [activeScripts, setActiveScripts] = useState<MicroScriptInstance[]>([]);
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const H = 150;

  const locomotionStateRef = useRef<LocomotionState>({ ...INITIAL_LOCOMOTION_STATE });
  const lastFrameTimeRef = useRef(0);
  const locomotionWeightRef = useRef(1.0);

  useEffect(() => {
    library.init().then(() => library.getAllCharacters().then(setCharacters));
  }, []);

  const logSystem = (msg: string) => setSystemLogs(p => [...p.slice(-15), { timestamp: new Date().toLocaleTimeString(), message: msg }]);

  const generateCharacter = async () => {
    if (!charDescription.trim()) return;
    const char = CharacterGenerator.generateCharacter(charDescription);
    await library.saveCharacter(char);
    setCharacters(p => [...p, char]);
    setCurrentCharacter(char);
    setGait(GaitSynthesizer.synthesizeGait(char, vibeScale));
    setCharDescription('');
    logSystem(`Fighter Archive updated: ${char.name}`);
  };

  useEffect(() => {
    if (currentCharacter) setGait(GaitSynthesizer.synthesizeGait(currentCharacter, vibeScale));
  }, [vibeScale, currentCharacter]);

  useEffect(() => {
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2 + panOffset.x} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2 + panOffset.y} ${newWidth} ${newHeight}`);
  }, [zoomIndex, panOffset]);

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused) return;
      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 1000 / targetFps) return;
      lastFrameTimeRef.current = time;

      // 1. Combat Processing
      let combatPose: Partial<WalkingEnginePose> = {};
      if (isCombatMode) {
          const stats: CombatStats = { structure, maxStructure: 100, health: 100, recoveryRate: 2, beatSensitivity: 0.8 };
          const cResult = CombatStateController.updateCombat(time, stats, 'DISCIPLE');
          setCombatState(cResult.state);
          setStructure(cResult.structure);
          setBeatProgress(cResult.beatProgress);
          combatPose = cResult.guardPose;

          // Force state-based gait adjustments
          if (cResult.state === 'ADVANCING') setEngineMode('locomotion');
          else if (cResult.state === 'BLOCKING' || cResult.state === 'STUNNED') setEngineMode('idle');
      }

      // 2. Base Physics
      const targetWeight = engineMode === 'locomotion' ? 1.0 : 0.0;
      locomotionWeightRef.current = lerp(locomotionWeightRef.current, targetWeight, 0.08);
      const locWeight = locomotionWeightRef.current;
      const p = (time * 0.005 * gait.frequency) % (Math.PI * 2);

      const locPose = updateLocomotionPhysics(p, locomotionStateRef.current, gait, DEFAULT_PHYSICS, DEFAULT_PROPORTIONS, activePins, 150, 'center', H, isIkEnabled, locWeight);
      const idlePose = updateIdlePhysics(time, elapsed, idleSettings, locWeight, currentCharacter?.tags || []);
      const { pose: scriptPose, remaining } = processActiveScripts(time, activeScripts);
      if (remaining.length !== activeScripts.length) setActiveScripts(remaining);

      // 3. Behavioral Blending
      const blendedPose = BehaviorEngine.blendPose(locPose, idlePose, scriptPose, locWeight, gait, time);

      // 4. Combat Overlay (Highest Priority)
      const finalBlended = { ...blendedPose, ...combatPose };

      // 5. Grounding
      const { adjustedPose, tensions: groundTensions } = applyFootGrounding(finalBlended, DEFAULT_PROPORTIONS, H, DEFAULT_PHYSICS, activePins, idleSettings, 'center', locWeight, elapsed);

      setTensions(groundTensions);
      setPose(adjustedPose as WalkingEnginePose);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, gait, activePins, idleSettings, isIkEnabled, targetFps, engineMode, activeScripts, currentCharacter, isCombatMode, structure]);

  return (
    <div className="w-full h-full flex bg-shell select-none overflow-hidden font-mono text-ink">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-white p-4 flex flex-col gap-1 custom-scrollbar overflow-y-auto shrink-0 z-20 shadow-2xl">
          <h1 className="text-xl font-archaic tracking-[0.3em] border-b-4 border-selection pb-1 text-ink uppercase italic flex items-center justify-between">
            <span>BITRUVIUS</span>
            <span className="text-[8px] bg-selection text-white px-2 py-0.5">SIFU.0.2</span>
          </h1>

          <CollapsibleSection title="AI State Manager">
             <button onClick={() => setIsCombatMode(!isCombatMode)} className={`w-full py-2 text-[9px] font-black border-2 rounded ${isCombatMode ? 'bg-accent-red text-white border-accent-red' : 'bg-white border-selection'}`}>
                {isCombatMode ? 'DISABLE COMBAT AI' : 'ENABLE COMBAT AI'}
             </button>
             {isCombatMode && (
                <div className="space-y-2 mt-2">
                   <div className="flex justify-between text-[7px] font-black uppercase text-mono-light">
                      <span>Fighter Structure</span>
                      <span className={structure > 80 ? 'text-accent-red' : 'text-selection'}>{Math.round(structure)}%</span>
                   </div>
                   <div className="w-full h-1 bg-shell border border-ridge overflow-hidden">
                      <div className="h-full bg-accent-red transition-all duration-300" style={{ width: `${structure}%` }} />
                   </div>
                   <div className="flex justify-between text-[7px] font-black uppercase">
                      <span className="text-mono-light">Active Rhythm</span>
                      <div className="flex gap-0.5">
                         {[1,2,3,4].map(b => (
                            <div key={b} className={`w-2 h-2 rounded-full ${Math.floor(beatProgress * 4) + 1 === b ? 'bg-selection' : 'bg-shell border border-ridge'}`} />
                         ))}
                      </div>
                   </div>
                   <button onClick={() => CombatStateController.triggerImpact(10, 25)} className="w-full py-1 text-[8px] bg-shell border border-ridge hover:bg-selection hover:text-white font-bold transition-all">SIMULATE IMPACT (+25 Struct)</button>
                </div>
             )}
          </CollapsibleSection>

          <CollapsibleSection title="Genome Archetype">
            <textarea value={charDescription} onChange={(e) => setCharDescription(e.target.value)} placeholder="e.g. 'Aggressive Disciple'..." className="w-full h-12 p-2.5 bg-shell border border-ridge text-[9px] resize-none focus:outline-none focus:border-selection font-bold" />
            <button onClick={generateCharacter} className="w-full py-2 bg-selection text-white text-[8px] font-black uppercase">Calibrate Fighter</button>
          </CollapsibleSection>

          <CollapsibleSection title="Gait Matrix" count={18}>
             <div className="flex flex-col gap-4 h-64 overflow-y-auto pr-3 custom-scrollbar">
               {['Primary', 'Body', 'Arms', 'Legs'].map(cat => (
                 <div key={cat} className="flex flex-col gap-2">
                    <div className="text-[7px] font-black text-mono-light uppercase border-b border-ridge pb-1 tracking-tighter opacity-60">{cat} Layers</div>
                    {Object.entries(gaitSliderConfig)
                      .filter(([_, conf]) => conf.category === cat)
                      .map(([key, conf]) => (
                        <div key={key} className="flex flex-col">
                           <div className="flex justify-between text-[7px] font-black text-selection uppercase">
                              <span>{conf.label}</span>
                              <span className="opacity-50">{gait[key as keyof WalkingEngineGait].toFixed(2)}</span>
                           </div>
                           <input type="range" min={conf.min} max={conf.max} step={conf.step} value={gait[key as keyof WalkingEngineGait]} onChange={(e) => setGait(p => ({...p, [key]: parseFloat(e.target.value)}))} className="w-full h-1 accent-selection" />
                        </div>
                      ))}
                 </div>
               ))}
             </div>
          </CollapsibleSection>

          <div className="mt-auto pt-4 border-t border-ridge">
             <SystemLogger logs={systemLogs} isVisible={true} />
          </div>
        </div>
      )}

      <div className="flex-1 relative overflow-hidden bg-shell">
        <div className="absolute top-4 left-4 z-50 flex gap-2">
            <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="p-2.5 bg-white border-2 border-selection hover:bg-shell rounded shadow-lg transition-all">{isConsoleVisible ? '✕' : '☰'}</button>
            <div className="px-4 py-1 bg-white/95 backdrop-blur-md border-2 border-selection rounded-full text-[9px] font-black text-selection flex items-center gap-3 shadow-lg">
                <div className={`w-2 h-2 rounded-full ${isCombatMode ? (combatState === 'STUNNED' ? 'bg-accent-red animate-ping' : 'bg-orange-500 animate-pulse') : 'bg-green-500'} `} />
                {isCombatMode ? `AI.${combatState}` : engineMode.toUpperCase()}
            </div>
            <button onClick={() => setIsPaused(!isPaused)} className={`px-5 py-1 text-[9px] font-black border-2 border-selection rounded-full shadow-lg ${isPaused ? 'bg-accent-red text-white' : 'bg-white'}`}>{isPaused ? 'RESUME' : 'PAUSE'}</button>
        </div>

        <div className="absolute top-4 right-4 flex flex-col gap-2 z-50">
          <button onClick={() => setZoomIndex(prev => Math.min(UI.ZOOM_LEVELS.length - 1, prev + 1))} className="w-10 h-10 flex items-center justify-center bg-white border-2 border-selection font-black shadow-lg hover:bg-shell rounded-xl">+</button>
          <button onClick={() => setZoomIndex(UI.DEFAULT_ZOOM_INDEX)} className="w-10 h-10 flex items-center justify-center bg-white border-2 border-selection text-[8px] font-black shadow-lg hover:bg-shell rounded-xl">RST</button>
        </div>

        <svg viewBox={viewBox} className="w-full h-full relative z-10 bg-triangle-grid">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={0} pivotOffsets={pivotOffsets} props={DEFAULT_PROPORTIONS} 
              showPivots={showPivots} baseUnitH={H * (currentCharacter?.anatomy.bodyLength || 1)} 
              onAnchorMouseDown={(k) => setActivePins(p => p.includes(k) ? p.filter(x => x !== k) : [...p, k])} 
              draggingBoneKey={null} isPaused={isPaused} activePins={activePins} tensions={tensions} jointModes={{}} lotteSettings={DEFAULT_LOTTE_SETTINGS}
              ghosts={[]}
            />
          </g>
        </svg>

        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-8 text-[8px] font-black text-selection/30 pointer-events-none uppercase tracking-[0.8em] items-center">
            <span>BITRUVIUS KINETIC FIGHTER // BEAT {Math.floor(beatProgress * 4) + 1}</span>
        </div>
      </div>
    </div>
  );
};

