};

export class CombatStateController {
  private static bpm = 105; // Cinematic Shaw Bros tempo
  private static lastBeatTime = 0;
  private static structureInternal = 0;
  private static currentMove: CombatMove | null = null;

  static updateCombat(
    time: number, 
    stats: CombatStats, 
    archetype: FighterArchetype = 'MASTER'
  ): { 
    state: CombatState; 
    structure: number; 
    beatProgress: number; 
    combatPose: Partial<WalkingEnginePose>;
    activeMoveName: string;
  } {
    const beatInterval = 60000 / this.bpm;
    const elapsed = time - this.lastBeatTime;

    if (elapsed >= beatInterval) {
      this.lastBeatTime = time;
    }

    const beatProgress = elapsed / beatInterval;
    const currentBeatIndex = Math.floor((time / beatInterval) % 4);

    // Structure Recovery
    const recovery = stats.recoveryRate * 0.016; // per frame @60fps
    this.structureInternal = clamp(this.structureInternal - recovery, 0, 100);

    // State Logic
    let state: CombatState = 'NEUTRAL';
    let moveName = 'Waiting...';

    if (this.structureInternal >= 100) {
      state = 'STUNNED';
      moveName = 'GUARD BROKEN';
    } else if (this.structureInternal > 70) {
      state = 'BLOCKING';
      moveName = 'Defending';
    } else {
      // Check for move trigger on beat
      const sequence = SHAW_BROS_SEQUENCES[archetype];
      const move = sequence.find(m => m.beatIndex === currentBeatIndex);

      if (move && beatProgress < 0.4) {
        state = 'ATTACKING';
        this.currentMove = move;
        moveName = move.name;
      } else if (this.currentMove && beatProgress < 0.7) {
        state = 'ATTACKING'; // Hold the pose
        moveName = this.currentMove.name;
      } else {
        state = archetype === 'BOUNCER' || archetype === 'MASTER' ? 'NEUTRAL' : 'ADVANCING';
        this.currentMove = null;
      }
    }

    // Kinetic Pose Generation
    const combatPose: Partial<WalkingEnginePose> = {};
    const tension = this.structureInternal / 100;

    if (state === 'ATTACKING' && this.currentMove) {
      Object.assign(combatPose, this.currentMove.pose);
    } else if (state === 'BLOCKING') {
      combatPose.collar = 20 * tension;
      combatPose.l_elbow = -145;
      combatPose.r_elbow = -145;
      combatPose.l_shoulder = -30;
      combatPose.r_shoulder = 30;
      combatPose.neck = -10;
    } else if (state === 'STUNNED') {
      const wobble = Math.sin(time * 0.01) * 10;
      combatPose.neck = 40 + wobble;
      combatPose.torso = 30;
      combatPose.l_shoulder = 15;
      combatPose.r_shoulder = -15;
      combatPose.l_elbow = -5;
      combatPose.r_elbow = -5;
    }

    // Add general "Structure" tension to all poses
    if (tension > 0.5) {
      combatPose.l_elbow = (combatPose.l_elbow || 0) - (tension * 15);
      combatPose.r_elbow = (combatPose.r_elbow || 0) - (tension * 15);
    }

    return { 
      state, 
      structure: this.structureInternal, 
      beatProgress, 
      combatPose,
      activeMoveName: moveName
    };
  }

  static triggerImpact(structureDamage: number) {
    this.structureInternal = clamp(this.structureInternal + structureDamage, 0, 100);
  }

  static reset() {
    this.structureInternal = 0;
    this.currentMove = null;
  }
}

