  const [vibeScale, setVibeScale] = useState(1.0);

  // Combat AI State
  const [isCombatAIActive, setIsCombatAIActive] = useState(false);
  const [combatState, setCombatState] = useState<CombatState>('NEUTRAL');
  const [structure, setStructure] = useState(0);
  const [beatProgress, setBeatProgress] = useState(0);
  const [currentMoveName, setCurrentMoveName] = useState('Idle');
  const [fighterArchetype, setFighterArchetype] = useState<FighterArchetype>('MASTER');

