  const [targetFps, setTargetFps] = useState(60);
  const [isConsoleVisible, setIsConsoleVisible] = useState(true);
  const [zoomIndex, setZoomIndex] = useState(4);
  const [panOffset] = useState<Vector2D>({ x: 0, y: 0 });
