                      >
                        <option value="MASTER">Grand Master</option>
                        <option value="DISCIPLE">Fast Disciple</option>
                        <option value="BOUNCER">Heavy Bouncer</option>
                        <option value="GRUNT">Street Grunt</option>
                      </select>
                    </div>

                    <div className="flex flex-col gap-1">
                      <div className="flex justify-between text-[7px] font-black uppercase text-mono-light">
                        <span>Current Form</span>
                        <span className="text-selection">{currentMoveName}</span>
                      </div>
