const SHAW_BROS_SEQUENCES: Record<FighterArchetype, CombatMove[]> = {
  DISCIPLE: [
    { name: 'Lead Jab', beatIndex: 0, durationInBeats: 1, pose: { l_shoulder: -100, l_elbow: -5, neck: -25, torso: 15, x_offset: 20 } },
