export class CombatStateController {
  private static bpm = 90; // Slower, more cinematic tempo
  private static lastBeatTime = 0;
  private static structureInternal = 0;
  private static currentMove: CombatMove | null = null;
  private static moveStartTime = 0;

  // Interpolation state
  private static smoothedPose: Partial<WalkingEnginePose> = {};
  private static impulseOffset = { x: 0, y: 0 };
  private static impulseShake = 0;

  static updateCombat(
    time: number, 
    stats: CombatStats, 
    archetype: FighterArchetype = 'MASTER'
  ): { 
    state: CombatState; 
    structure: number; 
    beatProgress: number; 
    combatPose: Partial<WalkingEnginePose>;
    activeMoveName: string;
    impulse: { x: number, y: number, shake: number }
  } {
    const beatInterval = 60000 / this.bpm;
    const elapsedSinceLastBeat = time - this.lastBeatTime;

    if (elapsedSinceLastBeat >= beatInterval) {
      this.lastBeatTime = time;
    }

    const beatProgress = elapsedSinceLastBeat / beatInterval;
    const currentBeatIndex = Math.floor((time / beatInterval) % 4);

    // 1. Reactive Impulses (Decay)
    this.impulseOffset.x = lerp(this.impulseOffset.x, 0, 0.1);
    this.impulseOffset.y = lerp(this.impulseOffset.y, 0, 0.1);
    this.impulseShake = lerp(this.impulseShake, 0, 0.15);

    // 2. Structure Recovery
    const recovery = stats.recoveryRate * 0.015;
    this.structureInternal = clamp(this.structureInternal - recovery, 0, 100);

    // 3. Move Logic with Anticipation & Recovery
    let state: CombatState = 'NEUTRAL';
    let moveName = 'Waiting...';
    let targetPose: Partial<WalkingEnginePose> = {};

    const sequence = SHAW_BROS_SEQUENCES[archetype];
    const move = sequence.find(m => m.beatIndex === currentBeatIndex);

    if (this.structureInternal >= 100) {
      state = 'STUNNED';
      moveName = 'GUARD BROKEN';
      targetPose = { neck: 45, torso: 35, collar: 20, l_elbow: -5, r_elbow: -5 };
    } else if (this.structureInternal > 75) {
      state = 'BLOCKING';
      moveName = 'Iron Shield';
      targetPose = { collar: 25, l_elbow: -150, r_elbow: -150, l_shoulder: -40, r_shoulder: 40, neck: -15 };
    } else if (move) {
      state = 'ATTACKING';
      moveName = move.name;

      // Phase Logic: 0-20% Anticipation, 20-50% Strike, 50-100% Recovery
      const moveProgress = beatProgress / move.durationInBeats;

      if (moveProgress < 0.2) {
        // Wind-up: Slight opposite movement
        moveName = `Prep: ${move.name}`;
        Object.keys(move.pose).forEach(k => {
          const key = k as keyof WalkingEnginePose;
          (targetPose as any)[key] = (move.pose[key] as number) * -0.2;
        });
      } else if (moveProgress < 0.6) {
        // Full Strike
        targetPose = { ...move.pose };
      } else {
        // Recovery: Return halfway
        moveName = `End: ${move.name}`;
        Object.keys(move.pose).forEach(k => {
          const key = k as keyof WalkingEnginePose;
          (targetPose as any)[key] = (move.pose[key] as number) * 0.4;
        });
      }
    } else {
      state = 'NEUTRAL';
      moveName = 'Flowing...';
      targetPose = { torso: Math.sin(time * 0.002) * 5 }; // Gentle idle sway
    }

    // 4. Kinetic Spring Interpolation
    // We blend current smoothedPose toward targetPose for "Heavy" feel
    const INTERP_SPEED = state === 'ATTACKING' ? 0.25 : 0.08;
    const keys = new Set([...Object.keys(targetPose), ...Object.keys(this.smoothedPose)]) as Set<keyof WalkingEnginePose>;
    keys.forEach(k => {
      const current = this.smoothedPose[k] || 0;
      const target = targetPose[k] || 0;
      (this.smoothedPose as any)[k] = lerp(current, target, INTERP_SPEED);
    });

    return { 
      state, 
      structure: this.structureInternal, 
      beatProgress, 
      combatPose: this.smoothedPose,
      activeMoveName: moveName,
      impulse: { ...this.impulseOffset, shake: this.impulseShake }
    };
  }

  static triggerImpact(structureDamage: number) {
    this.structureInternal = clamp(this.structureInternal + structureDamage, 0, 100);
    // Dynamic Push-back
    this.impulseOffset.x = (Math.random() - 0.5) * 40;
    this.impulseOffset.y = -10 - Math.random() * 20;
    this.impulseShake = 15;
  }

  static reset() {
    this.structureInternal = 0;
    this.smoothedPose = {};
    this.impulseOffset = { x: 0, y: 0 };
    this.impulseShake = 0;
  }
}

