  const [showPivots, setShowPivots] = useState(false);
  const [zoomIndex, setZoomIndex] = useState(UI.DEFAULT_ZOOM_INDEX);
  const [viewBox, setViewBox] = useState(`${UI.BASE_VIEWBOX.x} ${UI.BASE_VIEWBOX.y} ${UI.BASE_VIEWBOX.width} ${UI.BASE_VIEWBOX.height}`);

  // Combat State
  const [combatStats] = useState<CombatStats>({ structure: 0, maxStructure: 100, health: 100, recoveryRate: 5, beatSensitivity: 1.0 });
  const [archetype, setArchetype] = useState<FighterArchetype>('MASTER');
  const [activeMoveName, setActiveMoveName] = useState('Wait...');
  const [structureUI, setStructureUI] = useState(0);
  const [structureGhost, setStructureGhost] = useState(0);

  const [activePins, setActivePins] = useState<string[]>([]);
  const [tensions, setTensions] = useState<Record<string, number>>({});
  const [pivotOffsets] = useState<WalkingEnginePivotOffsets>(DEFAULT_RESTING_POSE as any);
  const [props] = useState<WalkingEngineProportions>(DEFAULT_RESTING_POSE as any);

  const H = 150;
  const svgRef = useRef<SVGSVGElement>(null);
  const lastFrameTimeRef = useRef(0);

  useEffect(() => { 
    const zoom = UI.ZOOM_LEVELS[zoomIndex];
    const newWidth = UI.BASE_VIEWBOX.width / zoom;
    const newHeight = UI.BASE_VIEWBOX.height / zoom;
    setViewBox(`${UI.BASE_VIEWBOX.x - (newWidth - UI.BASE_VIEWBOX.width) / 2} ${UI.BASE_VIEWBOX.y - (newHeight - UI.BASE_VIEWBOX.height) / 2} ${newWidth} ${newHeight}`);
  }, [zoomIndex]);

  const handleImpact = () => {
    CombatStateController.triggerImpact(25 + Math.random() * 15);
  };

  useEffect(() => {
    let frame: number;
    const animate = (time: number) => {
      frame = requestAnimationFrame(animate);
      if (isPaused) return;

      const elapsed = time - lastFrameTimeRef.current;
      if (elapsed < 16) return; // Cap at 60fps
      lastFrameTimeRef.current = time;

      // 1. Update Combat Engine
      const combatData = CombatStateController.updateCombat(time, combatStats, archetype);

      // 2. Visual Feedback (HUD)
      setStructureUI(combatData.structure);
      setStructureGhost(prev => lerp(prev, combatData.structure, 0.05));
      setActiveMoveName(combatData.activeMoveName);

      // 3. Pose Generation
      const blendedPose: Partial<WalkingEnginePose> = { ...DEFAULT_RESTING_POSE, ...combatData.combatPose };

      // Apply Combat Impulse (Pushback + Jitter)
      const shakeX = (Math.random() - 0.5) * combatData.impulse.shake;
      const shakeY = (Math.random() - 0.5) * combatData.impulse.shake;

      blendedPose.x_offset = (blendedPose.x_offset || 0) + combatData.impulse.x + shakeX;
      blendedPose.y_offset = (blendedPose.y_offset || 0) + combatData.impulse.y + shakeY;

      // 4. Grounding & IK Finalization
      const { adjustedPose, tensions: groundTensions } = applyFootGrounding(
        blendedPose, 
        props as any, 
        H, 
        { motionSmoothing: 0.8, jointElasticity: 0.7, stabilization: 0.8 } as any, 
        activePins, 
        { idlePinnedFeet: 'both' } as any, 
        'center', 
        1.0, 
        16
      );

      setTensions(groundTensions);
      setPose(adjustedPose as WalkingEnginePose);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [isPaused, archetype, combatStats, activePins]);

  return (
    <div className="w-full h-full flex flex-col bg-paper select-none overflow-hidden font-mono text-ink">
      {/* Cinematic HUD */}
      <div className="absolute top-8 left-1/2 -translate-x-1/2 w-[400px] flex flex-col gap-2 z-50 pointer-events-none">
        <div className="flex justify-between items-end">
          <span className="text-[12px] font-bold tracking-widest text-olive uppercase">{archetype} • {activeMoveName}</span>
          <span className="text-[10px] text-mono-light uppercase tracking-tighter">Guard Integrity</span>
        </div>
        {/* Structure Bar with Ghost Trailing */}
        <div className="h-2 w-full bg-ridge relative overflow-hidden">
          <div 
            className="absolute top-0 left-0 h-full bg-mono-light opacity-30 transition-all duration-300"
            style={{ width: `${structureGhost}%` }}
          />
          <div 
            className="absolute top-0 left-0 h-full bg-selection transition-all duration-75"
            style={{ width: `${structureUI}%` }}
          />
        </div>
      </div>

      <div className="absolute bottom-8 right-8 flex gap-4 z-50">
        <button 
          onClick={handleImpact}
          className="px-6 py-2 bg-accent-red text-paper text-[10px] font-bold tracking-widest hover:brightness-110 active:scale-95 transition-all shadow-lg"
        >
          TRIGGER IMPACT [S]
        </button>
        <select 
          value={archetype}
          onChange={(e) => setArchetype(e.target.value as FighterArchetype)}
          className="bg-mono-dark border border-ridge px-4 py-2 text-[10px] uppercase font-bold outline-none"
        >
          <option value="MASTER">Master (Crane/Snake)</option>
          <option value="BOUNCER">Bouncer (Heavy Stomp)</option>
          <option value="DISCIPLE">Disciple (Lead/Cross)</option>
          <option value="GRUNT">Grunt (Wild Swing)</option>
        </select>
      </div>

      <div className="flex-1 relative">
        <svg ref={svgRef} viewBox={viewBox} className="w-full h-full">
          <g transform={`translate(${pose.x_offset}, ${500 - (MANNEQUIN_LOCAL_FLOOR_Y * H) + pose.y_offset})`}>
            <Mannequin 
              pose={pose} bodyRotation={0} pivotOffsets={{}} props={props as any} 
              showPivots={showPivots} baseUnitH={H} onAnchorMouseDown={() => {}} 
              draggingBoneKey={null} isPaused={isPaused} activePins={activePins} 
              tensions={tensions} jointModes={{}} lotteSettings={{ enabled: false } as any} 
            />
          </g>
        </svg>
      </div>
    </div>
  );
};

export default App;
